window.__LIBQ=window.__LIBQ||{};window.__LIBQ["tien-nghich"]=window.__LIBQ["tien-nghich"]||{};window.__LIBQ["tien-nghich"]["q06"]=window.__LIBQ["tien-nghich"]["q06"]||{};window.__LIBQ["tien-nghich"]["q06"]["cotTruyen"]=[{"chuong":458,"tieuDe":"Kiếm Ý","tomTat":"Trương Hướng Phàm ấn lệnh bài vào chỗ ba đạo bạch ngân giao nhau trong trận pháp Phẩm Linh Các, kích hoạt cánh cửa truyền tống tại tầng thứ bảy rồi cung kính mời Thất sư tổ Vương Lâm tiến vào. Vương Lâm được đưa tới một tiên cảnh đầy hương hoa, mây bảy sắc và tiên hạc, nơi một nhân ảnh khổng lồ canh giữ xác nhận hắn là Đệ thất tử Tử hệ đã 103 năm chưa lĩnh tiên ngọc. Hắn chọn lấy toàn bộ và kinh ngạc khi 123.600 khối tiên ngọc bay ra chất cao như núi, đỏ mắt thu hết vào túi trữ vật, ngầm nghi vấn vì sao Thiên Vận tông lại nhiều tiên ngọc đến vậy. Trở ra, Vương Lâm hóa cầu vồng về Tử Lâm Các, dự định bế quan ba tháng để đột phá Anh Biến trung kỳ và tranh đoạt danh hiệu thiên vận thất tử. Trong một tòa lầu trúc, ba chấp pháp trưởng lão bàn luận về hắn, nhắc lệnh của Thủy tổ là chỉ cần không phạm môn quy thì khỏi quản, và bàn về sự khốc liệt của cạnh tranh nội bộ. Vừa về tới Tử Lâm Các, Vương Lâm liền bị năm người hợp vây gồm tứ sư tỷ Tử hệ, Triệu Tinh Sát, đệ tử thứ hai Lam tông, Tư Mã Như Phong v�� một người y phục xanh nửa bước vấn đỉnh. Tứ sư tỷ bất đắc dĩ thừa nhận được người nhờ vả, bắt quyết thi triển Tử thuật - Na di, một tia sáng bạc bao trùm mười dặm mở màn cuộc chiến."},{"chuong":459,"tieuDe":"Khốn Địa Tu Luyện","tomTat":"Tứ sư tỷ cùng Triệu Tinh Sát, nhị sư huynh và hai người Thanh-Lam hai hệ liên thủ khóa không gian, phát bốn đạo sát khí chấn nhiếp rồi dùng thần thông na di đưa Vương Lâm tới một thạch lâm khốn địa hoang vu cách Thiên Vận Tông hơn mười ngàn dặm. Tứ sư tỷ hẹn ba năm sau tới thả ra, hứa sẽ truyền thần thông na di, rồi tuyên bố với đại sư huynh rằng nhân tình năm xưa nay đã hồi báo, từ nay không còn liên quan, trước khi hóa ngân quang bay về tông. Vương Lâm thử phá vây bằng tiên kiếm chém kiếm quang nhưng bị triệt tiêu, bay thẳng lên trên thì gặp lực cản tương đương Anh Biến hậu kỳ đè bật trở lại. Hắn cho Hứa Lập Quốc trong tiên kiếm cùng loan đao lao thử nhưng vẫn không phá nổi trận pháp do đại sư huynh bố trí. Nhận ra kẻ địch muốn vây tới khi tranh đoạt danh hiệu Thiên Vận Thất Tử kết thúc, hắn quyết tự phá nơi này thay vì chờ ba năm. Vương Lâm tìm được biên giới thạch lâm, ngồi khoanh chân hấp thu lượng lớn tiên ngọc luyện công, sau lưng hiện quầng sáng vàng báo hiệu tiên lực đạt bão hòa, hướng tới đột phá Anh Biến trung kỳ."},{"chuong":460,"tieuDe":"Thọ Yến","tomTat":"Tiên lực điên cuồng nhập thể Vương Lâm, hắn dồn toàn lực hấp thu suốt ba tháng tại thạch lâm cách Thiên Vận Tông hơn mười ngàn dặm. Cùng lúc, cả Thiên Vận Tinh náo động chuẩn bị đại thọ ngàn năm của Thiên Vận Tử — tử vụ đại trận tạm ngừng vận động, đệ tử thất tông nghênh đón tu sĩ bản địa, năm tiểu tinh cầu, lão quái các tiểu tu chân tinh, cả sứ giả huyền trấn liên minh đổ về. Triệu Tinh Sát — đại sư huynh Tử hệ — canh giữ tử vụ đại trận, độc thoại điểm danh sáu vị tử khác (lão nhị bỏ cuộc, lão tam coi thường, lão tứ nữ có cách giữ, lão ngũ bị phạt thiên ngục, lão lục sinh tử chưa rõ) và cảnh cáo lão thất chớ tranh đoạt danh hiệu Thiên Vận thất tử với mình. Kim Ma tử — tôn giả độc chiếm một tiểu tinh, thân tròn như cầu thịt da trong như thủy tinh, đồn đạt Hư Thật nhị ý — đáp chiến xa vàng do bốn yêu thú nâng đỡ tới chúc thọ, được Triệu Tinh Sát cung kính dẫn về, dù thân phận chỉ đủ ngồi tiệc Xích tông. Thọ yến chia tám chỗ cho thất tông và Thiên Vận Tử, số người được vào Thiên Vận Tông không quá trăm. Cuối chương, một nam tử tóc dài tại thạch lâm mở mắt phát quang như trăng rằm, nhấn tay phá nát thạch lâm mười dặm, há miệng hút thu khí tức như phễu rồi thét dài chấn động thiên địa — khả năng cao chính là Vương Lâm hoàn tất bước đột phá."},{"chuong":461,"tieuDe":"Tử Khí Đông Lai","tomTat":"Sau ba tháng bị tấm màn sáng hình vòm vây khốn trong thạch lâm rộng mười dặm, Vương Lâm bay lên sát đỉnh màn dùng Tịch Diệt Chỉ điểm tạo vết nứt nhưng trận tự khôi phục. Hắn chuyển sang Hóa Ma Chỉ, nghịch hóa toàn bộ tiên lực thành ma hỏa tím; nhờ đã đột phá Anh Biến trung kỳ bằng tiên ngọc, hắn thiêu rụi cả tấm màn chỉ trong ba nhịp thở. Không thuộc địa hình, Vương Lâm phất hồn phiên thả nguyên thần Tào Nhất Đấu, được chỉ hướng tây ba mươi vạn dặm tới sơn môn Thiên Vận Tông. Trên đường hắn hồi tưởng bị Tử hệ nhất mạch và Triệu Tinh Sát na di vây khốn, lập thề ai phạm ta giết không tha. Sau giờ ngọ ngày thứ hai, hắn tới giữa thọ yến ngàn năm của sư tôn Thiên Vận Tử, nơi Tử tông bày tiệc náo nhiệt và sáu đại trưởng lão tông phái nhỏ cùng dự. Đúng lúc đại sư huynh Triệu Tinh Sát đứng dậy chúc rượu, một đạo cầu vồng màu tím từ chân trời đằng đông lao thẳng tới, báo trước cuộc đối đầu."},{"chuong":462,"tieuDe":"Xông Vào Yến Tiệc","tomTat":"Một đám mây tím phá không bay tới Tử Tông Sơn trên Thiên Vận Tinh, kinh động buổi thọ yến của sư tôn Tử hệ; Triệu Tinh Sát bóp nát chén rượu khi nhận ra Vương Lâm chẳng những thoát vây mà còn đột phá Anh Biến Trung Kỳ. Nhị sư huynh Hứa Lập Quốc hóa tử quang nghênh chiến, phóng Thượng chi lực hóa đám cát như bầy ong nhưng bị Vương Lâm dùng Cấm Phiên tạo cơn lốc cấm chế đen xé tan. Vương Lâm cảnh cáo các tu sĩ tông phái khác không được can dự, rồi khơi ma hỏa quyết đòi mạng kẻ thù. Khi Triệu Tinh Sát bước ra dùng Đại tự tại thiên địa quyết bọc ma hỏa, Vương Lâm hô “Bạo”, ma hỏa tự nổ thiêu vỡ quầng sáng trắng, quét nghìn trượng tạo hố lớn khiến mọi tu sĩ tản chạy. Vương Lâm vung tiên kiếm cùng loan đao truy sát; Hứa Lập Quốc dùng cấm thuật Tiên Ma thể hóa sương mù đen hòng trốn nhưng bị chém tan, lộ tên thật. Cuối cùng Vương Lâm dùng Côn Cực Tiên kéo dài đánh trúng nguyên thần đang thuấn di cách nghìn trượng, khiến nguyên thần trọng thương sắp tan, phát tiết lượng lớn tiên lực tinh hoa, trong khi Triệu Tinh Sát đứng nhìn cười lạnh không cứu."},{"chuong":463,"tieuDe":"Cổ Yêu","tomTat":"Vương Lâm dịch chuyển bắt lấy nguyên thần đang hoảng sợ ném vào Tôn Hồn Phiên rồi chỉ thẳng Triệu Tinh Sát, tuyên bố ai cản trở sẽ thành kẻ thù; các chấp pháp trưởng lão Tử Tông do dự không dám tiến. Triệu Tinh Sát quay sang cầu viện lão tứ, nhưng nữ tử bình thản đáp ân tình ba tháng trước đã đền đáp và đã đồng ý không tranh danh hiệu Thiên Vận Thất Tử, khiến hắn mất chỗ dựa. Bị dồn ép, Triệu Tinh Sát dùng trước thuật triệu Cổ Yêu vốn định để dành: ký hiệu cổ quái lóe giữa lông mày gọi ra hư ảnh yêu vật trăm trượng, càng dùng thân thể càng suy yếu. Khương Thiên Tôn, trưởng lão Vấn Đỉnh Hậu Kỳ của Thủy Vân Môn, nhận ra đó là cổ yêu trong truyền thuyết thượng cổ và gọi tên Yêu lực — khí tức vượt xa linh lực, ngang tiên lực và ma hỏa. Vương Lâm dùng Tôn Hồn Phiên thu hồi chủ hồn bị lốc xoáy đỏ hút, rồi triệu Hồn Thú từ Xạ Thần Xa đâm xuyên thân cổ yêu. Khi cổ yêu định nuốt Hồn Thú, từ tổng tông vang tiếng hét của Xích Liệt sư thúc buộc nó rút lui, Triệu Tinh Sát phun máu cười u ám. Vương Lâm điềm tĩnh thu Khu Thú Quyển, ung dung về ngồi vào chỗ của mình; Triệu Tinh Sát cung kính tham kiến Xích Liệt, xác nhận từng gặp mặt mấy ngàn năm trước."},{"chuong":464,"tieuDe":"Cửu Chuyển Luyện Tiên Quyết","tomTat":"Xích Liệt khẳng định yêu linh trong Triệu Sát Tinh vừa hình thành đã gượng sử dụng nên áp giải hắn về cho sư phụ trừng phạt, đồng thời tiết lộ sư phụ kỳ vọng cao ở Vương Lâm và đại sư huynh Tử hệ sẽ không tranh danh hiệu Thiên Vận Thất Tử, rồi hóa mây đỏ bay đi. Vương Lâm trở thành tâm điểm yến hội ngày cuối, được các tu sĩ tông phái kéo đến chúc rượu; đêm khuya tứ sư tỷ trao một ngọc giản chứa cấm pháp Đại Na Di cùng một cấm pháp do sư tôn phỏng theo hạ phẩm tiên thuật, coi như xin lỗi việc tháng trước. Trên đường về Tử Vi Các, Bạch Vi lộ vẻ ác độc, trách sư tôn đã cấy yêu linh vào đại sư huynh khiến kế hoạch báo thù lung lay. Về mật thất Tử Lâm Các, Vương Lâm thử thành công Đại Na Di — bước bảy bước trong hào quang bạc rồi xuất hiện trên đỉnh núi cách mười vạn dặm, xác nhận đã đứng đúng trên Thiên Vận Tinh. Sau đó hắn tới thung lũng hẻo lánh, đặt tên cấm pháp thứ hai là Cửu Chuyển Luyện Tiên Quyết, lần lượt tu thành nhất chuyển, nhị chuyển, tam chuyển và ngưng luồng kim tiên lực sắc bén ở tay trái — đánh dấu lần đầu tu thành tiên thuật chân chính. Trời sáng, lễ giảng đạo vạn năm một lần của Thiên Vận Tử bắt đầu, bảy hệ tông Xích, Chanh, Hoàng, Lục, Thanh, Lam, Tử lần lượt xuất hiện kính bái, Tử Tông chỉ ba người nên bị sáu tông khinh bỉ châm biếm. Vương Lâm quét mắt nhận ra ba cao thủ: Tư Mã Như Phong Anh Biến đại viên mãn của Lam Tông, một nam tử họ Vương mặt lạnh của Thanh Tông đã bước nửa bước vào Vấn Đỉnh, và người trung niên vị trí thứ tư Cam Tông — chính là người năm xưa ở tiên giới đánh nhau với Sất Hổ bằng Sát Khí Huyết Tinh, nay đã Anh Biến Hậu Kỳ."},{"chuong":465,"tieuDe":"Tôn Trưởng Lão!","tomTat":"Tại đại thọ vạn năm của Thiên Vận Tử, Vương Lâm với thân phận đệ tử Tử Hệ đánh giá thực lực thất hệ, nhận thấy nhiều đệ tử ẩn giấu bản lãnh và trừ Tử Hệ thì các Hệ khác đều có thể hoành hành ở Chu Tước Tinh. Tứ sư tỷ truyền âm than thở rằng Tử Tông đang sa sút vì tranh đoạt nội bộ, danh hiệu Thiên Vận Thất Tử đổi quá thường xuyên, không còn uy phong như thời Tôn Vân sư đệ. Thiên Vận Tử xuất hiện trên quầng sáng bảy màu, được toàn tông và vô số tu sĩ tham bái, rồi bất ngờ mời lão bằng hữu từ tu chân liên minh. Tôn trưởng lão giáng lâm bằng đạo kim quang vạn trượng ngưng tụ thành trận pháp khổng lồ, dáng vẻ khoảng bốn mươi tuổi mặc trường bào tím, uy áp khiến các cao thủ phải cúi đầu. Ông tặng phi kiếm trung phẩm tiên khí ngưng luyện vạn năm, Thiên Vận Tử nhận rồi tặng lại Côn Bằng Tử của Hoàng Hệ. Khi Thiên Vận Tử bắt đầu giảng Thiên Vận Chi Đạo, con tiểu điêu ba mắt của Tôn trưởng lão bay tới đậu lên vai Vương Lâm dò xét, khiến hắn thấy quen quen và chăm chú quan sát."},{"chuong":466,"tieuDe":"Hắn!","tomTat":"Vương Lâm nhìn con tử điêu ba mắt đậu trên vai và qua truyền thừa ký ức cổ thần Đồ Ti nhận ra đó là Tinh Ngân điêu còn nhỏ — loài sinh vật hiếm trưởng thành có thể biến ảo thành vạn vật, hóa hình người, là tài liệu tốt nhất chế con rối thần thông. Con chim không màng thượng phẩm tinh thạch mà chỉ chăm chú nhìn hắn vì bị khí tức cổ thần cực yếu trên người hắn thu hút, rồi đoạt nuốt liền hai khối tiên ngọc với tốc độ chỉ thấy tử quang lóe lên trước khi đậu sang vai Tôn trưởng lão. Trên tường vân, Thiên Vận Tử bắt đầu giảng đạo, liệt kê bảy cảnh từ Ngưng Khí tới Vấn Đỉnh thuộc bước một chữ ‘tu’, bước hai là hư thực nhị ý và toái niết tam cảnh nơi hầu hết tu sĩ phải dừng chân do một lực lượng trong cõi u minh nhiễu loạn. Một hắc y nhân mặt sẹo tỏa hung khí trầm giọng hỏi về bước thứ ba, được Thiên Vận Tử giải thích đó là chữ ‘đạo’ cầu thiên vận, tu thành đạt độ cao không ngờ nhưng cách tu thành thì không ai biết. Được sư tôn gọi đích danh, Vương Lâm vấn đạo phân biệt tu tiên, tu chân, tu đạo: tiên giới đã mất nên ‘tiên’ và ‘chân’ thành quá khứ, nay tu sĩ chỉ truy tìm ‘đạo’ mà không phải thiên đạo, khiến tu sĩ bốn phía tranh cãi cuồn cuộn. Khi Vương Lâm tỏ ý hoài nghi có thực sự tồn tại bước thứ ba, Thiên Vận Tử bồi hồi tiết lộ ba ngàn năm trước nhờ gặp được ‘hắn’ mới tin, lời này khiến Tôn trưởng lão lộ vẻ sợ hãi và cả hội trường trầm mặc dị thường."},{"chuong":467,"tieuDe":"Gặp Lại Lăng Thiên Hầu","tomTat":"Sau khi nhắc tới một nhân vật bí ẩn, Thiên Vận Tử bị tu sĩ truy hỏi và tiết lộ “hắn” là kẻ duy nhất lão biết đã đạt tới bước thứ ba, từng khiến Tu Chân Liên Minh nếm khổ một lần rồi biệt tích. Buổi giảng đạo ba ngày nhân đại thọ vạn năm kết thúc, Vương Lâm im lặng lắng nghe và dần có lĩnh ngộ. Theo lệ, Thiên Vận Tử tuyên bố sẽ thi triển một trung phẩm Tiên thuật — điều cực hiếm khiến đông đảo tu sĩ tề tựu, và là lần đầu Vương Lâm được thấy Tiên thuật thật. Đúng lúc đó, Kiếm Tôn Lăng Thiên Hầu, Tông chủ Đại La Kiếm Tông, cưỡi biển phi kiếm cùng hơn vạn đệ tử áo đen xuất hiện, sau lưng có bốn bóng kiếm hư ảo, dưới chân là xà hình bảo kiếm mà Vương Lâm nhận ra chính là Vũ chi đệ nhị kiếm. Lăng Thiên Hầu lạnh lùng đồng ý làm đối tượng để Thiên Vận Tử thi triển Dẫn Tiên thuật. Thiên Vận Tử phóng xích mang lên trời, hiện ra mảnh đỏ mây cuộn như rồng và sấm sét như rắn bạc, kèm thiên uy ép đa số tu sĩ tái mặt phải ngồi xuống; Vương Lâm vận tam chuyển kim tiên lực lưu chuyển toàn thân để chống đỡ và dần đứng vững lại."},{"chuong":468,"tieuDe":"Dẫn Tiên Thuật!","tomTat":"Khảo nghiệm áp lực kết thúc, Bạch Vi ngồi sụp xuống đất, cả Tử hệ chỉ còn Vương Lâm và Tứ sư tỷ trụ vững — Vương Lâm vận kim tiên lực ba vòng khôi phục, được Tứ sư tỷ liếc nhìn thâm ý. Thiên Vận Tử đổi hướng nhắm vào đệ tử Đại La Kiếm Tông, hô “Dẫn độ” thi triển Dẫn Tiên thuật cuốn hơn vạn đệ tử mê man bay lên hư không. Lăng Thiên Hầu thúc xà hình phi kiếm bị bắt giữ, triệu Kỳ Lân thú từ mi tâm lao tới, nhưng Tôn Hồn Phiên trong nguyên thần Vương Lâm phát tiếng gầm cộng hưởng khiến Kỳ Lân thú dừng lại, buộc hắn vội che giấu tàn hồn. Hư ảnh sứ giả Tiên giới mặc trường bào vàng hiện thân, ấn chưởng kim sắc phong kín toàn bộ đệ tử đưa vào hư không, khiến tu sĩ dự thọ kinh hãi và nghi ngờ về nguồn gốc Trung phẩm Tiên thuật. Lăng Thiên Hầu trách móc nhưng đành nhẫn nhịn chờ ba ngày đệ tử trở về, còn Thiên Vận Tử muốn mượn người hỏi xem đã đến đâu. Cuối cùng lão tuyên bố Hoàng hệ và Tử hệ hôm nay sẽ xuất hiện người mang phong hiệu Thiên Vận Thất tử, hé lộ chuyện lão Tam Hoàng hệ từng đạt phong hiệu rồi mất tích ở tinh không ba mươi năm trước."},{"chuong":469,"tieuDe":"Triệu Hân Mộng","tomTat":"Trong cuộc phân phong hiệu Thiên Vận Thất tử, sáu đệ tử Hoàng hệ lần lượt bỏ cuộc; cuối cùng lão đại Vận Đường — từng giữ phong hiệu hơn 800 năm rồi bị lão Tam đoạt — cũng nhường ngôi, đề cử Nhị sư đệ Côn Bằng Tử. Thiên Vận Tử trao Côn Bằng Tử khối tinh thể vàng dấu hiệu phong hiệu, hứa truyền Hạ phẩm Tiên thuật và bảo mệnh pháp bảo, để hắn vào bế quan. Vương Lâm phát hiện Vận Đường lộ biểu hiện quỷ dị và ánh mắt sợ hãi khi tinh thể vàng xuất hiện. Tứ sư tỷ Triệu Hân Mộng khiêu chiến Vương Lâm để hắn không đạt phong hiệu quá dễ dàng; Vương Lâm ban đầu định bỏ cuộc nhưng bị Thiên Vận Tử đích thân khuyên — người thứ hai sau Tôn Vân — nên đổi ý khai chiến. Triệu Hân Mộng dùng Tử Ma thủ mô phỏng từ Hoá Ma chỉ qua Yêu ảnh đạo, Vương Lâm đáp trả bằng Hoá Ma chỉ khiến ma khí ngập trời. Thiên Vận Tử độc thoại về ‘hắn’ gặp ba vạn năm trước và bước thứ ba của Thiên Vận đạo, xét Vương Lâm có phải người phù hợp số phận, ánh mắt cuối cùng lộ một tia chán nản."},{"chuong":470,"tieuDe":"Tử Hệ Lão Lục","tomTat":"Vương Lâm thi Hoá Ma chỉ đối đầu Tử Ma thủ của Triệu Hân Mộng; nàng dùng hạt châu hút ma lực hòng cướp đoạt, nhưng Vương Lâm vạch trần ma lực chỉ là tia hư ảo do tiên lực chuyển hoá và khiến nó tự sụp, viện lời hứa với Tư Đồ Nam mà từ chối nhường. Hai bên đấu Cửu chuyển luyện tiên quyết: Vương Lâm dù mới nhận công pháp vài ngày đã tu tới ngũ chuyển, lại rút chiến phủ Cự Ma Tộc và Xạ Thần xa, khiến Triệu Hân Mộng thừa nhận xem thường hắn rồi bỏ cuộc. Tiếp đó Tử hệ Lão Lục Trần Đào — đệ tử lâu năm từng đạt phong hiệu Thiên Vận Thất tử trước Tôn Vân — trở về dâng Thất thải lưu ly quang (kỳ bảo xếp thứ 93 Tu Chân Liên Minh) cho Thiên Vận Tử và đòi tranh lại phong hiệu. Thiên Vận Tử phán chỉ Trần Đào và Vương Lâm đủ tư cách nhưng chỉ một người đạt. Trần Đào khinh thường Vương Lâm rồi giao chiến: đẩy ngũ chuyển kim tiên lực lên cửu chuyển phản công, còn Vương Lâm dùng Đại Na Di làm cơn lốc biến mất rồi triệu Hồn thú chấn động cả trường. Trần Đào nổ tan đòn nuốt của Hồn thú, xé áo rút trường thằng đen nghênh chiến khi trận đấu còn dang dở."},{"chuong":471,"tieuDe":"Chiến Vấn Đỉnh!","tomTat":"Trong trận đấu tại lễ chúc thọ, Trần Đào khoe Long cân rút từ xác yêu long ở Yêu Tinh, vung từ góc độ khó tin buộc cổ Hồn thú của Vương Lâm rồi đứng trên đầu nó siết chặt khống chế. Vương Lâm bình thản kết ấn, lần đầu mở đạo phong ấn thứ nhất của Xạ Thần xa — pháp bảo bắn hạ được thần tiên mà hắn chưa từng dám mở vì sợ bị cắn trả, nay nhờ đạt Anh Biến trung kỳ mới đủ vài phần nắm chắc. Hồn thú đang bị khốn bỗng phát điên, bành trướng từ mười trượng lên hơn trăm trượng, hóa hắc mang phản công Trần Đào và đoạt được một số thiên uy thần thông. Trần Đào dựng tử sắc quang cầu phòng ngự nhưng vẫn bị tổn thương, sắc mặt khó coi vẫn nồng nặc chiến ý, mỉa mai Vương Lâm “có tư cách làm sư đệ”, bị phản bác rồi hóa tàn ảnh lao tới tấn công. Biết mình không phải đối thủ Vấn Đỉnh kỳ nhưng không từ bỏ, Vương Lâm nâng ngón út thi triển sát chiêu cuối Hoàng tuyền chỉ của Tư Đồ Nam: tiêu tan sinh mạng, trời tối sầm sét đánh, hiện tranh sơn thủy biểu thị Hoàng tuyền cùng Sinh tử luân hồi ý cảnh. Thiên Vận Tử ngưng trọng nhìn kỹ, Kiếm Tôn Lăng Thiên Hầu thầm khen, còn một lão già mặt đỏ mang hồ lô đỏ giật mình nhận ra sát chiêu này giống hệt của một “người điên” lão từng gặp, khi mọi ánh mắt đổ dồn về Vương Lâm."},{"chuong":472,"tieuDe":"Toái Tiên Chi Địa","tomTat":"Vương Lâm phóng hai đạo Hoàng tuyền chỉ công kích Trần Đào nhưng đối phương nhờ kỳ ngộ đạt Vấn Đỉnh trung kỳ nên đỡ được; Vương Lâm bị đẩy lùi, phun tiên huyết và bỏ cuộc, để Trần Đào đoạt phong hiệu Thiên Vận Thất tử của Tử hệ. Thiên Vận Tử trao tinh thể phong hiệu cho Trần Đào, kết thúc đại thọ vạn năm tuổi; Kiếm Tôn Lăng Thiên Hầu rời đi và nhắc ước hẹn ba tháng sau phải tuyển người vào Đông Hải Yêu Linh chi môn. Thiên Vận Tử nhận Vương Lâm làm đệ tử chân chính, hứa truyền Cấm pháp thần thông cùng pháp bảo bản mạng, đưa về Tổng tông ba ngọn núi tại Thiên Vận Tinh. Vương Lâm giải đúng câu đố rằng hai sườn núi hai bên là giả do Chân huyễn pháp, nên được đặc ân tự chọn Cấm pháp thần thông; cảnh ba ngọn núi gợi hắn nhớ ký ức Cổ Thần Đồ Ti về thanh tam xoa kích hóa cự sơn. Theo khảo nghiệm, hắn leo ngọn núi trắng phủ Cửu U chi hàn không dùng thuấn di, đến gần đỉnh trăm bước thì hạ chân xuống băng và bước vào Toái Tiên chi địa. Nơi đây hắn lĩnh ngộ Vấn Tâm chỉ cảnh — tâm lạnh hơn vạn vật băng hàn, ý chí bất khuất bao thân — và nhận ra Luân hồi đạo chính là đại Vô tình đạo, hiện Luân hồi Hoạ trục sau lưng. Vượt cực hạn Anh Biến trung kỳ, Vương Lâm đi hai mươi mốt bước khiến Thiên Vận Tử khiếp sợ, rồi tiếp tục bước thứ hai mươi hai và thêm năm bước nữa, tiến gần kỷ lục hai mươi sáu bước của Tôn Vân."},{"chuong":473,"tieuDe":"Ý Cảnh Nhập Thể!","tomTat":"Trên nền hai mươi bước, Vương Lâm dung một tia cảm ngộ vào tâm cảnh, bước thêm năm bước đạt cực hạn hai mươi bảy bước; Luân hồi Họa trục bộc phát khí thế kinh người, ý cảnh bắt đầu thực chất hóa và mở ra con đường lên Vấn Đỉnh. Sinh Tử Luân Hồi đạo của hắn là loại lĩnh ngộ cực hiếm khó thực chất hóa nhất, nhờ kết hợp Vấn Tâm chi đạo tại Toái Tiên chi địa mới khai thông; bước thứ hai mươi tám nếu bước ra sẽ khiến tu vi sụp đổ. Thiên Vận Tử dự đoán trong vòng trăm năm Vương Lâm có hy vọng Vấn Đỉnh, dùng ánh sáng bảy màu tạo cầu vồng đưa hắn tới dưới bảo tháp và kể nguồn gốc Thiên Vận Tông theo đuổi Thiên vận số. Lão xé không trung tỏa ánh sáng Tối hỉ thất thải chiếu rọi gần nửa bầu trời Thiên Vận Tinh, rồi chính thức thu Vương Lâm làm đệ tử thứ bảy của Tử hệ. Vương Lâm quỳ bái, thề chỉ cần sư phụ và Thiên Vận Tông không phụ hắn thì hắn không phụ lại; Tế đàn bảy màu hạ xuống, lệnh bài khắc danh tự cháy hóa lửa tím. Cuối chương, Thiên Vận Tử hỏi Vương Lâm muốn chọn loại Cấm pháp thần thông nào, hắn trầm ngâm vì đã có nhiều pháp công kích như ba thức sát chiêu của Tư Đồ Nam, Xạ Thần xa, kiếm tiên và loan đao."},{"chuong":474,"tieuDe":"Hơn Một Người!","tomTat":"Vương Lâm cân nhắc thần thông phòng thân và nhận ra Cấm pháp Đại Na Di cùng Ngân Long la bàn chỉ đủ đối phó tu sĩ Vấn Đỉnh, không kham được kẻ đạt cảnh giới Toái Niết. Hắn xin Thiên Vận Tử truyền ‘Sinh tồn pháp thuật’ nhưng bị từ chối, nên được sư phụ điểm ánh sáng bảy màu đưa vào thế giới bảy màu chứa 3600 đạo Cấm pháp thần thông để tự chọn. Quan khán hơn phân nửa, hắn ghi nhận Cửu chuyển luyện tiên quyết, Cấm pháp Tiên Ma thể và thần thông bảy màu (Tối hỷ khẩu thất thải) — chỉ thứ cuối khiến hắn khiếp sợ và gần như định chọn. Bất ngờ hắn chú ý một Thiên Vận Tử mặc áo bào màu tro, mắt xám, trẻ hơn và không có tiên lực; mọi công kích bằng Cấm chế ấn quyết, kiếm tiên và loan đao đều xuyên qua thân như ảo ảnh. Khi sát khí người áo xám lan ra, cả 3600 Thiên Vận Tử hô ‘Phong!’ dựng phong ấn nhưng bị một chữ ‘Cút!’ làm sụp đổ, đẩy lui mấy vạn dặm — thần thức Vương Lâm đếm ra tổng cộng 3601, ‘hơn một người’. Sau sáu lần chạm mặt, người áo xám tiết lộ Thiên Vận Tử đưa hắn tới chính vì Sát Lục Tiên quyết, một thứ bắt chước Tiên thuật vô danh dựa vào giết chóc đoạt sinh lực, với điều kiện ‘không lưu người sống’. Vương Lâm thi triển Sinh tử Luân hồi ý cảnh rồi trầm mặc từ chối ‘Ta không học!’; người áo xám không đáp câu hỏi về quan hệ với sư phụ mà hoá một ngọc giản từ bụi khí để lại, và Vương Lâm bắt lấy, ánh mắt trầm ngâm."},{"chuong":476,"tieuDe":"Huyền Uyên Phái","tomTat":"Vương Lâm bước vào Truyền tống trận khổng lồ phạm vi mười dặm của Huyền Uyên Phái; tu sĩ Triệu Tứ kết quyết đánh một đạo thanh quang vào trận, toàn trận chấn động và truyền Vương Lâm vượt liên tinh cầu rời Thiên Vận Tinh tới Địa Tinh. Triệu Tứ ở lại hâm mộ nhìn theo, thắc mắc Thất sư tổ tới Địa Tinh làm gì rồi chuyên tâm tu luyện hướng Hoá Thần hậu kỳ. Địa Tinh là một trong năm tinh cầu phụ quay quanh Thiên Vận Tinh, nơi có Huyền Uyên Phái — Lục cấp tu chân quốc duy nhất do Lão Tổ Huyền Minh đứng đầu. Thiếu Tông Hứa Vân Sơn cầm bảo phiến ngọc bích cùng các Trưởng lão ra Truyền tống trận nghênh đón, vì sớm biết sứ giả mới là Tử hệ Lão Thất Vương Lâm nên rung động muốn kết giao. Vương Lâm hiện thân, thấy Hứa Vân Sơn cũng là Anh Biến Trung kỳ nên thuận theo, được thu xếp chỗ u tĩnh. Trong hoa viên, hắn ngẫm về việc đề cao tu vi để đối phó Thác Lâm, về Sát lục tiên quyết, Sinh chi lạc ấn và Thiên nghịch châu còn thiếu kim thuộc tính. Sau hai ngày, Hứa Vân Sơn đưa hắn tới Ngũ cấp tu chân quốc Linh Nhạc quốc để nhận chức sứ giả, nơi có toà tháp chọc trời làm chỗ ở của các thế hệ sứ giả."},{"chuong":477,"tieuDe":"Sứ Giả","tomTat":"Vương Lâm chính thức nhậm chức Sứ giả của Huyền Uyên Phái tại Linh Nhạc quốc, được hơn trăm tu sĩ cung kính đón tiếp; Hứa Vân Sơn cáo từ rời đi, để mình hắn tọa trấn Thông Thiên tháp. Hắn tuyên bố bế quan, cấm mọi người bước vào phạm vi ngàn dặm, dùng Cấm Phiên phóng hắc khí tạo màn sương đen và thả các Chủ hồn từ Tôn Hồn Phiên ra phòng bị, rồi nghiên cứu Sát Lục Tiên quyết — một đạo Sinh chi lạc ấn dựa vào giết chóc mà sinh ra. Suốt hơn một tháng hắn không tìm được điểm khởi đầu nên chuyển sang lĩnh ngộ thiên đạo; cùng lúc Xạ Thần xa cắn trả lần đầu kể từ khi giải khai đạo phong ấn, hắn đại chiến Khuất thú mấy ngày rồi dùng bí pháp áp chế thành công. Thiên Thai lão nhân, cao thủ đệ nhất Linh Nhạc quốc, đến tháp thăm dò, tận mắt thấy Khuất thú nên khiếp sợ, khiến các tông phái hạ lệnh lập cấm địa quanh tháp. Cuối cùng Vương Lâm ngộ ra Sát Lục Tiên quyết phải cảm ngộ từ giết chóc thật, bèn thu hết màn sương đen ngưng thành Cấm Phiên tím đen và thu Chủ hồn tế luyện. Nhớ lời sư phụ dặn đến Đông Hải trong ba tháng, hắn lên đường, trước hết tới Ngũ Linh Sơn gặp Thiên Thai lão nhân."},{"chuong":478,"tieuDe":"Địa Ma Bắc Giới","tomTat":"Thiên Thai lão nhân tự trách vì để lão đạo phá quy củ kinh động Khuất thú khiến Vương Lâm không thu phục được con thú, rồi trao cho hắn ngọc giản ghi ba chỗ yêu thú tụ tập trên Địa Tinh; lão nhận ra giữa mi tâm Vương Lâm ẩn sát khí và đoán hắn đi vì giết chóc. Vương Lâm thi triển pháp thuật thuấn di ngân mang, bước mười bước cực hạn tạo dị tượng mặt trời bạc để tới Cực Bắc Địa Tinh, hiện thân tái nhợt phải dùng đan dược hồi phục. Hắn hoá tử hồng bay tới trước tấm bia đá khắc bốn chữ đỏ Địa Ma Bắc Giới, tuyên bố sẽ tu Sát Lục Tiên quyết tại đây vì công pháp phải ở trong giết chóc mới lĩnh ngộ, rồi bước thẳng vào làn sương mù. Ngay sau đó nhóm năm người Đại La Kiếm Tông do đại sư huynh Quách Tà Dật dẫn đầu bay đến chân bia, chờ Sư bá. Quách Tà Dật mâu thuẫn với Thiên Cầm cô nương vì mượn danh sư môn chiếm Diệu Kim quả, chỉ hứa để lại cho nàng một quả. Cuối chương ba Trưởng lão Đại La Kiếm Tông giáng lâm gồm một lão Hoá Thần hậu kỳ là sư thúc và hai Kiếm Các Trưởng lão Anh Biến sơ kỳ, được Quách Tà Dật quỳ tham kiến; trong sương mù Vương Lâm để tâm tới Đại La Kiếm Tông nhằm tìm tung tích Chu Dật tiền bối và tò mò về Diệu Kim quả."},{"chuong":479,"tieuDe":"Văn Thú Tiến Hoá!","tomTat":"Hai lão già Anh Biến sơ kỳ — Trưởng lão Đại La Kiếm Tông — tra hỏi Quách Tà Dật về Diệu Kim quả; hắn chỉ về phía Thiên Cầm, khai rằng sư môn nàng phát hiện vật nhưng có yêu thú thủ hộ nên không lấy được. Nghe Thiên Cầm đáp ước chừng trăm quả, lão già thấp người mắt bừng tinh quang; đồng môn nàng tức giận trách Đại La Kiếm Tông liền bị nàng quát im. Quách Tà Dật xin cho nàng một quả, lão già cao người đồng ý và bảo dẫn đường; Thiên Cầm chua xót hận hắn phản bội nhưng vì khí tức hai Trưởng lão vượt xa sư môn nhỏ bé của mình nên đành cắn răng dẫn đoàn vào Địa Ma Bắc Giới. Trong khi đó, Vương Lâm phi hành trong Tùng Mãng Sơn mạch tu luyện Sát Lục Tiên quyết, giết tiểu thú sương đen và Bôn Ngưu thú để thu bụi khí nghi là sinh lực, đồng thời thả Văn thú hấp thu nội đan, huyết nhục các yêu thú Hóa Thần để nuôi nó lớn lên. Văn thú — thú đến từ tinh không, càng ăn càng mạnh — lóe bạch mang mỗi lần nuốt, đang ở thời khắc mấu chốt sắp tiến hóa, khiến Vương Lâm thấy hình ảnh một tinh cầu đầy Văn thú vô tận. Cuối cùng hắn phát hiện vị trí Diệu Kim quả ở phía Nam, cưỡi Văn thú bay nhanh tới, dự định dùng hai lão Anh Biến sơ kỳ làm thí luyện giả cho công pháp của mình."},{"chuong":480,"tieuDe":"Cửu Lê Trùng","tomTat":"Đoàn Đại La Kiếm Tông gồm hai Trưởng lão Anh Biến sơ kỳ là Thạch Phương và lão già thấp người, một lão già Hoá Thần kỳ (sư bá Quách Tà Dật) cùng Thiên Cầm dẫn đường, tiến sâu vào Địa Ma Bắc Giới tìm Diệu Kim quả. Càng vào sâu, một cỗ áp lực quỷ dị như vạn sơn áp đỉnh bao phủ, ánh mắt vô hình theo dõi khiến hai Trưởng lão khó thở và sinh ý giết người, song thần thức dò xét không thu hoạch gì. Vương Lâm ngồi trên Văn thú vô thanh vô tức bám theo phía sau, dựa ký ức Cổ Thần Đồ Ti nhận ra Diệu Kim quả thực chất là kim linh căn — vật khiến thân thể cứng rắn, thuốc bổ hiếm có với Cổ Thần thuở nhỏ và có tác dụng đặc thù với Văn thú đang loé bạch mang khát vọng. Thiên Cầm chỉ tới sơn cốc, Thạch Phương ngưng côn tiên lực hoá tiên phong thổi tan cây cối, mở thông đạo lộ ra phiến hoa vàng cùng đám Diệu Kim quả nhỏ như đầu ngón tay. Hai Trưởng lão phát hiện ổ Cửu Lê trùng ẩn dưới lá khô gần đó làm mãnh thú thủ hộ, cần dược dẫn để đối phó. Lão già thấp người tàn nhẫn dùng lực vô hình ném gã đồng môn áo trắng bên Thiên Cầm vào sơn cốc làm mồi, lập tức vô số điểm đỏ Cửu Lê trùng như tia chớp dày đặc lao ra cực kỳ đáng sợ."},{"chuong":481,"tieuDe":"Vỡ!","tomTat":"Nam tử áo trắng — sư huynh của Thiên Cầm — bị ném vào giữa sơn cốc và bị vô số Cửu Lê trùng chui vào da thịt ăn thịt, dãy dụa thảm thiết rồi tắt tiếng trong tuyệt vọng. Thiên Cầm chấn động gặng hỏi tiền bối vì sao, từ thê thảm chuyển sang bình tĩnh đáng sợ, trong khi Quách Tà Dật thừa nhận đã dựng nên việc này và kết thù với nàng. Thạch Phương, Trưởng lão Đại La Kiếm Tông, dùng cấm thuật Kiếm phong chi cấm qua ngọc giản đỏ hóa lưới tơ kết kỳ hiệu điện quang phong ấn đàn trùng; cùng lão già lùn dọn sạch số Cửu Lê trùng còn sót để mở đường vào cốc. Lão già lùn sai Lữ Tùng Nghĩa — lão già Hóa Thần kỳ, sư thúc Quách Tà Dật — đi hái Diệu Kim quả trên tảng đá vàng. Đột nhiên một cơn gió mát khiến hai Trưởng lão đại biến sắc mặt, cảm giác đè nén từ khi vào Địa Ma Bắc giới bùng nổ, một đoàn bụi khí nồng đậm xuất hiện ngoài cốc. Lão già lùn ném gương đồng tỏa thanh quang và Thạch Phương hóa bóng kiếm hơn mười trượng chém xuống, còn Lữ Tùng Nghĩa lao tới bên Diệu Kim quả. Bụi khí bùng lên như vạn mã phá tan tất cả, giọng lạnh lẽo vang lên rằng ánh sáng đom đóm sao sánh được ánh trăng, khiến gương đồng vỡ vụn và kiếm của Thạch Phương tan biến."},{"chuong":483,"tieuDe":"Giết!","tomTat":"Vương Lâm vỗ túi trữ vật, kiếm tiên nhốt Hứa Lập Quốc cùng thanh loan đao truy đuổi giam giữ lão già thấp người Trưởng lão Đại La Kiếm Tông đang bỏ chạy. Đối mặt kiếm quang và nguyên thần ly thể của Thạch Phương, hắn dùng kính tản tia sáng phát Tứ chuyển hàm tiên lực vỗ tan kiếm quang làm nứt vỡ sơn cốc, rồi thả tiên ảnh đánh trọng thương nguyên thần và sai Văn thú nuốt sạch thân xác Thạch Phương chỉ chừa hài cốt. Thạch Phương vội đoạt xá tiểu bối Quách Tà Dật theo lối siêu tốc khiến Vương Lâm kinh ngạc, rồi cầu xin tha mạng, giết hai tiểu bối để tỏ thành ý và hiến ngọc giản đoạt xá kèm thần thông mượn xử nữ chữa thương. Thiên Cầm run rẩy quỳ cầu Vương Lâm giết Thạch Phương cùng Trưởng lão Đại La Kiếm Tông, nguyện làm trâu ngựa hầu hạ. Vương Lâm dò hỏi vụ kiếm hồn và Kiếm Tôn Lăng Thiên Hậu hai trăm năm trước nhưng nhận ra Thạch Phương không nói thật, nên sau khi nhận ngọc giản đã phóng khí xám khiến thân Thạch Phương nổ tung, để lại một khối cầu xám. Cuối cùng hắn tới mảng hoa vàng phía Tây hái một Diệu Kim quả, dự định bổ kim thuộc tính cho Nghịch Thiên châu vốn còn thiếu gần một nửa sau trận Chu Tước mộ, chưa lập tức tra hỏi Trưởng lão Đại La Kiếm Tông đang bị giam."},{"chuong":484,"tieuDe":"Kim Linh","tomTat":"Vương Lâm đặt Diệu Kim quả lên mi tâm nhưng thất vọng khi nhận ra nó khó làm viên mãn kim thuộc tính của Nghịch Thiên châu, nên cho Văn thú hút một phần ba số quả. Theo ký ức Đồ Ti, hắn bố trí ngọc giản khắc văn, kết thủ ấn cổ quái và thốt Chú ngôn ‘Một!’, phóng ánh sáng vàng làm nổ từng ngọc giản, ép hoa, quả và cành cây héo rũ tan thành chất lỏng vàng dung nhập xuống đất. Sau nửa nén hương, hắn bới đất thu được bốn kim linh căn cỡ ngón tay cái giống nhân sâm, hiểu rằng nếu hình thành tự nhiên hẳn đạt năm chiếc. Thiên Cầm đứng xem từ chỗ đau lòng vì quả héo rũ đến vỡ lẽ giá trị thật của Diệu Kim quả nằm ở gốc rễ. Vương Lâm ném một rễ cho Văn thú khiến nó bắt đầu biến hoá và bị kim quang bọc thành lồng vàng, một rễ cho Lôi Oa, rồi tặng Thiên Cầm sợi cuối coi như đền cơ duyên, thu thân cây lưu cho bổn tôn. Hắn hoá khói rời đi, phóng vào chỗ sâu Địa Ma Bắc giới. Ở nơi khác, Trưởng lão Đại La Kiếm Tông mặt tái nhợt ngồi trên đại thụ, bị một thanh loan đao chĩa mi tâm và một kiếm tiên chĩa thiên linh cái uy hiếp, không dám cử động."},{"chuong":485,"tieuDe":"Mục Tiêu - Đông Hải!","tomTat":"Vương Lâm khống chế lão già thấp người của Đại La Kiếm Tông bằng phi kiếm cực cứng và thanh loan đao quỷ dị dán chặt mi tâm, ép lão khai mọi điều. Lão khai chuyện Kiếm Tôn từ tiên giới trở về bị một đạo kiếm hồn truy kích, cuối cùng phong ấn hơn 1/3 kiếm hồn cùng Chu Dật ở chỗ sâu trong Đông Hải Yêu Linh chi môn — một trong ba đại cấm địa bên ngoài Thiên Vận tinh, nơi huyết tinh thí luyện mở mỗi năm ngàn năm, với phần thưởng Yêu Linh quán đính có thể tăng một cảnh giới và hỗ trợ đột phá Vấn Đỉnh, Âm Dương nhị ý. Khai xong, qua cảm ứng của Hứa Lập Quốc, loan đao xuyên đầu giết lão; lão dùng Tam phân thần thức thuật tái sinh lần cuối và thề báo thù, nhưng vừa bay đi liền bị hai làn khí xám Sát lục tiên quyết của Vương Lâm xuyên thân hút sạch sức sống mà chết thật. Vương Lâm tự nhủ ba lý do đi Đông Hải: tu Sát lục tiên quyết, cứu ân nhân Chu Dật, và tuân lệnh sư phụ Thiên Vận Tử, đồng thời mong tìm kim thuộc tính giúp Nghịch Thiên châu viên mãn để Lý Mộ Uyển thức tỉnh. Hắn ẩn trong Địa Ma Bắc giới hai mươi ngày, ngưng kết Sinh ấn ba phân khiến thân thể cứng hoá kiếm chỉ không xuyên thấu, rồi hướng ánh mắt quyết đoán về phía Đông Hải."},{"chuong":486,"tieuDe":"Vì Sao Đông Hải","tomTat":"Chương giới thiệu Đông Hải Yêu Linh — nơi thần bí phía đông Thiên Vận Tinh trông như mặt biển hai màu xanh đỏ, cứ năm nghìn năm bập bênh một lần phát ra lực lượng kỳ dị hút mọi vật vào trong mà không phóng thích, được đồn là tiên phủ của một tiên quân hoặc không gian thông đạo trên cả tiên giới. Xưa kia Thiên Vận Tử cùng Kiếm Tôn Lăng Thiên Hậu lập nhóm thăm dò ba lần, lần thứ ba ra chỉ còn nửa quân số rồi hai người tách nhau, giữ kín bí mật; Thiên Vận Tử tuyên bố trong đó có Cổ Yêu và lập nơi này thành cấm địa, Tu Chân Liên Minh đành để mặc. Cứ năm nghìn năm cửa mở một lần là đại sự bậc nhất, các lão quái phái đệ tử Anh Biến đến Hư Thực Nhị Ý vào, nhưng cấm tu vi vượt Vấn Đỉnh và cửa chỉ mở một nửa. Còn năm ngày trước khi mở, vô số tu sĩ tụ về hư không; rồi hồng quang và mùi máu tanh báo hiệu Diêu Tích Tuyết — con gái Huyết Tổ Diêu Tinh Hải — cưỡi huyết ngọc khổng lồ đến, nhắm mắt khoanh chân ngồi chờ. Chương kể lai lịch Huyết Tổ: lão quái thông thiên từng bảy lần khiêu chiến Thiên Vận Tử, độc chiếm Huyết Tinh nạp huyết tu ma công, truyền toàn bộ công pháp cho con gái. Tại truyền tống trận Huyền Uyên phái trên một phó tinh, thiếu tông chủ Tôn Vân Sơn ngăn em gái áo hồng đòi lên Đông Hải, sai Huyền Nhất bắt nàng về dù nàng viện cớ “Mẹ đã đồng ý rồi”. Cuối cùng Tôn Vân Sơn phát hiện người đến qua truyền tống trận, mỉm cười nói “Vương huynh! Tôn mỗ chờ huynh đã lâu!”."},{"chuong":487,"tieuDe":"Hành Trình Của Tham Lang","tomTat":"Vương Lâm hóa đạo cầu vồng tử quang phóng tới hội hợp với Tôn Vân Sơn, người vốn cố đợi hắn để cùng đi Đông Hải Yêu Linh dù bị gia phụ ép buộc. Tôn Vân Sơn giới thiệu xá muội Tôn Nhược Nam và ba trưởng lão Huyền Uyên phái, rồi ra lệnh mở trận pháp tinh không tạo cầu vồng cao trăm trượng đâm vào tầng mây, nhưng từ chối cho Tôn Nhược Nam đi theo; nàng bèn lén dùng truyền tống ngọc giản trộm của cha hóa sợi tơ trắng bám theo. Ở cửa Đông Hải Yêu Linh phía đông ngoài Thiên Vận Tinh, hơn một vạn tu sĩ và nhiều lão quái tụ tập chờ hiện tượng thủy triều năm nghìn năm một lần, trong đó con gái Huyết Tổ Diêu Tích Tuyết được kiêng nể. Kiếm Tôn Lăng Thiên Hậu xuất hiện, cưỡi Hùng Lân thú dẫn theo Kiếm Tiếu Thập Nhị Tử, được tiết lộ là kình địch cả đời của Thiên Vận Tử. Mục đích thật của lão là mượn thủy triều để hút đạo kiếm hồn của một nữ quân tiên giới chìm sâu vĩnh viễn vào Đông Hải, quyết không để rơi vào tay Thiên Vận lão tặc. Ngay lúc đó Tham Lang cưỡi đống xương khô khổng lồ phá hư không xông vào, chào Lăng Thiên lão hữu, thân mang thương nặng vì phải tránh Tư Đồ Nam, và đề nghị tặng Kiếm Tôn một cơ duyên cực lớn để đè đầu Thiên Vận Tử."},{"chuong":488,"tieuDe":"Tâm Tư Của Tham Lang","tomTat":"Kiếm Tôn Lăng Thiên Hậu dò hỏi vì sao Tham Lang để ý một vật, Tham Lang tiết lộ chuyện mấy vạn năm trước Tu Chân Liên Minh treo thưởng một bộ thượng phẩm tiên thuật hoàn chỉnh để tìm một hạt châu, thừa nhận vết thương của mình liên quan đến hạt châu và đang bị người giữ nó bức bách. Lăng Thiên Hậu hoãn việc đến sau Đông Hải Yêu Linh, đổi lại yêu cầu Tham Lang vào trong bảo vệ mười hai đệ tử của lão hoàn thành nhiệm vụ bí mật, vạch trần tâm cơ Tham Lang và hứa mở cửa Yêu Linh cho hắn. Thiên Vận Tử mặc áo trắng từ đám mây bảy màu bước ra, dẫn chín đệ tử Thiên Vận Tông (gồm lão lục Trần Đào) tới cửa Đông Hải và được nghênh đón long trọng nhất; lão cùng Trần Đào tìm kiếm Vương Lâm. Vương Lâm hóa thân ảnh tử sắc phóng tới, tách khỏi Tôn Vân Sơn rồi cung kính bái kiến sư tôn, được nhận ra là Tử Hệ Lão Thất và đứng vào hàng chín đồng môn dưới ánh mắt thâm ý của Thiên Vận Tử. Lăng Thiên Hậu thấy hắn quen mặt, Tham Lang cảm thấy hắn như cố nhân năm xưa, còn Diêu Tích Tuyết theo lời phụ thân dò xét tên đệ tử mới. Thủy triều Đông Hải bắt đầu khởi động với tiếng nổ ầm ầm, hơn một vạn tu sĩ chấn động khi ngày hoàng kim năm nghìn năm một lần chỉ còn cách một ngày."},{"chuong":489,"tieuDe":"Thủy Triều","tomTat":"Tại cửa Đông Hải Yêu Linh — một trong tam đại cấm địa phía đông Thiên Vận Tinh — hiện tượng thủy triều năm nghìn năm một lần khởi động: mặt biển bập bềnh như nham thạch sắp phun, vô số vật trôi nổi giãy dụa giữa tiếng nổ ngập trời. Vương Lâm lần đầu chứng kiến nơi này, chỉ biết về nó qua lời Tôn Vân Sơn kể trên đường. Các vật trôi nổi chậm rãi xoay tròn dưới một lực kỳ dị, hút những tu sĩ tu vi yếu về phía vòng xoáy, nhưng đạo tâm Vương Lâm vẫn kiên định. Thanh khí xanh bốc lên ngưng tụ về trung tâm thành cột cao trên ngàn trượng giống mắt quỷ, tản ra cổ uy áp nồng hơn thiên uy gấp bội khiến Vương Lâm phải dùng đạo khí xám mi tâm hóa ký hiệu bao thân mới chống đỡ tới cực hạn, nhiều tu sĩ mặt trắng rút lui suýt chết. Lăng Thiên Hậu lẩm bẩm “Bắt đầu rồi!”, còn Thiên Vận Tử băn khoăn lần này vật gì sẽ bị hút đến. Cột thanh khí nổ tan, hồng quang đỏ chói tản ra vô tận bao phủ Đông Hải Yêu Linh, lan tới các tinh cầu hoang và tận Chu Tước Tinh khiến Chu Vũ Thái đang tĩnh tọa bừng mở mắt. Hồng quang dừng ở cực hạn, mọi vật vô chủ trong phạm vi — pháp bảo, ngọc giản, linh thạch, tiên ngọc, thi hài, cổ kiếm, tàn bảo, tiên quyết — đồng loạt rung động."},{"chuong":490,"tieuDe":"Lệnh Bài","tomTat":"Cửa Đông Hải Yêu Linh bên ngoài Thiên Vận Tinh mở ra, luồng hồng quang nghìn năm mới hiện một lần đột ngột ngừng rồi điên cuồng rút về như thủy triều, cuốn theo vô số pháp bảo, linh thạch, ngọc giản, tiên ngọc, yêu thú và linh vật vô chủ về cửa, làm tinh không vang tiếng nổ ầm. Vương Lâm kinh hoàng chứng kiến cảnh tượng hồng quang xuyên thấu thân thể tu sĩ như ảo giác, và nhờ ký ức Cổ Thần Đồ Ti nhận ra nhiều vật luyện khí quý như Thiên Kim Thượng, Quỳnh Hoa Dịch, Thủy Mặc Thạch, Linh Tê Giác cùng một thanh đại kiếm rỉ sét hình cánh cửa loé lên rồi biến mất. Con sóng hồng quang cuối quỷ dị ngăn cản thần thức khiến nhiều tu sĩ chạm vào liền sụp đổ, phun máu; một lão già gầy đét cảnh báo đừng dùng thần thức xem. Vương Lâm vận ba đạo ấn ký khí xám trên mi tâm thành thần thông ánh mắt, chịu đau chảy máu mắt, cuối cùng ánh mắt nổ tung phá vỡ hồng quang và nhìn rõ một khối lệnh bài kim quang khắc ký hiệu, khiến Thiên Vận Tử, Kiếm Tôn Lăng Thiên Hậu cùng các lão quái Thiên Vận Tinh đại biến sắc lao ra tranh đoạt. Sau đó, Diêu Tích Tuyết ngồi trên huyết ngọc phương xa vô ý nhìn thấy ánh mắt yêu dị mang khí xám của Vương Lâm liền chấn động, mặt tái nhợt vội cúi đầu, hiểu ra vì sao phụ thân dặn nàng phải chú ý đến người này."},{"chuong":491,"tieuDe":"Đông Hải Yêu Linh","tomTat":"Kiếm tôn Lăng Thiên Hậu chỉ tay về Đông Hải, bốn kiếm ảnh hóa cầu vồng đánh vào khối nước khổng lồ lơ lửng, mở ra lối vào hỗn độn xanh đỏ dẫn tới một thế giới khác. Kiếm Tiếu Thập Nhị Tử của Đại La kiếm tông vào trước, đệ tử cuối được ban kiếm khí bảo mệnh — chính là Tham Lang đã hóa thành; mười người Thiên Vận Tông gồm Vương Lâm cùng khoảng cả trăm tu sĩ nối nhau vào, Diêu Tích Tuyết hóa huyết quang bay theo. Lăng Thiên Hậu thu kiếm đóng cửa; Thiên Vận Tử xác nhận có ba lệnh bài liên quan đại bí mật Thiên Vận Tinh, ước định năm trăm năm sau tụ lại tiến vào lần nữa. Lăng Thiên Hậu về Đại La tinh bế quan, quyết hai trăm năm lấy chín chín yêu linh quy nhất luyện Tiên kiếm thành yêu kiếm; Thiên Vận Tử về bảo tháp bảy màu rải xương thú tà dị bói vận may Vương Lâm. Bên trong cánh cửa, Vương Lâm bị lực kỳ dị đẩy tản vào hoang nguyên một mình. Hắn lập kế hoạch năm trăm năm: tu Sát lục tiên quyết tới đại thành, tìm cứu Chu Dật, truy tìm Cự Phú học kiếm kỹ kiếm hồn, tất cả để đề phòng Thác Sâm thoát khốn truy sát."},{"chuong":492,"tieuDe":"Sơn Cốc","tomTat":"Vương Lâm trầm tư về khối lệnh bài bí ẩn trên Thiên Vận Tinh từng khiến Thiên Vận Tử và Lăng Thiên Hậu biến sắc, định mượn năm trăm năm ẩn náu ở tinh cầu để tăng nhanh tu vi và tránh Thác Sâm. Bay mười ngày qua bình nguyên hoang vu vắng lặng, hắn đột nhiên biến sắc rồi thuấn di tới một vùng núi non trùng điệp. Tại đó hắn chứng kiến một người nửa xích lõa, vẽ nhựa cây ẩn thân, không có linh lực nhưng linh tính kinh người, dùng dao u quang giết chết một con dã thú không linh lực mà máu lộ u quang. Vương Lâm hiện thân, người nọ cảnh giác giành con thú; hắn cười nhường rồi lặng lẽ theo dõi, thấy người này kéo thú vào một sơn cốc. Quan sát kỹ, Vương Lâm kết luận bên ngoài cốc có trận pháp ẩn giấu khí tức sinh mạng do tu sĩ thượng cổ bố trí, thủ pháp khác hẳn liên minh tu chân và khó phá giải trong thời gian ngắn. Hắn thử phóng linh quang dò trận thì bị luồng khí xanh thôn phệ phản kích, theo sát cũng bị cản lại. Cuối cùng hắn làm tan trường côn của một người mới xông ra, dùng lực vô hình giam bốn người để tra hỏi nguồn gốc nơi này, rồi hai người nữa từ trong cốc tiếp tục đi ra."},{"chuong":493,"tieuDe":"Trưởng Lão Trong Cốc","tomTat":"Hai sinh vật rời sơn cốc cắn lưỡi phun máu tạo nên huyết vụ đỏ dày đặc, từ đó một bóng đen ẩn hiện đòi Vương Lâm trả người và cút khỏi bộ tộc. Vương Lâm bước một bước sinh sóng không khí ầm ầm, làm tan huyết vụ trong chưa tới ba nhịp thở rồi bắt giữ kẻ hắc bào ném vào chỗ sáu người còn lại. Sau ba ngày, lão giả tóc bạc Âu Dương Hoa cầm quải trượng đen cùng mười một sinh vật thân trâu mình người bước ra, tự xưng trưởng lão sơn cốc, xin thả tộc nhân để đối thoại. Lão tiết lộ về Cổ yêu thành ngoài ba ngàn dặm, khuyên Vương Lâm tới đó tìm vật cần và nói người ngoài cứ bốn trăm năm lại tới một lần gây gió tanh mưa máu. Vương Lâm lấy Cấm Phiên phóng chín trăm chín mươi chín đạo cấm khí đen công phá trận, đồng thời nhận ra Âu Dương Hoa trước mặt chỉ là thế thân hư ảo. Trận pháp phản kích, hút kéo vạn vật ngưng thành hư ảnh người màu xanh cao mấy trượng để giết Vương Lâm lấy hồn phách tế yêu linh. Vương Lâm triển khai Cấm pháp chi mâu, ngưng cấm khí đen thành trường mâu ba trượng rồi vung hóa tia chớp đen lao thẳng vào hư ảnh xanh."},{"chuong":494,"tieuDe":"Phá Trận","tomTat":"Vương Lâm dùng trường mâu cấm khí phá không lao tới đánh tan thanh ảnh xanh của trận pháp thượng cổ, thì thanh ảnh bất ngờ bắt quyết đọc khẩu quyết như tu sĩ, kích hoạt lồng thanh quang phạm vi ngàn trượng vây giam hắn. Trong lúc lùi lại, Vương Lâm vận thượng cổ cấm chế của cổ thần để tính toán, ghép phù văn thành các tổ hợp cấm chế, đếm dần từ năm mươi bảy lên. Âu Dương Hoa từ trong sơn cốc cười lạnh chiêu hàng tàn nhẫn, đòi hắn tự cắt một tay một chân để hấp thu nguyên thần, còn dọa biến hắn thành yêu ảnh thứ hai. Thanh mang thôn phệ vạn vật thu nhanh, sinh vật đi qua héo rũ, ép tới chỉ còn cách ba trượng. Vương Lâm phản kích bằng phù văn cấm chế leo thang từ một đạo đến tổng cộng tám mươi ba tổ hợp, đánh tan thanh võng và cột sáng xanh. Hắn từng bước áp sát sơn cốc, lực lượng bảo vệ tiêu tán hoàn toàn, khiến Âu Dương Hoa hoảng sợ cầu xin tha mạng và thừa nhận biết sai."},{"chuong":495,"tieuDe":"Hoàng Long","tomTat":"Âu Dương Hoa dẫn mười tộc nhân ra khỏi sơn cốc, cung kính xưng Vương Lâm là thượng tiên và khẩn cầu hắn đừng phá trận pháp kẻo cả tộc bại lộ dưới yêu linh. Vương Lâm giơ tay điểm lên hư không, khôi phục trận pháp cổ làm tốc độ tiêu tán của lực lượng bảo vệ ngừng hẳn. Âu Dương Hoa vẩy giọt máu mở thông đạo mời vào cốc; Vương Lâm phát hiện cả sơn cốc đều là phàm nhân, cảm thấy xấu hổ nên ôm quyền tạ lỗi, ném ba bình ngọc đan dược cố bổn bồi nguyên rồi định rời đi. Âu Dương Hoa cảnh báo tối nay là đêm yêu linh, pháp lực thông thiên cũng khó chống nổi nên mời Vương Lâm về nhà mình. Tại đó Vương Lâm thấy bức tranh ố vàng vẽ Hoàng Long thượng tiên, người vô số năm trước dẫn tổ tiên Âu Dương Hoa đến định cư. Cái tên Hoàng Long khiến nguyên thần Vương Lâm chấn động, tâm thần hắn hồi tưởng quê nhà Chu Tước tinh và thời thiếu niên từ sơn thôn đi ra gia nhập Hằng Nhạc phái."},{"chuong":496,"tieuDe":"Thiên Yêu Quận","tomTat":"Vương Lâm trầm ngâm về bức tranh trong sơn cốc, nhận ra người trong tranh giống Hoàng Long chân nhân của Hằng Nhạc phái nhưng không thể là một người, càng thấy nơi yêu linh này yêu dị. Âu Dương Hoa giải thích mỗi đêm trăng tròn là đêm yêu linh đi săn mồi, chỉ trong trận pháp mới được bình an, và tiết lộ thiên hạ nơi yêu linh có chín quận; bộ tộc đang ở thuộc Thiên Yêu quận với yêu đế Tai Hư, bát đại yêu soái, thiên vạn yêu binh và hơn trăm thành trì. Lão còn kể quy luật cứ năm trăm năm lại có người bên ngoài tiến vào, gia nhập các quận lấy chiến công thăng tiến và có biến hóa thần kỳ, từng có người ngoài nắm một vị trí bát đại yêu soái. Khi Vương Lâm khoe hơn mười bình ngọc đan dược, Âu Dương Hoa hạ quyết tâm dẫn hắn đi xem vật người bên ngoài cần. Đi qua khu cư dân, Vương Lâm dừng lại xoa đầu một hài đồng v�� nhớ tới Đại Ngưu lúc nhỏ. Tới đáy sơn cốc hình hồ lô, lão chỉ vào khối ngọc yêu linh trắng hình lục giác khảm trong vách đá xanh thẫm — kết tinh tiên lực dùng chữa trị tộc nhân. Vương Lâm chụp lấy tinh thạch, hấp thu khí tức yêu lực cực lạnh chạy theo khớp xương tụ ở đan điền thành tinh thể cỡ hạt gạo, toàn thân biến hóa cực kỳ rõ ràng."},{"chuong":497,"tieuDe":"Hắc Y Nam Tử","tomTat":"Tại thung lũng Hồ Lô Cốc trên Thiên Vận Tinh, Vương Lâm cảm nhận yêu lực kết tinh vừa hấp thu khiến yêu khí trong người biến thành đoàn yêu hỏa, nhận định yêu lực này giống tiên lực nhưng quỷ dị và có thể dung hợp đẩy tu vi. Hắn lấy hơn mười bình ngọc đổi lấy yêu lực kết tinh duy nhất của thung lũng từ Âu Dương Hoa, rồi ngồi thiền suy ngẫm về công dụng ẩn giấu của nó, định thả lỏng tính tình giết chóc như năm xưa ở Tu Ma Hải. Đêm xuống, Âu Dương Hoa cùng dân cốc cầm vũ khí phòng thủ đêm Yêu linh săn mồi và niệm chú duy trì trận pháp đã suy yếu. Vương Lâm tách một tia nguyên thần hóa thần thức phóng đi, thấy yêu linh Đông Hải tạo đạo khí tím khuếch tán hình tròn hủy diệt sinh khí, rồi phát hiện Hắc y nam tử đang hấp thu yêu lực và tuyên bố coi hắn là con mồi. Vương Lâm nhận ra đối thủ là tu sĩ Ứng Biến hậu kỳ đại viên mãn, còn Hắc y nam tử lầm tưởng hắn chỉ Ứng Biến trung kỳ. Khi trận pháp bị sóng yêu khí công phá sắp vỡ, Hắc y nam tử hóa điện quang phi kiếm lao tới, Vương Lâm hiện thân ở cửa cốc bên cạnh Âu Dương Hoa, mở màn cuộc săn."},{"chuong":498,"tieuDe":"Sinh Chi Lạc Ấn","tomTat":"Âu Dương Hoa biến sắc kinh hãi khi nhận ra Vương Lâm; một kiếm quang chém nứt trận pháp thung lũng giam yêu linh, Vương Lâm vỗ túi trữ vật triệu Cấm Phiên gia cố khiến uy lực trận tăng mấy lần rồi bước ra ngoài. Cách mười trượng, hắc y nam tử La mỗ đạp phi kiếm đứng xem giữa sóng yêu linh khí; Vương Lâm diệt một đầu yêu linh thú và lạnh lùng cảnh cáo y rời đi, còn y do dự dò hỏi môn phái vì sợ giết nhầm người quen. Vương Lâm xuất kiếm tiên cùng loan đao làm rạn phi kiếm địch và đả thương ngực La mỗ tuôn huyết quang, buộc y nuốt đan dược khôi phục. La mỗ phản công bằng Địa diệt chi hỏa hóa sáu rồng lửa cùng cấm thuật Kiếm toái; Vương Lâm thi triển Sinh Chi Lạc Ấn — hai ký hiệu hiện mi tâm bao trùm toàn thân — chống đỡ, gây vụ nổ long trời dội ngược cả sóng yêu linh. Vương Lâm bước ra từ bóng tối, xuyên qua khí lãng yêu linh và suýt điểm trúng La mỗ. Cuối chương, La mỗ vạch rõ đối phương chính là đệ tử Thiên Vận Tử, Tử hệ lão thất Vương Lâm dùng cấm pháp Tịch Diệt Chỉ, tu vi Anh Biến trung kỳ nhưng từng đấu mười một trận Vấn Đỉnh, và lo ngại khó hạ sát vì hắn còn pháp bảo bảo mệnh."},{"chuong":499,"tieuDe":"Ma Cấm","tomTat":"Hắc y nam tử — tu sĩ Anh Biến hậu kỳ đại viên mãn tự xưng La mỗ, hành sự thay Tôn sư — phối hợp kiếm vỡ hàn quang và hắc hỏa phá mất một trong ba tầng Sinh chi lạc ấn hộ mệnh của Vương Lâm, khiến hắn tiếc nuối và sát khí đằng đằng. Vương Lâm truy kích bằng roi tiên Côn Cực Tiên; đối phương dùng huyết sắc ngũ sát đan lưới năm sao định phong ấn roi nhưng lần đầu thất bại, bị hắc mang phản khiến tay bốc khói trắng, rồi bị roi quất trúng đả thương nguyên thần. Hắc y nam tử phun độc khí chui vào yêu linh khí lãng rút lui, Vương Lâm niệm thần chú Phong gọi gió phá độc hóa mây thoát ra. Vương Lâm suy đoán đối thủ là người Thiên Vận Tinh vì biết danh tiếng và pháp bảo hộ mệnh của mình, quyết không tha. Hai người rượt đuổi xuyên đêm trong Yêu linh khí lãng, diệt sạch yêu linh cấp thấp và hấp thu yêu khí. Bị loan đao bám sát, Hắc y nam tử hút khói đen vào ngực chịu đau tột độ, thi triển Ma cấm hô “thiên quỷ đệ tứ tôn, hiện!” biến tay trái thành mười Quỷ ảnh quái dị; Quỷ ảnh nuốt luôn kiếm quang của Vương Lâm, còn tơ đen quanh thân hắn cản loan đao không vào gần được."},{"chuong":500,"tieuDe":"Gạt Bỏ","tomTat":"Đối mặt Quỷ ảnh (Thiên Quỷ) của Hắc y nam tử lao tới, Vương Lâm phun ra đại phiên hắc quang cao ba trượng, thả mấy chủ hồn — gồm tàn hồn kỳ lân — làm mồi nhử; Quỷ ảnh nhằm thẳng Anh Biến chủ hồn nên hắn thừa cơ ôm trọn nó, ném Khu Thú Quyển rồi chỉ ngón trỏ về phía đối thủ. Vương Lâm thi triển Hóa ma chỉ — chiêu thứ hai trong Tam thức sát chiêu, chiêu hắn từng dùng đấu Tử hệ lão Tứ — và kích hoạt Sinh chi lạc ấn, ký hiệu xám lan toàn thân giúp hắn xuyên qua khói độc vô hại để đuổi sát. Hai Hóa ma chỉ va chạm tạo tiểu cầu hủy diệt chứa điện quang như Thiên kiếp tiên lôi; Hắc y nam tử khoe mình Anh Biến hậu kỳ đại viên mãn còn Vương Lâm chỉ trung kỳ, nhưng Vương Lâm đáp Thiên Quỷ đã hấp thu tiên lực của hắn. Thiên Quỷ hạ quyết tâm tự sinh hắc quang, xuyên qua yêu linh khí lãng bỏ trốn khiến Hắc y nam tử nổi điên đổ lỗi. Mất quỷ vật hấp thu, hắn dồn gần 90% quỷ tiên lực vào tiểu cầu, đẩy nó áp đảo về phía Vương Lâm. Vương Lâm hô mở Xạ Thần Xa, dùng Cửu Tự Chân Ngôn học từ Ngọc giản tiên nhân khống chế Hồn thú bất khuất nhằm thẳng đối thủ, buộc Hắc y nam tử vỗ mi tâm cho nguyên thần rời cơ thể bỏ chạy; thân xác không hồn ngã ngửa, tiểu cầu đổi hướng lao thẳng về phía nó."},{"chuong":501,"tieuDe":"Sưu Hồn Thuật","tomTat":"Tiểu cầu của hồn thú đáp lên thân Hắc y nam tử, thiêu rụi toàn thân chỉ còn nguyên thần thoát ra; Vương Lâm lần đầu phối hợp ăn ý với hồn thú qua Xạ Thần Xa, thậm chí được nó chủ động cõng bay đi vì chê hắn chậm. Nguyên thần đối phương dùng Tổn Thần thuật bỏ chạy nhưng bị Vương Lâm dùng Côn Cực Tiên quấn bắt, giam vào hồn phiên trước khi kịp tự nổ. Hồn thú phẫn nộ vì bị cướp mồi, Xạ Thần Xa hóa Khu Thú Quyển hút mạnh tiên lực, Vương Lâm phải dùng tiên ngọc chống đỡ. Bị lập cấm chế ngăn tự bạo, Hắc y nam tử lộ thân phận là La Vân người Thiên Quỷ Đạo, dọa sư tôn Quỷ Chân Nhân sẽ báo thù. Vương Lâm thi triển Sưu Hồn Thuật, ép La Vân kêu la khoảng một nén nhang rồi bất động, rút khối kết tinh trong đan điền cùng toàn bộ ký ức. Cuối cùng hắn giam nguyên thần La Vân định luyện thành chủ hồn trong Tôn hồn phiên, hóa tia chớp bay theo hướng chủ hồn đang truy kích Thiên quỷ, ngẫm thấy trong ký ức La Vân có vài thuật ma cấm đáng tu luyện."},{"chuong":502,"tieuDe":"Thủy Cảnh","tomTat":"Vương Lâm nắm trọn ký ức La Vân, qua đó hiểu rõ vùng đất yêu linh chia mười quận, mỗi quận phong ấn một Cổ yêu chi linh — dung hợp được thì tu vi tăng vọt và có cơ hội tiến vào cảnh thần chi thủy, nơi tốc độ cảm ngộ thiên đạo tăng vọt và có thể tự sáng tạo tiên thuật. Hắn xác định kế hoạch của La Vân là nhập một quận để đạt chiến công, quận gần nhất là Thiên Yêu quận cần đủ ba giáp yêu lực; kiểm tra yêu tinh La Vân thấy hai giáp, cộng một giáp đã hấp thu vừa đủ ba giáp, nhờ đó hiểu vì sao La Vân muốn giết mình. Cái tên thần chi thủy gợi Vương Lâm nhớ tới Thủy cảnh cùng tài liệu Cực Cảnh, Đạo cảnh, Thủy cảnh từng chiếm ở động tiên ngầm trong Tu Ma Hải khi còn ở Chu Tước Tinh, và hắn mơ tưởng kết hợp Cực cảnh với Thủy cảnh thành đại đạo luân hồi rồi tự kiềm chế. Hắn dịch chuyển ngàn dặm tới một bình nguyên có khe rãnh, há mồm hút các chủ hồn âm hồn gồm một đầu lân dung nhập vào Tôn Hồn Phiên. Sau đó hắn giải thích cơ chế Thiên quỷ — vật thần thông của Thiên Quỷ Đạo sinh từ hư vô, được luyện thành bản mạng quỷ linh — và việc quỷ linh của La Vân phản chủ do hắn tu luyện quá ngắn. Cuối cùng Vương Lâm dùng thuật đám bụi khí hóa hàn quang truy diệt Thiên quỷ đang suy yếu trốn trong khe, phủ đầy tro bụi lên thân nó."},{"chuong":503,"tieuDe":"Luyện Hồn Tân Tông","tomTat":"Vương Lâm đứng ngoài khe rãnh dụ Thiên quỷ lao ra, dùng Côn Cực Tiên chuyên đánh nguyên thần quất cho nó suy yếu; theo trí nhớ La Vân, hắn biết Thiên quỷ cần bốn chín ngày tu dưỡng sau phản bội nên quyết bắt sống ngay lúc nó yếu nhất. Thiên quỷ giả vờ suy yếu rồi phun Bản mạng chi hỏa hòng hủy roi, nhưng Côn Cực Tiên bất ngờ lóe một đạo kim quang quỷ dị chụp tắt lửa khiến Thiên quỷ suýt tiêu tan; Vương Lâm vội thu roi, dùng hồn phiên cuộn Thiên quỷ vào giữ lại. Sau khi bị lửa đốt, Côn Cực Tiên cuộn lên một lớp da cực cứng như rắn lột da nhưng lột chưa xong. Ba ngày sau hắn về sơn cốc tộc Âu Dương Hoa qua trận pháp dung hợp cấm phiên, vào cấm địa tọa định; Âu Dương Hoa cung kính cung đón thượng tiên, ra lệnh cấm vào sâu thung lũng và tuyên chiến mở rộng địa bàn. Vương Lâm tính ở lại giáo hóa cư dân, truyền thuật hồn phiên để gây dựng lực lượng riêng trước khi tới thành Cổ Yêu, nhắm khôi phục Tôn hồn phiên và đoạt Cổ yêu chi linh. Hắn lưu khẩu quyết Luyện Hồn, Trừu Phách cùng cách chế tác hồn phiên vào hai ngọc giản, cố ý cài một sơ hở trí mạng chỉ mình biết để có thể trực tiếp khống chế hồn phiên của đệ tử."},{"chuong":504,"tieuDe":"Yêu Lực Kết Tinh","tomTat":"Chế tác xong yêu giản, Vương Lâm thả thần thức bao quát thung lũng, thấy cư dân tư chất tốt và nhận định vùng đất yêu linh tuy không có linh lực nhưng có thể dùng yêu lực luyện hồn phiên. Hắn gọi trưởng lão Âu Dương Hoa, trao hai quả ngọc giản chứa khẩu quyết luyện hồn nhưng lão thử mãi không cảm nhận được. Quan sát thấy kinh mạch lão tắc nhiều chỗ, Vương Lâm dùng song chỉ điểm từ bụng lên mi tâm cưỡng ép đả thông, khiến lão đau ngất rồi tỉnh dậy đột phá nhị tinh, tự thấy như được hồi sinh và quỳ tạ thượng tiên. Vương Lâm tuyên bố truyền thụ thuật luyện hồn cho toàn cốc, điều cực hiếm nơi vùng yêu linh, khiến Âu Dương Hoa cảm kích thề khắc cốt và hành lễ như đệ tử. Ba tháng sau, toàn bộ đàn ông trong tộc đạt thành quả, riêng Âu Dương Hoa và một thanh niên thiên phú tiến bộ vượt bậc — thanh niên đã đạt giai đoạn ba, chuẩn bị chế tác hồn phiên. Cùng lúc Vương Lâm dung hợp hai khối yêu tinh thành ‘Ba giáp yêu tinh’ ẩn yêu lực vô biên, nuốt thử thì thân hóa yêu dị nhưng mới đạt Trúc Cơ kỳ vì lượng chưa đủ, rồi rút yêu lực về trở lại trạng thái siêu phàm."},{"chuong":505,"tieuDe":"Thập Tam","tomTat":"Tại sơn cốc ở Thiên Vận Tinh, Vương Lâm chế hồn phiên thay thế từ cươn thụ chi mộc, da dã thú và thủ ấn để bù tài liệu thiếu khuyết — thứ này chỉ phong ấn được không quá mười hồn phách và ẩn một sơ hở trí mạng chỉ hắn biết. Hắn khắc phương pháp lên ngọc giản rồi trao cho Thập Tam, thanh niên có ngộ tính trời sinh với Luyện Hồn Thuật mà hắn âm thầm theo dõi, khiến Thập Tam run rẩy quỳ lạy ba lạy. Âu Dương Hoa trình kế hoạch một tháng sau tấn công một bộ tộc vài chục người cách ngàn dặm, Vương Lâm chỉ đáp “Tùy ngươi!”. Sau ba lần thất bại, Thập Tam chế thành cây hồn phiên bảy thước đầu tiên và triệu hồn phách sư tử cánh dài; Âu Dương Hoa tuy chế xong trước đã cố ý nhường cơ hội cho hắn. Khi Thập Tam hô “Thu!”, sư tử quay đầu phản phệ lao vào hắn đầy sát khí, Âu Dương Hoa triệu chim sẻ chặn nhưng không kịp, Thập Tam bị giam cầm suýt chết. Vương Lâm một tiếng hừ “Nghiệt súc, ngươi dám!” khiến sư tử tan nát rồi thuần phục, lướt mấy trăm trượng hiện thân, để lộ rằng hắn đã cải biến Luyện Hồn Thuật cài backdoor khống chế mọi hồn thú do người học phong ấn."},{"chuong":506,"tieuDe":"Tán Hồn Dưỡng Phách","tomTat":"Vương Lâm khống chế con sư tử yêu thú hóa thành hắc mang nhập Hồn Phiên làm chủ hồn cho Thập Tam, đồng thời cảnh cáo Luyện Hồn Thuật không thể nhờ thủ thuật vì chủ hồn có thể cắn trả. Một tháng sau, Âu Dương Hoa và Thập Tam dẫn mười nam nhân đánh hạ bộ tộc trong động dưới lòng đất; Vương Lâm coi đây là thử thách và không can dự, nếu họ bại sẽ rời đi tới Cổ Yêu thành. Đội thắng trận trở về, trưởng lão đối phương bị nuốt và luyện hóa thành chủ hồn thứ hai của Thập Tam. Người ngoại tộc bị bắt uống yêu thang để xóa ký ức rồi nhồi danh tính mới, dần thành tộc nhân. Âu Dương Hoa dâng nhị giáp yêu tinh, Vương Lâm nuốt dung hợp thành ngũ giáp và ban khẩu quyết Luyện Hồn Thuật giai đoạn bốn, lập ra ba cách lập công để đổi khẩu quyết. Vương Lâm tính kế ‘tán hồn dưỡng phách’: để tộc nhân phong ấn hồn phách vào Hồn Phiên, đợi th��i cơ chín muồi khởi ý thu về nhằm hồi phục thập ức tôn Hồn Phiên. Bộ lạc bùng nổ tu hành, chuyển sang xâm lược, chia ba nhóm đồng thời đánh ba bộ lạc khác, một lực lượng âm thầm trưởng thành giữa cảnh chém giết kéo dài cả trăm năm."},{"chuong":507,"tieuDe":"Chiến Thư","tomTat":"Trong ba tổ đi đánh bộ lạc, hai tổ thắng trở về còn tổ Thập Tam mất tích; ba ngày sau chủ hồn sư tử có cánh mang Thập Tam toàn thân loang máu, ngực có yêu vật tơ hồng ký sinh, bay về thung lũng. Vương Lâm thu chủ hồn sư tử thành dấu ấn ngón tay, rút sợi tơ hồng đốt thành tro, cứu Thập Tam khỏi cơn nguy hiểm nhưng xác nhận hắn đã bị phế: kinh mạch nát, mất sạch yêu lực tam tinh, hồn phiên bị cướp. Qua lời Thập Tam, Vương Lâm hiểu lão già áo trắng (chấp sự dưới trướng Tả Dực tướng quân ở Cổ Yêu thành) đã cố ý dùng Thập Tam làm chiến thư sống để dụ hắn lộ diện và moi khẩu quyết cờ kỳ quái. Vương Lâm tới đồng bằng Thiên Thủy, không phá nổi trận pháp viễn cổ mười dặm nên dùng Khai Thiên phủ đào vòng quanh ven trận rồi nhổ cả mảnh đất mười dặm bay lên, mang về thung lũng để Hồn phiên (sáu chủ hồn phun lửa tím) luyện hóa bảy ngày bảy đêm. Hắn cân nhắc truyền thuật Cổ Thần cho Thập Tam nhưng từ bỏ vì rủi ro chết và không chắc Cổ Thần cắn nuốt được yêu lực; Thập Tam tỉnh dậy, dập đầu ba cái r��i đi, về phòng cố thổ nạp đến phun máu hôn mê. Lão áo trắng tự ra ngoài trận hạ chiến thư đòi đánh tay đôi, bị Vương Lâm bóp cổ giết “rắc”, nguyên thần giam vào cờ Tôn Hồn, xác bị đốt thành tro; lão áo xám sợ hãi mở trận pháp quy thuận. Vương Lâm thu nạp toàn bộ dân Thiên Thủy, dung hợp ba trận thành trận bảo vệ hai mươi dặm, Âu Dương Hoa đặt tên bộ lạc là Luyện Hồn với hơn năm trăm nam đinh; thung lũng cũ thành vùng cấm chỉ Vương Lâm ở. Hai năm hấp thu yêu lực từ vạn vật (cả bông tuyết), Vương Lâm nâng yêu tinh từ năm giáp lên ba mươi bốn giáp, tiên ngọc gần đủ Anh Biến hậu kỳ, mở ra con đường dùng yêu lực thay tiên ngọc; bộ lạc Luyện Hồn mỗi tháng đánh chiếm bộ lạc nhỏ thu tù binh và yêu tinh."},{"chuong":508,"tieuDe":"Chương 508","tomTat":"Vương Lâm mất ba ngày mở rộng trận pháp bộ lạc Luyện Hồn lên bốn mươi dặm, rồi dùng Tôn Hồn phiên hóa màn sương đen bao trùm tế dưỡng hồn phách cho toàn tộc, biến nơi đây thành dấu hiệu độc đáo. Âu Dương Hoa mang thợ săn Thập Tam bị dã thú yêu hóa làm trọng thương tới cầu cứu; Vương Lâm dò ra Thập Tam đã tự phát luyện thể nhờ tích yêu lực trong xương cốt máu thịt, gần đạt nhị tinh nhưng sẽ chết nếu tiếp tục mù quáng. Dùng Nguyên thần đọc trí nhớ và cảm động trước sự kiên trì hơn một năm của hắn, Vương Lâm cứu chữa và truyền Luyện Thể thuật của Cự Ma Tộc qua ngọc giản, hứa truyền khẩu quyết tầng một Cổ Thần nếu thành tựu. Qua bốn năm bộ lạc bành trướng tới gần ba trăm dặm với hơn năm nghìn nam đinh, thôn tính hầu hết mười vạn dặm; Thập Tam thành tựu thân cứng như sắt còn Hổ Bào trỗi dậy tới giai đoạn thứ năm ngang Kết Đan kỳ, được xem là thiên tài. Cuối cùng Vương Lâm luyện hai ngọc giản truyền âm làm đường lui, dẫn Thập Tam và Hổ Bào rời bộ lạc nhắm tới Cổ Yêu thành. Cách bộ lạc mười dặm, hắn triệu Văn Thú — con thú vàng tím mang Kim linh căn thực lực ngang Hóa Thần hậu kỳ đại viên mãn — làm tọa kỵ lên đường."},{"chuong":509,"tieuDe":"Chương 509","tomTat":"Vương Lâm thu phục yêu thú Văn Thú tỏa khí âm hàn, cưỡi nó chở Thập Tam và Hổ Bào vượt ba ngàn vạn dặm, bảy ngày tới Cổ Yêu thành trong Thiên Yêu quận, trên đường nảy ý dung hợp các bộ lạc Yêu linh chi địa cho bộ lạc Luyện Hồn của mình. Tại cửa Bắc, hắn không thu liễm tiên lực mà phá quy củ đi thẳng vào; Thập Tam dùng thuật Luyện thể Cự Ma Tộc đấm vỡ trường thương thị vệ và bị Vương Lâm quở vì chưa khống chế lực tùy tâm. Khi hơn mười yêu binh vây công, Vương Lâm tùy ý đánh một quyền vào không trung khiến cả đám đông cứng rồi bị đẩy bay thổ huyết, hút máu tạo quả cầu máu bắn vào tường thành. Diêu Nghiêu lĩnh — nữ tử áo trắng quen biết cũ — lao ra hóa giải cầu máu, từ chối giao chiến và dẫn hắn qua Truyền tống trận tới gặp Tả dực Yêu tương. Tả dực Yêu tương yêu lực gần Vấn Đỉnh đánh thử một quyền, Vương Lâm hóa giải bằng Tịch Diệt chỉ rồi từ chối chức Trưởng lão vì chỉ muốn chức ngoài có binh quyền. Yêu tương bèn ra Thập Băng Chiến Ý gồm mười quyền biến hóa chồng chất, hứa tiếp được sẽ ban chức Đô thống. Vương Lâm đứng vững như cây tùng, vận Sát lục tiên quyết kết hợp Hóa Ma chỉ nghịch hóa tiên lực thành ma khí mà đón đòn."},{"chuong":510,"tieuDe":"Chương 510","tomTat":"Chương mở đầu bằng lai lịch ba sát chiêu Tư Đồ Nam sáng tạo và truyền cho Vương Lâm — Tịch Diệt chỉ, Hóa Ma chỉ và Hoàng Tuyền chỉ; trong đó Hoàng Tuyền chỉ mạnh nhất, uy lực gần Tiên thuật cấp thấp nhưng dùng nhiều sẽ kéo đạo tâm nhập ma, Vương Lâm chỉ từng dùng một lần khi đánh Trần Đào. Tại Cổ Yêu thành, Vương Lâm giao chiến với Tả dực Yêu tương dưới thần công Thập Băng Quyền Ý gồm tám lần sụp đổ vô hình, càng về sau càng mạnh. Hắn lần lượt dùng Hóa Ma chỉ chống lần thứ nhất, Sát lục tiên quyết tạo rồng khí xám và lốc xoáy giết chóc cho lần thứ hai, rồi ngưng thành trường kiếm bảy thước khí xám chém vỡ lần thứ ba. Tả dực Yêu tương khen hắn là số ít người phản công được và thách phá đủ tám lần sụp đổ; Diêu Tích Tuyết đứng xa hồi tưởng ba năm trước nàng bại ở lần thứ tám và nhận chức Thống lĩnh. Đến lần sụp đổ thứ tư mạnh gấp ngàn lần khiến trường kiếm vỡ nát, Vương Lâm không muốn lộ Hoàng Tuyền chỉ ở Yêu linh nên thu khí xám lại, hiện hai đạo Sanh ấn phòng hộ trên mi tâm. Giữa đợt công kích, hắn cảm ngộ một niềm tin vô bờ bến ẩn trong quyền ý, ánh mắt sáng ngời như Chu Dật năm xưa lúc linh lực thiêu đốt ngộ ra."},{"chuong":511,"tieuDe":"Rời Đi","tomTat":"Khi chống chịu lần sụp đổ thứ tư của Thập Băng Quyền Ý, Vương Lâm cảm nhận được ‘niềm tin tất thắng’ mà Tả dực Yêu tướng tích lũy từ tâm niệm vô số kẻ bại trận, ngộ ra bản chất quyền ý chính là Thần thông Niềm tin và mấu chốt phá nó không nằm ở tu vi mà ở niềm tin. Bị đánh văng nghìn trượng, Sanh ấn ở mi tâm chỉ còn nửa đạo, hắn dung niềm tin vào Hóa Ma chỉ và lần đầu thi triển uy lực chân chính: tiên lực vô thanh hóa thành ma khí, tóc dài quá gối, ma văn xanh bạc hiện ở mi tâm, Sanh ấn phục hồi đầy đủ bao trùm toàn thân. Nhờ đó hắn phá liên tiếp lần sụp đổ thứ năm và thứ sáu, rồi chỉ bằng hai chữ ‘Nhường đường’ chứa niềm tin vô bờ mà phá tan lần thứ bảy. Hắn lĩnh ngộ thêm ‘Ma niệm’ — nghịch thiên tùy ý, phá hư đạo pháp, tự đi con đường riêng. Tả dực Yêu tướng rốt cục biến sắc, thừa nhận đã xem thường đối phương và lần đầu xúc động sau mấy ngàn năm, gọi Vương Lâm là người đầu tiên cảm ngộ được dưới quyền ý này. Diêu Tích Tuyết đứng quan sát ở xa cũng kinh ngạc, nhớ lại lời phụ thân Huyết Tổ rằng người có chú ý đến Vương Lâm."},{"chuong":512,"tieuDe":"Khảo Nghiệm Của Yêu Tương","tomTat":"Ở trạng thái nhập ma với ma khí xông trời, Vương Lâm vượt qua bảy lần ‘sụp đổ’ của Thập Băng Quyền do Tả Dực Yêu tương thi triển, đối kháng được lần thứ tám hóa dạng nước lũ; khi lần thứ chín im lìm áp tới, hắn quyết đoán lùi ra nghìn trượng để bảo toàn đạo tâm thay vì liều đánh. Tả Dực Yêu tương khen hắn biết tiến biết lùi, xưng danh đầy đủ là Vân Lệ Hải, phong Vương Lâm làm Thống lĩnh Cổ Yêu thành nắm một vạn yêu binh và trao một lệnh bài đồng; Diêu Tích Tuyết định nói gì đó nhưng bị hắn phớt lờ. Vào trung tâm thành, Vương Lâm khoanh chân thổ nạp bốn ngày để khôi phục đạo tâm, nén ma niệm thành một điểm phong ấn giữ làm uy lực thay vì loại bỏ, đồng thời làm rõ động cơ nhập ma là lĩnh ngộ Niềm tin và đoạt chức vị bên ngoài. Thập Tam và Hổ Bào hội hợp, cùng hắn dạo Cổ Yêu thành; Vương Lâm ngờ cả vùng Yêu linh Đông Hải là động phủ một vị tiên đế, cư dân như gia súc trong ‘hàng rào tre’. Tại quán Trúc Thanh lâu có vò rượu khổng lồ, hắn uống rượu Trúc Thanh và hoài niệm loại rượu duy nhất từng uống thời phàm nhân ở Chu Tước Tinh do Đại Ngưu để lại, băn khoăn không biết Đại Ngưu và con cháu nay còn bình an."},{"chuong":513,"tieuDe":"Ngộ Trong Chiến Đấu","tomTat":"Vương Lâm uống rượu cùng Thập Tam và Hổ Bào, chìm trong hồi ức hơn mười năm sống đời phàm nhân và nhớ Đại Ngưu cùng Chu Tước tinh, sinh niềm xúc động mãnh liệt muốn rời Yêu Linh chi địa và Thiên Vận tinh để trở về cố hương. Sự xúc động kéo dài bất thường khiến tâm ma bị áp chế lớn mạnh, chén rượu vỡ cắm vào tay mà hắn không hay. Bảy tám yêu binh hắc giáp do một thống lĩnh nét mặt âm trầm dẫn đầu xông vào tửu lâu gây sự; hắn vốn là Nghiêu Lĩnh chính bị một người ngoài đến chiếm chỗ nên bất mãn, ném hai vò rượu dò xét rồi tấn công bàn Vương Lâm, định dùng Tru Tiên trận. Thập Tam giơ tay bắt vò rượu thứ hai bị thương, sau đó tung một quyền đánh trọng thương một yêu binh dù Luyện Thể thuật chưa đầy đủ. Hổ Bào lấy mười lá cờ nhỏ rồi phất Hồn phiên thả vô số hồn phách, nhưng sáu yêu binh dùng Yêu lực phá thần bức lui, hai thuộc hạ quyết tử bảo vệ lão tổ. Thống lĩnh chợt biến sắc hô thu hồi yêu lực nhưng đã muộn, sáu đạo yêu lực mất khống chế bay thẳng vào mi tâm Vương Lâm. Ma niệm hút trọn khiến hắn bừng tỉnh khỏi hồi ức, ánh mắt trở lại trong sáng, thở dài thốt rằng ma niệm lợi hại thật, trong mắt hiện chút kinh hãi."},{"chuong":514,"tieuDe":"Ma Niệm","tomTat":"Sau cơn đắm chìm vào hồi ức tại tửu lâu, Vương Lâm nhận ra tình cảnh vừa rồi chẳng khác kiếp nạn vì trong người vẫn còn chút ma niệm di chứng từ lần nhập ma trước, chính nó lôi ký ức Chu Tước tinh ra khiến tinh thần mất kiểm soát; chương cũng luận giải hai quan điểm về thiên ma ngoại vực giữa tu sĩ thượng cổ và tu chân liên minh. Nhân lúc yêu lực sáu yêu binh tung hoành, hắn tìm được đường đột phá trong nghịch cảnh, dung hợp yêu lực vào tiên lực rồi cắn nuốt toàn bộ sáu luồng yêu lực, thần trí lập tức khôi phục. Khi rời tửu lâu, một nam tử âm trầm tán phát yêu lực ngưng thành trường kiếm tấn công nhưng bị Vương Lâm vung tay tạo gió hóa giải, để lại lời sẽ còn gặp lại. Về khách sạn, hắn vận tiên lực dò khắp cơ thể suốt hai ngày, khu trừ sạch ma niệm kết thành ba quả cầu đen và thu vào túi trữ vật làm thủ đoạn về sau. Hết hạn bảy ngày, quản sự tham quân dưới trướng Yêu Tương tới kiểm tra lệnh bài đồng rồi vẽ Truyền Tống trận bằng máu do Yêu đế tạo để đưa đi. Tới quân doanh, ba người chịu sóng âm chấn động khiến Thập Tam phun máu và Hổ Bào loạn yêu lực, đều được Vương Lâm truyền lực cứu chữa; cuối cùng hắn đứng giữa hơn vạn yêu binh giáp đen đầy sát khí mà vẫn hết sức bình thản, ��áp lại bằng ánh mắt lạnh lẽo."},{"chuong":515,"tieuDe":"Thống Lĩnh","tomTat":"Vương Lâm vừa từ pháp trận bước ra, một vạn yêu binh Hắc Giáp quân mặc giáp đen đồng loạt hét vang đầy sát khí; Quản sự tham quân giới thiệu hắn là tân thống lĩnh và Tư Mã Viêm là phó thống lĩnh. Tư Mã Viêm cưỡi cự thú một sừng tới, tháo mũ để lộ khuôn mặt âm trầm chính là người từng gặp ở tửu lâu, xưng ra mắt thống lĩnh, còn Vương Lâm chỉ bình thản đáp lại. Quản sự tham quân cáo từ về phục mệnh Yêu Tương đại nhân rồi vào trận pháp biến mất. Khi Vương Lâm lệnh toàn quân lui ra, không một yêu binh nào động đậy cho tới khi Tư Mã Viêm lên tiếng, chúng cười khinh miệt sau lưng ba người. Không có chỗ ở, Vương Lâm cùng Thập Tam và Hổ Bào ngồi thổ nạp ngoài bãi đất trống suốt ba ngày, dùng thần thức quan sát toàn quân và nắm rõ cơ cấu mười Thống đội. Dựa vào ghi chép tổ tiên do La Vân đưa, hắn hiểu rõ quy tắc Cửu quận yêu binh cùng quy định mười người không nghe hiệu lệnh nên ẩn nhẫn chờ thời cơ chỉnh đốn như thợ săn rình mồi. Tư Mã Viêm ngày càng khiếp sợ vì không nhìn thấu vị tân thống lĩnh, bèn triệu tập các thống đội bàn về Vương Lâm và được báo hai người Từ U, Chu Khải vắng mặt."},{"chuong":516,"tieuDe":"Yêu Binh","tomTat":"Trong quân doanh Thiên Yêu quận, các thống đội của Tư Mã Viêm bàn về thống lĩnh mới Vương Lâm; một lão già giáp đen cho rằng kẻ ngồi im nửa tháng không mất bình tĩnh ắt tâm cơ thâm trầm, còn Tư Mã Viêm chốt sách chờ Vương Lâm chủ động ra tay rồi mới đối phó. Vương Lâm ẩn nhẫn thổ nạp nửa tháng, mặc kệ hơn vạn yêu binh khinh miệt, cho tới khi Tôn thống đội nhổ nước bọt gọi hắn là phế vật. Vương Lâm giơ tay trói kéo Tôn thống đội lại, sai Thập Tam đọc điều thứ tám quân quy rồi bóp nát cổ, phá tu vi và hút yêu khí từ thất khiếu xác chết. Khi nửa ngàn yêu binh lao tới báo thù, hắn lấy kiếm tiên và loan đao chém giết dễ dàng, rồi duỗi tay hấp thu yêu lực mấy trăm xác chết tạo thành lốc yêu lực quanh thân. Chín thống đội cùng chín ngàn yêu binh kéo tới vây trận, Hổ Báo xuất hồn phiên còn Thập Tam đứng cạnh, nhưng Vương Lâm vẫn ngồi khoanh chân. Tư Mã Viêm phóng tới chất vấn việc giết Tôn thống đội và trảm yêu binh, liền bị Vương Lâm sai Thập Tam viện dẫn điều mười ba và điều hai quân quy ép cả đám phải lùi và giải tán trong số nhịp hô hấp quy định. Tư Mã Viêm hiểu ra Vương Lâm ngồi im cả tháng chính là để chờ cơ hội này, ba thống đội né tránh tranh giành, còn Thập Tam bắt đầu đếm ngược nhịp hô hấp."},{"chuong":517,"tieuDe":"Doanh Trại Hắc Giáp Quân","tomTat":"Tư Mã Viêm hạ lệnh chín ngàn yêu binh tản ra phá thế bao vây, thì quản sự tham quân gầy gò cùng một lão già áo vải bố tóc bạc theo luồng sáng đỏ như máu hiện thân thị uy; chỉ một cái liếc mắt của Vương Lâm khiến một trong bốn phong ấn trong thân lão già suýt vỡ. Vương Lâm ném ngọc giản lưu hình ảnh chứng minh thống lĩnh giết người vô cớ, quản sự xem xong bỏ ý truy cứu, sinh lòng kết giao và hứa bẩm báo Yêu Tương đại nhân, khiến Tư Mã Viêm cùng đám thống đội buộc phải nhận lỗi thỏa hiệp. Vương Lâm nhấn tay dựng lên một ngôi lầu hai tầng bằng bùn đất, chấn nhiếp toàn doanh và lập uy danh; sau mấy tháng thổ nạp luyện hóa yêu lực dung nhập tiên lực, hắn tiến tới Anh Biến hậu kỳ, còn Hổ Bào hòa nhập quân doanh và rung động với nữ thống đội Từ U. Ở quân doanh thứ ba, đêm trăng tím nửa-năm-một-lần, Diêu Tích Tuyết dùng la bàn đỏ, cây đèn trắng và giọt máu lam thi triển pháp thuật xông vào vực sâu nơi thủy triều theo kế hoạch của phụ thân. Lần thứ tư nàng vẫn thất bại, nhờ Huyết Hồn đan mới tái sinh trở về, đã phá được hơn một nửa; nàng nghĩ nếu có người giúp nhất định thành công và gọi tên Vương Lâm."},{"chuong":518,"tieuDe":"Sự Im Lặng Đáng Sợ","tomTat":"Trong Cổ Yêu thành, Diêu Tích Tuyết tính toán nhân lực và kết luận chỉ Vương Lâm đủ tu vi tiếp được Thất Băng quyền của Yêu Tương để nhờ cậy, bèn truyền âm hẹn hắn lúc canh ba ở cổ sơn cách quân doanh ngàn dặm. Vương Lâm khi đó đang khổ tu trong Hắc Giáp quân, sau khi hấp thu yêu lực năm trăm yêu binh và Tôn thống đội thì yêu tinh trong người đạt gần ngàn giáp, nên hắn phớt lờ lời hẹn để dồn sức đột phá Anh Biến hậu kỳ. Đợi tới bình minh không thấy hắn, Diêu Tích Tuyết nổi giận hóa tia sáng trắng xông thẳng vào quân doanh, khống chế Thập Tam bằng tia sáng đỏ và phong tỏa chín ngàn yêu binh. Vương Lâm dùng một cơn gió giải trừ khống chế trên Thập Tam rồi tiếp chuyện nàng trong lầu tối, cảnh cáo nếu không có việc khiến hắn động tâm thì chớ trách. Diêu Tích Tuyết cầu hắn cùng phá một trận pháp cấm chế mười tám phong ấn mà nàng chỉ phá được tới cái thứ mười một, hứa cung cấp toàn bộ tiên ngọc đủ để hắn đạt Vấn Đỉnh sơ kỳ. Nội tâm nàng giấu việc phá trận mang tính sinh tử — đã thất bại bốn lần, chết bốn lần và hao bốn viên Huyết Hồn đan trong mười ba viên phụ thân luyện. Vương Lâm dao động mạnh trước mồi tiên ngọc nhưng nghi nàng che giấu nhiều chuyện, không đồng ý ngay mà hẹn sau bốn tháng sẽ cho câu trả lời thuyết phục."},{"chuong":519,"tieuDe":"Lập Uy","tomTat":"Diêu Tích Tuyết trình bày yêu cầu nhờ Vương Lâm giúp bài trừ phong ấn cấm chế bí mật trên người nàng, thứ phải đợi tới Vấn Đỉnh kỳ mới tự giải được. Tin chắc thực lực hắn sau trận đánh với Yêu Tương, nàng đưa thù lao hậu hĩnh nhưng Vương Lâm liên tục trì hoãn để nâng giá khiến nàng nổi giận. Cuối cùng nàng giao cây đèn Huyết Hồn đan — đồn rằng giúp sống lại một lần dù nguyên thần bị diệt — ném thêm túi tiên ngọc đủ tu tới Anh Biến hậu kỳ cùng lời hứa lệnh bài Huyết Phù, hẹn ba ngày sau canh ba lên cổ sơn. Sinh nghi vì sự hào phóng khác thường, Vương Lâm triệu hồn phách Tào Nhất Đấu ra giám định. Tào Nhất Đấu xác nhận đèn đúng là Huyết Hồn đan với 3614 ký tự phù văn, một trong ba bảo vật Thiên Vận tinh của Huyết Tổ. Tuy nhiên cả hai đoán ra đây thực chất là phế đan chứa độc tố, do Huyết Tổ cố ý tung ra lẫn lộn để bảo vệ bảo vật thật khỏi bị cướp đoạt."},{"chuong":520,"tieuDe":"Diêu Tích Tuyết","tomTat":"Từ việc Tào Nhất Đấu thân phận thấp không biết phân biệt Huyết Hồn đan, cộng thái độ hào hiệp của Diêu Tích Tuyết, Vương Lâm suy ra mọi việc là mưu kế của Huyết Tổ và xác định viên Huyết Hồn đan nàng đưa là đan giả khiến người dùng tử vong; hắn không vạch trần mà lặng lẽ cất cây đèn vào túi trữ vật. Thu túi trữ vật chứa đủ tiên ngọc để tu tới Anh Biến hậu kỳ, hắn chìm xuống lòng đất ba ngày, dựa kết cấu yêu tinh học ở bộ lạc Luyện Hồn cô đọng tiên lực thành ‘Tiên tinh’. Đúng hẹn dưới trăng tím trên cổ sơn ngoài quân doanh ngàn dặm, Diêu Tích Tuyết xuất bảy pho tượng đỏ, cắn lưỡi vẽ ký tự máu dựng trận ẩn thân khiến thần thức không soi thấy chính mình, nói cả Yêu Tương cũng không phát hiện. Nàng dùng la bàn đỏ canh yêu khí cực điểm, dẫn hắn vượt truyền tống trận do Huyết Tổ bố trí, hứa trao lệnh bài Huyết Phủ và tiên ngọc khi trở về. Hai người tới một không gian như tinh không chỉ toàn ánh sáng, có bình đài trăm trượng đặt trận pháp cùng quỹ tích với trận bảy pho tượng. Vương Lâm nhận ra con đường uốn lượn trước mặt là thân giao long Tôn Long do thần thông bố trí, không có trong ký ức Cổ Thần Đồ Ti; vừa khoanh chân chuẩn bị cảm ngộ ý cảnh tạo ấn ký thì trong đầu chợt nảy một ý nghĩ."},{"chuong":521,"tieuDe":"Giao Dịch","tomTat":"Trong Yêu Linh chi địa, Vương Lâm phỏng đoán nơi này do một vị Tiên đế bố trí, ngồi tĩnh tâm cảm ngộ ý cảnh Sinh Tử luân hồi (tay trái sinh, tay phải tử, giữa là thời gian bất biến) mà vẫn phân một niệm cảnh giác Diêu Tích Tuyết. Một lực lượng thần bí từ trời giáng xuống ngưng tụ vào mi tâm Diêu Tích Tuyết, để lại kim phù ấn ba nét tỏa uy nghiêm như vô thượng tiên tôn. Khi lực lượng ấy vờn quanh Vương Lâm, hắn dùng ấn ký Sát Lục chi đạo cùng Sinh ấn, chọn nghe thanh âm thay vì nhìn ảnh, nắm bắt được tiếng tự xưng “Ta là Thanh Sương” và đắc kim phù ấn sáu nét phức tạp hơn. Kim phù sáu nét của hắn lấn át kim phù ba nét của Diêu Tích Tuyết khiến nàng khó chịu, vô thức tránh ánh mắt rồi dẫn hắn lên con đường Tôn Long lắc lư trong hư không. Đi cực nhanh ba ngày mới được một phần ba đường, hai người tới bình đài phong ấn đầu tiên với pho tượng đá cao ba trượng. Diêu Tích Tuyết kích hoạt tượng (uy lực ngang Anh Biến sơ kỳ) rồi ném ngọc phù màu máu hô “Phong!” phong ấn dễ dàng, hẹn Vương Lâm phá giải tầng thứ hai, khiến hắn hiểu thêm về thực lực của nàng."},{"chuong":522,"tieuDe":"Huyết Hồn Đan","tomTat":"Vương Lâm thầm đoán cái ngọc phù đỏ như máu của Diêu Tích Tuyết do phụ thân nàng — Huyết Tổ — luyện chế, rồi dùng Sinh ấn ngưng vào hai mắt nhìn xuyên áo đỏ, phát hiện trong tượng đá ẩn một ký hiệu chỉ có một nét. Hắn suy ra ký tự một nét là thứ cơ bản chung của ký tự ba nét (Diêu Tích Tuyết) và sáu nét (chính hắn), đồng thời nhận định nàng có Huyết Hồn đan nên dù bị đánh lén cũng sống lại, rất khó giết. Sau bảy ngày hai người tới bình đài thứ ba có tượng đá thêm con mắt thứ ba; Diêu Tích Tuyết nhường hắn thử trước. Tượng thức tỉnh đuổi giết, Vương Lâm chống đỡ bằng Sinh ấn và Cấm phiên (đã tích 999 đạo cấm chế), dần nhìn thấu tượng vốn chỉ là một đống cấm chế chồng lớp. Hắn hấp thu rừng cột đá nhọn vào Cấm phiên, phun máu triệt tiêu ánh sáng vàng từ con mắt thứ ba và hét phá vỡ tượng. Cuối cùng hắn vẽ ký tự hai nét bằng tiên lực, hút lấy ký tự vàng dung hợp vào nét vẽ của mình."},{"chuong":523,"tieuDe":"Tiên Tinh","tomTat":"Trên đài phong ấn đường Tôn Long, Vương Lâm vẽ thành công ba nét phù văn, kim quang phát ra ẩn chứa ấn ký thiên đạo và buộc Diêu Tích Tuyết phải dùng huyết ngọc trăm năm hóa giải. Hai người vượt các tầng phong ấn tới đài thứ mười hai — một cửa đá hình mặt người — nơi Động Phủ Chi Linh hiện ra, đòi qua được ba đạo kiếm khí mới được vào động phủ tiên nhân, bằng không cả hai phải chết. Vương Lâm tự xưng chỉ Anh Biến trung kỳ, cố ý trúng đạo kiếm khí thứ nhất rồi chấn nát tiên tinh giấu trong người để bùng tiên lực, diễn cảnh trọng thương văng vào hư vô đánh lừa Diêu Tích Tuyết. Nàng gắng tiếp hai đạo kiếm khí còn lại đến cạn tiên lực, ngồi xuống vận công đối kháng. Đúng lúc nàng lơ là, Vương Lâm đội mũ rơm Vân Tước Tử che thần thức bay lên, điểm mi tâm phong ấn nàng giữa sự sống và cái chết, làm đứt kinh mạch và vô hiệu Huyết Hồn Đan. Hắn vạch rõ toàn bộ mưu kế, đoạt bốn túi trữ vật giấu trên người nàng, liên hệ cảnh hài cốt thiếu nữ bị phong ấn từng thấy trên Chu Tước Tinh năm xưa. Cuối chương, hắn không giết mà giam Diêu Tích Tuyết trong trạng thái không thể chết rồi đề nghị một cuộc giao dịch."},{"chuong":524,"tieuDe":"Sáu Nét Kim Phù","tomTat":"Vương Lâm đề nghị giảm năm mươi năm trong năm trăm năm phong ấn để đổi một câu trả lời từ Diêu Tích Tuyết, cảnh báo nếu nàng nói dối thì sau này y sẽ không tới mở phong ấn; nàng chỉ đáp muốn vào động phủ không có nguyên nhân nên bị y bủa cấm chế nhốt vào quả cầu hắc quang cất vào túi trữ vật. Vấn đáp với Động Phủ Chi Linh hiện hình người đàn ông trung niên dưới cửa đá, y biết được hai người đủ tư cách vào vì cùng tiếp ba đạo kiếm khí, rằng ký hiệu vàng trên mười một đài là Hộ Phủ Thần Thông, mở một phong ấn sẽ thu quyền hạn nhưng động phủ tự đóng, người vào trước đều đã chết, muốn rời đi phải mở một đạo thảo ấn. Vào trong, y phát hiện toàn động phủ dựng bằng Tiên Ngọc phủ tiên cấm tiên giới nên không thể đào, lò luyện đan đã bị vét sạch, và đọc ra dấu vết ba tiền nhân: một người dùng Mai Hoa Thập Bát Cấm vào đầu chỉ lấy vật quý, hai kẻ sau cưỡng ép phá lấy đồ. Theo hành lang tiên ngọc rẽ phải qua rừng trúc, y tìm thấy một khu vườn còn nguyên vẹn cấm chế là trung tâm của mọi cấm chế nên tiền nhân mạnh nhất cũng phải rút lui. Vương Lâm thôi diễn hai tháng, liên tục dẫn phát thử từ ba nghìn lên hơn vạn biến hóa, khi chín trăm chín mươi chín tổ cấm chế trên cấm phiên hoàn thành thì phá vỡ bình cảnh, độ nắm chắc tăng từ bốn lên năm phần. Y men theo đường sinh tiến vào, tới cách bàn đá ba bốn trượng thì trận pháp đột nhiên xoay ngược đổi phương hướng vận chuyển, nổ cơn lốc đen sấm chớp như Du Long đặt y vào thế hiểm nghèo."},{"chuong":525,"tieuDe":"Ba Ký Tự Hợp Làm Một","tomTat":"Sau mười lần hít thở, cơn lốc và tia chớp đen tan biến, Vương Lâm tiến vào bàn đá và kích hoạt chùm sáng cao vạn trượng mở ra động phủ với giả sơn, cỏ xanh, rừng trúc nối liền bốn phía. Một âm thanh từ hư vô trao cho hắn tư cách sở hữu động phủ cùng Động Phủ Lệnh bằng thủy tinh phát sáng bảy màu. Hắn phá cấm chế trên bầu rượu bằng kỹ thuật con sóng và vòng nước xoáy, đoạt được bầu rượu chứa khoảng mười giọt mỹ tửu. Uống một giọt, toàn thân đỏ bừng, tiên lực điên cuồng lưu chuyển và cơn say đẩy hắn vào giấc ngủ say suốt một năm. Trong giấc ngủ tiên lực tăng trưởng kinh người, Yêu Tinh trong đan điền vỡ tan hòa vào tiên lực; tỉnh dậy hắn kinh hoàng nhận ra tu vi đã vượt xa Anh Biến hậu kỳ đại viên mãn, chỉ chờ ý cảnh là đủ sức trùng kích Vấn Đỉnh. Hắn phong ấn cất kỹ bầu rượu, lo lắng không biết đã ngủ bao lâu, rồi dùng lệnh bài rời khỏi động phủ và dự định quay lại khai thác kho bí mật cùng căn từ đường chưa khám phá trong rừng trúc."},{"chuong":526,"tieuDe":"Xoay Chuyển Càn Khôn","tomTat":"Sau khi đột phá Anh Biến hậu kỳ đại viên mãn trong động phủ Huyết Tổ, Vương Lâm cầm tiểu lệnh thủy tinh hóa tàn ảnh bay về theo đường Tôn Long, chỉ nửa tháng tới cái đài đầu tiên có trận truyền tống do Huyết Tổ lưu lại. Hắn mở ba trong bốn túi trữ vật cướp của Diêu Tích Tuyết, thu được tiên ngọc khổng lồ, hơn ngàn Ngọc phù huyết sắc, Huyết Hồn Đan cùng một la bàn huyết sắc, nhưng phát hiện đạo tử tuyến nghi cạm bẫy thần thức Huyết Tổ trên túi thứ tư nên không dám mở. Hắn xóa thần thức Diêu Tích Tuyết trong la bàn, lưu thần thức mình, rồi dùng ba ngày hiệu chỉnh trận cùng ba mươi ngày bố trí cấm chế biến trận truyền tống thành cạm bẫy cuốn người ngoài vào khe không gian. Kích hoạt la bàn, Vương Lâm truyền tống về một ngọn núi cổ ngoài Cổ Yêu Thành và nhận ra mình mới chỉ mất tích một năm. Hắn phá tan màn sương đen phòng hộ rồi tiến vào quân doanh Hắc Giáp quân, nơi Đô Thống cùng mười vạn Yêu binh và bốn thống lĩnh chờ sẵn, Tư Mã Viêm cung kính bên cạnh. Một tiếng quát Lui ra ẩn tiên lực Anh Biến hậu kỳ đại viên mãn đã chấn nhiếp khiến ba thống lĩnh tái mặt dừng lại; Đô Thống báo hắn đã bị Yêu Tướng bãi miễn chức rồi hóa thân Huyền Vũ trăm trượng chống cự. Vương Lâm thi triển Tịch Diệt Chỉ uy lực tăng vọt, hút cả huyết nhục yêu lực vài yêu binh khiến thiên địa biến sắc, quân doanh tối sầm."},{"chuong":527,"tieuDe":"Khu Vườn","tomTat":"Tại vùng đất Yêu Linh, người đàn ông vạm vỡ áo giáp đen dung nhập vào bóng Huyền Vũ biến ảo để chiến đấu, nhưng bị Vương Lâm dùng Tịch Diệt Chỉ ấn một cái phá tan Huyền Vũ từng đốt, áo giáp vỡ vụn, phun tiên huyết quỳ gối; Vương Lâm lúc này ở Anh Biến đại viên mãn, gần tiếp cận Vấn Đỉnh. Hắn chộp Tư Mã Viêm tới hỏi tung tích hai tùy tùng, rồi thi triển Sưu hồn thuật đọc ra việc Hổ Bào bị phế tu vi ném hắc lao rồi mất tích bí ẩn, còn Thập Tam bị bóp nát gân cốt và được Đô thống mang đi. Phẫn nộ, Vương Lâm vận Sát Lục Tiên quyết giết Tư Mã Viêm, luyện hóa toàn thân công phu hắn thành tia khí xám tụ ở tay phải. Đại hán áo giáp đen lộ tên là Tần Lâm, khai từng theo lệnh Yêu Tướng tìm người cường độ thân thể cao nên chữa thương cho Thập Tam rồi dâng tặng; hắn được Vương Lâm tha vì có công có tội. Tần Lâm tiết lộ Yêu Tướng bế quan nửa năm, mọi truyền tống trận đều bị phong kín từ bên trong, muốn vào chỉ có thể xông thẳng qua sáu cửa, rồi ôm ngực rút lui chữa thương. Vương Lâm tự nhận mình không hợp làm người tu đạo, chỉ cầu không thẹn lương tâm, quyết cứu Thập Tam dù tương đương chống lại cả Thiên Yêu Quận. Hắn hiện thân trước cửa thứ sáu canh phòng cẩn mật, thở sâu rồi thả tiên kiếm chứa Hứa Lập Quốc bay ra giữa tiếng gầm rú liên tục, chuẩn bị phá cửa."},{"chuong":528,"tieuDe":"Ngủ Say","tomTat":"Vương Lâm đơn thân xông vào cung điện Yêu Tướng, dùng tiên kiếm và gió lốc phá vỡ cửa thứ sáu rồi cửa thứ năm, đè bẹp mấy ngàn yêu binh và thả ba vỏ kiếm vô danh Chu Tước Tinh cùng Cấm Phiên chống lại luồng yêu khí của hơn mười vạn yêu binh. Cầu kiến Yêu Tướng hơn tuần hương không được hồi đáp, hắn thi triển Tịch Diệt Chỉ hút sạch huyết nhục yêu binh trăm dặm rồi phá cửa thứ tư. Lão già đầu bạc từng quản lý quân doanh Hắc Giáp hóa mãng xà yêu lực đánh lén, kinh ngạc trước sức mạnh vượt bậc của Vương Lâm, cuối cùng bỏ mạng khi con mãng xà va vào huyết long do Hóa Ma Chỉ tạo ra ở cửa thứ ba. Sau cửa ba, năm lão già tu vi ngang Anh Biến hậu kỳ bị Hoàng Tuyền Chỉ — sát chiêu chân chính do Tư Đồ Nam truyền — đẩy lùi phun huyết, khiến cửa thứ hai sụp đổ. Đệ nhất Đô Thống dáng thấp bé dùng quả cầu trắng tia chớp đen chặn Hoàng Tuyền Chỉ cách ba tấc nhưng bị đẩy lùi xô sập cửa thứ nhất, phun huyết bắn ra xa. Một người cao lớn bước ra tung Thập Băng Quyền ý nghênh chiến, vụ va chạm tạo sóng chấn lan mười dặm hủy lầu các và hóa tro yêu binh, đẩy Vương Lâm lùi hơn ba trượng. Suốt quá trình, Yêu Tướng vẫn bế quan không hề ra mặt, đúng như tiêu đề Ngủ Say."},{"chuong":529,"tieuDe":"Thu Hoạch","tomTat":"Vương Lâm dùng Sát Lục Tiên quyết luyện hóa khí xám thành bốn-năm luồng sát lục chi khí, đối đầu tuyệt chiêu Yêu Hải Bách Lãng của Yêu Tướng. Khi cấm chế và Huyết sắc Ngọc phù đều bị sóng yêu khí phá vỡ, Vương Lâm dùng phù văn màu vàng từ tượng đá thứ hai vẽ ba nét phù văn thần thông bắn khí xám xuyên Yêu Hải, rồi tạo một chưởng ấn hư ảo mang khí thế hủy thiên diệt địa. Chưởng ấn thực ra vô lực nhưng buộc đối phương không dám đánh cuộc mạng sống. Yêu Tướng lộ tên thật Mạc Lệ Hải, khai luyện pháp bảo cần thân thể mười tám người, phong Vương Lâm làm Tả dực đệ nhất phó tướng, hẹn so đấu tại Thiên Yêu thành ba tháng sau và thả Thập Tam. Sau khi Vương Lâm rời đi, năm lão giả bàn luận, Mạc Lệ Hải thừa nhận chưởng kia chín phần mười là giả nhưng không dám liều, đồng thời nhắc bí ẩn tu vi Vương Lâm tăng vọt. Vương Lâm tìm Hổ Bào khắp Cổ Yêu thành và hắc lao nhưng không thấy dấu vết linh hồn, rồi về bộ lạc Luyện Hồn được toàn tộc và Âu Dương Hoa quỳ nghênh lão tổ. Ba ngày sau hắn đánh thức Thập Tam, hồi tưởng chiến lợi phẩm từ Cự Ma Tộc lão tổ gồm bình máu Cổ Thần, một tia nguyên thần Pháp Cổn Luân và một ngọc giản."},{"chuong":530,"tieuDe":"Thực Lực Của Anh Biến Kỳ Đại Viên Mãn","tomTat":"Trong Luyện Hồn cốc, Vương Lâm ghi nhớ trọn chín tầng công pháp luyện thể Cự Linh Cửu Tu trong ngọc giản, xóa ba tầng cuối rồi chép sáu tầng đầu vào một ngọc giản xanh ném cho Thập Tam; Thập Tam quỳ đập đầu thề trung thành, tôn hắn làm Lão tổ và được dặn bảo vệ bộ tộc Luyện Hồn trước khi bị gió cuốn ra ngoài cốc. Vương Lâm ngồi dưỡng hồn dưới hắc vụ do Tôn Hồn Phiên hóa thành, lo ba tháng sau phải tới kinh thành Thiên Yêu quận nên không thể mang Tôn Hồn Phiên đi xa. Ở chiến trường cổ phía Tây trong lãnh thổ Yêu Linh, một thanh niên dùng hơn trăm tiểu kỳ đen đánh thức và thu hút linh hồn ngủ say, dưới sự giám sát của một lão già hắc y. Thanh niên xưng là Hổ Bào, vốn là thuộc hạ cũ của Vương Lâm; hắn kể vì Vương Lâm mà bị Tư Mã Viêm ném vào hắc lao, chờ cứu vô vọng nên ôm hận, nay thề báo thù cả Vương Lâm lẫn Tư Mã Viêm. Lão già hắc y cho biết chỉ cứu Hổ Bào vì hắn có Luyện Hồn Thuật kỳ dị, đã truyền cho hắn Diệt Thế Áp Nguyên Công rồi hóa khói biến mất. Sau đó lão vào hắc tháp mười tầng, quỳ trước bộ áo giáp cổ của chủ nhân, báo tin Yêu Đế Thiên Yêu quận ngàn năm trước bị ngừng ở bước đột phá cuối và nhận tin tức từ u quang trong giáp. Lão lên kế hoạch dùng Luyện Hồn Thuật cùng công pháp, đan dược và khẩu quyết của chủ nhân để biến Hổ Bào thành Yêu Vệ làm thí nghiệm, dự định sẽ tới bộ tộc Luyện Hồn thăm dò nếu thành công."},{"chuong":531,"tieuDe":"Cứu Thập Tam","tomTat":"Trong sơn cốc bộ lạc Luyện Hồn, Vương Lâm thả cấm chế bao bọc Diêu Tích Tuyết — đang bị Sinh Chi Lạc Ấn bơm sinh cơ vĩnh viễn không cho chết — đề nghị giảm phong ấn 50 năm đổi một câu trả lời nhưng bị nàng mắng chửi, dọa sẽ để phụ thân Huyết Tổ trả thù. Hắn lôi ra cây châm đỏ do tia tinh khí nguyên thần cuối cùng của nàng hóa thành giấu trong miệng định chặn sinh cơ tự sát, rồi phá luôn tâm cảnh hận nhập đạo bằng cách chấn nát quần áo và kích thích tuần hoàn cấm chế, cuối cùng thu nàng thành quả cầu cấm chế cất vào túi trữ vật, tiếc rằng tu vi chưa tới Vấn Đỉnh nên chưa dùng được Sưu Hồn Thuật. Hai tháng sau, sát hẹn ước với Yêu tướng, Vương Lâm dặn Âu Dương Hoa phái mấy trăm tộc nhân tiềm nhập các bộ lạc lớn nhỏ — dùng Hồn Phách Thủ Thần chống lại Linh Thang Loạn Thần — để truyền Luyện Hồn Thuật, đặt mục tiêu hơn trăm vạn tộc nhân; trao ngọc giản phần hai (thần thông rút phách) chỉ cho chi chính. Hắn thu Tôn Hồn Phiên vào nguyên thần, ném nhiều Hồn Phiên thường thay thế phủ kín bầu trời rồi rời đi, Âu Dương Hoa quỳ tiễn xưng lão tổ. Vương Lâm bay tới Cổ Yêu thành gặp Yêu tướng Mạc Lực Hải đang đứng trên tường thành cửa đông — Yêu tướng tiếc Thập Tam (bộ thứ mười tám của Thập Bát Yêu Ma Thân) bị Vương Lâm mang đi, mưu vào vòng ba cuộc chiến Yêu tướng để giành tư cách vào Cổ Yêu điện và chức phó soái. Hai người cùng qua ba truyền tống trận hướng kinh thành Thiên Yêu quận, nơi Vương Lâm ấp ủ ý bắt một trong mười người Đại La Kiếm Tông hỏi nơi Chu Dật bị phong ấn."},{"chuong":532,"tieuDe":"Một Chưởng","tomTat":"Chương mở ra toàn cảnh kinh đô Thiên Yêu quận: Thiên Yêu thành do chín tòa thành nhỏ ghép lại (tám thành ngoài theo bát quái, thành giữa là Đế Đô — tẩm cung của Yêu Đế), địa hình quanh thành như chín Cự Long quấn nhau cùng hướng về đầm Long Đàm nơi có Cổ Yêu Điện, sáng sớm phủ long khí có thể thổ nạp tăng tu vi. Tại truyền tống trận thứ mười bốn, một đội trưởng Yêu binh cùng thuộc hạ Nhị Cẩu trò chuyện, tiết lộ cứ ba trăm năm Đế Quân lại đích thân quan sát cuộc chiến Yêu tướng; lần này đặc biệt vì phải chọn hai vị soái mới thay hai phó soái tử trận trong đại chiến với Hỏa Yêu quận hai trăm năm trước, nên các Yêu tướng tấp nập về kinh. Truyền tống trận thứ mười bốn sáng lên, Mạc Lệ Hải cùng Vương Lâm bước ra, được Yêu binh cung nghênh. Mạc Lệ Hải mời Vương Lâm về phủ ở Hồng thành vì kinh thành đang hỗn tạp thế lực, giới thiệu hắn là “Vương tướng” bạn tốt. Mười chín kỵ binh giáp đen Hóa Thần dưới trướng quỳ tham kiến Chủ tướng rồi tham kiến cả Vương tướng. Cả đoàn phóng ngựa về phủ thì phía trước vang tiếng vó ngựa, Mạc Lệ Hải trầm sắc tăng tốc, còn Vương Lâm lóe mắt nhận ra một người quen."},{"chuong":533,"tieuDe":"Hổ Bào, Lão Già Và Áo Giáp","tomTat":"Trên quân đạo, đoàn người Mạc Lệ Hải chạm trán hai kỵ sĩ phóng tới: Thạch Tiễn tóc tím mặt sẹo mặc áo giáp thanh sắc và một tên gầy gò nhận ra Vương Lâm. Thạch Tiễn tung Lục Chỉ Kiếm Quyết đối Thập Băng Quyền Ý của Mạc Lệ Hải; nhờ Vương Lâm trợ một điểm xảo diệu, chiến mã Thạch Tiễn nứt bốn chân còn mã Mạc Lệ Hải bình an, cao thấp đã rõ. Tên gầy gò lộ thân phận là Trần Đào — sư huynh đồng hệ của Vương Lâm, bị Đại La Kiếm Tông đánh trọng thương tụt từ Vấn Đỉnh trung kỳ xuống Anh Biến viên mãn; Vương Lâm tặng túi Tuy Bình đan thiện chí rồi rời đi. Hai bên bàn về Thần Thông Tam Thức của Mạc Lệ Hải và kế luyện Thiên Nguyên đan khôi phục cho Trần Đào, đồng thời lộ tên Thạch Tiễn là kình địch cuộc chiến Yêu tướng. Vương Lâm vào Mạc phủ tu luyện bốn ngày trong khi Mạc Lệ Hải vào Đế Đô gặp Yêu Đế và thăm hỏi các Yêu tướng. Một lần luyện Sát Lục Tiên Quyết kéo dài bảy ngày, Sát Lục Chi Khí khiến hai quân sĩ phát điên sát khí và tiêu tán hơn nửa Yêu lực, khiến Vương Lâm sinh nghi vì sao giết nhiều mà Sát Lục Chi Khí lại ít."},{"chuong":534,"tieuDe":"Hỏi Diêu Tích Tuyết","tomTat":"Vương Lâm ngồi trong sân dùng hồi ức làm chậm từng lần luyện hóa Sát Lục Chi Khí để tìm quy luật, nhưng không thấy điểm chung — kể cả lần nén giận giết Tư Mã Viêm luyện được một đạo vẫn không giải thích thông. Hắn xác định Sát Lục Tiên Quyết là trọng điểm chuyến vào lãnh thổ Yêu linh, năm xưa học để chống Thác Sâm; nay có thêm Huyết Hồn Đan phối Sinh Cơ Lạc Ấn đủ bảo vệ tính mệnh, song vẫn quyết thí nghiệm và thôi diễn hàng loạt để lĩnh ngộ phần huyền bí còn ẩn. Hắn gọi hai quân sĩ dẫn đường, giấu tiên lực giả làm thư sinh ra cửa đông Hồng thành dạo phố, nhưng giữa cảnh đông vui lại thấy mình cô độc lạc lõng. Khi trời tối, tiếng đàn bi thương từ một thuyền hoa trên nhánh sông Thiên Yêu thành khiến hắn dừng bước, gợi nhớ tiếng đàn của Uyển Nhi ở sơn cốc Chu Tước Tinh; hắn vuốt mi tâm như chạm vào Lý Mộ Uyển trong Hạt Châu Thiên Nghịch và thề sẽ gặp lại nàng. Khi thuyền đi xa và bóng hắn tan vào đêm, cô gái đánh đàn như có linh tính xoay nhìn về con đường tối đen, mơ hồ thấy một hình bóng cô độc đang tan biến. Nàng gảy một tiếng đàn bi thương, lộ ra mình bị mù — trước mắt chỉ là khoảng đen kịt — ngồi đầu thuyền như đóa sen không nhiễm bụi, cô độc đón gió mà không ai thật sự lắng nghe."},{"chuong":535,"tieuDe":"Người Quen","tomTat":"Vương Lâm đứng bên bờ sông Hồng thành cả ngày, cảm nhận được trong Hồng lao — một trong tứ Đại Lao ngục của kinh đô, giam hơn vạn trọng phạm — ẩn chứa một cỗ yêu khí cường đại không kém Mạc Lệ Hải. Hắn về Mạc phủ đề nghị được đưa vào Hồng lao để giết chóc tu luyện, và để chứng minh giá trị đã vung tay tạo năm đạo sát lục khí hóa thành năm con thương long; chúng bị Mạc Lệ Hải đánh tan thì dung hợp lại, len qua quyền phong chấn động yêu giáp khiến hắn kinh ngạc, cuối cùng chốt cho vào bảy ngày. Sau khi Vương Lâm đi, Mạc Lệ Hải tự nhủ thứ sát khí xám sắc bén như yêu kiếm lại có biến hóa dẫn động sinh cơ là cực kỳ đáng sợ, nên quyết giữ quan hệ tốt. Suốt ba ngày chờ Mạc Lệ Hải sắp xếp, Vương Lâm không tu luyện mà ra bờ sông uống rượu nghe tiếng đàn bi thương từ hoa thuyền để tẩy rửa tâm linh, độc thoại về đạo nghịch thiên cô độc và chí thoát khỏi thân phận con kiến hôi. Đến khi mọi việc sắp xong, một ngày tiếng đ��n đứt đoạn; Vương Lâm đứng dậy nhìn hoa thuyền xa dần rồi rời đi, còn nữ tử đánh đàn quay đầu nhìn theo bóng hắn. Một khách nhân giọng bình thản bên cạnh gọi tên nàng là Minh Huyên và lạnh lùng buộc nàng đổi bài khác, hé lộ nàng đang bị một thế lực bí ẩn khống chế."},{"chuong":536,"tieuDe":"Loạn Kinh Đô","tomTat":"Vương Lâm nghe một nữ tử bị ép gảy khúc đàn vui mà ẩn tiếng khóc, cước bộ sững lại nhưng không quay đầu mà đi tiếp. Nửa đêm hắn cùng Mạc Lệ Hải phóng tới Hồng lao ở Hồng thành, được nam tử họ Hứa tu vi Anh Biến hậu kỳ đại viên mãn tiếp nhận; Mạc Lệ Hải trả ba tầng đầu Thập Băng Quyền Ý để đổi cho Vương Lâm một suất tu luyện rồi rời đi. Hứa cho Vương Lâm một tháng trong lồng giam dưới lòng đất giết phạm nhân nghiên cứu sát lục khí, nhưng sau năm ngày hắn vẫn cách một tầng giấy mỏng vì thiếu sát tâm. Hứa chỉ điểm sát tâm như kiếm chưa rời vỏ, ra điều kiện đưa Vương Lâm tới nơi cảm nhận sát lục chân chính để đổi việc giết yêu tướng Thạch Tiễn, rồi tiết lộ bí mật tầng đáy Hồng lao là thế giới máu nuôi yêu kiếm của yêu đế. Vương Lâm ngồi vào hồ máu, hòa vào chu kỳ chém giết, mất ý thức thi triển Tịch Diệt Chỉ và Hóa Ma Chỉ, trở thành một trong hơn trăm người sống sót và ngộ ra cần có sát lục chi tâm. Qua nhiều ngày chém giết, người sống sót giảm dần còn huyết sát vụ trên thân Vương Lâm dày tới hơn trăm trượng. Yêu kiếm ngân long hiện ra hút sát vụ và xé tan kẻ phản kháng; cuối cùng chỉ còn Vương Lâm và một thanh niên tóc đen khi ngân long lại hút mạnh."},{"chuong":537,"tieuDe":"Cố Cười","tomTat":"Trong thế giới huyết sắc của Hồng Lao, Vương Lâm chứng kiến cảnh tu sĩ tan-tái sinh trong hồ máu và minh ngộ bản chất Sát Lục tiên quyết — lấy sát niệm đoạt tính mệnh, luyện sinh cơ thành lạc ấn sinh mệnh đi “từ tử tới sinh”, hợp luân hồi chi đạo. Khí Sát Lục bạo phát xé tan mọi tu sĩ trong các hồ máu, cuối cùng 3792 đạo sát lục khí xám vờn quanh hắn, chỉ thanh niên tóc đen sống sót. Vương Lâm dùng 3792 đạo sát lục khí phá vỡ một trảo của ngân long Đế Kiếm — lần đầu con mồi đánh bại nó — rồi hóa điện quang dùng hơn ba nghìn lạc ấn làm phòng hộ chịu kiếm quang, lao khỏi thế giới huyết sắc. Đế Kiếm phẫn nộ tự rút khỏi Kiếm Các bay về Hồng Thành, khiến các Yêu Soái, Yêu Tướng (Thạch Tiêu, Tôn Đào), Mặc Phi và Quý Phi Lâu chấn động; tướng mạo Mặc Phi giống y hệt thanh niên tóc đen. Nam tử họ Hứa dẫn Vương Lâm trốn khỏi Hồng Lao qua đường bí mật và nhắc về giao hẹn, còn Mạc Lệ Hải đưa hắn ẩn trong Thiên Nghịch Châu suốt một tháng tránh Đế Kiếm lùng sục. Mạc Lệ Hải tiết lộ quy chế đại hội Yêu Tướng đêm yêu linh cho phép đề cử người ngoài thay thế, hẹn tiến cử Vương Lâm. Cuối chương, Vương Lâm nghe đàn bên sông và đối ẩm với thanh niên áo xanh, rồi cùng Mạc Lệ Hải viếng phủ phó soái Huyền Thành."},{"chuong":538,"tieuDe":"Đế Kiếm Ủy Khuất","tomTat":"Mạc Lệ Hải dẫn Vương Lâm vào soái phủ bái kiến phó soái Huyền Thành — nam tử áo tím bản lãnh tương đương Vấn Đỉnh Sơ Kỳ đỉnh phong. Phó soái tỏa áp lực thử hai người nhưng cả hai đứng vững; hắn coi thường Vương Lâm chỉ là tùy tùng và thách thi triển thần thông mạnh nhất. Vương Lâm phóng hai nghìn đạo sát lục chi khí như rồng giận, xuyên thủng mãnh hổ yêu khí và màn yêu giáp bảy tấc, ép phó soái liên tục lui giẫm nát hoa quý, buộc hắn công nhận tư cách rồi đuổi hai người về. Sau đó phó soái phun máu, tuyên bố ba tháng không tiếp ai rồi bế quan. Về Mạc phủ, Mạc Lệ Hải chân thành nhờ Vương Lâm trợ giúp đại hội Yêu Tướng, Vương Lâm đồng ý, cùng uống rượu chôn hơn năm trăm năm. Tại Đế Đô Kiếm Các ở trung tâm Thiên Yêu Thành, một người mặc hoàng bào trấn áp Đế Kiếm trong trận pháp, cấm nó tới Hồng Lao phá hoại và dọa đưa tới Long Đàm, khiến thế giới huyết sắc tầng thấp nhất của Hồng Lao dần khôi phục."},{"chuong":539,"tieuDe":"Hoạt Động Ngầm","tomTat":"Trong huyết đàm vô tận, một nam tử tóc đen để sát niệm nhập thân, quyết thoát ra như kẻ từng thoát trước đó; sau một ngày chém giết chỉ còn mình hắn đứng vững, hắn lao tới lối ra và tự bạo thân tạo màn sương máu trăm trượng làm thương tay Ngân long Đế Kiếm, rồi bị ngân long giết đi sống lại nhiều lần. Ngân long phẫn nộ, mối hận với Vương Lâm bị khơi lại; nó bị Yêu Đế hạn chế nên trút giận trong huyết đàm. Còn nửa tháng tới cuộc đấu Yêu Tướng, cả Thiên Yêu Thành căng thẳng vì đây là bệ phóng lên Yêu Soái; luật cấm Yêu Tướng chiến đấu sinh tử nên thủ đoạn dồn vào giết người trợ giúp, còn ám sát chính Yêu Tướng thì đụng gián điệp Yêu Đế nên gần như chắc chết. Mạc Lệ Hải bế quan trong phủ giữ trạng thái và bố trí trận pháp tránh ám sát. Giữa thời loạn, chỉ Vương Lâm bình tĩnh mỗi sáng ra bờ sông nghe đàn uống rượu, mơ hồ thấy dấu hiệu sắp đột phá và đánh giá Mạc Lệ Hải tâm cơ sâu thủ đoạn nhiều. Khi một sát thủ áo đen của Yêu Linh (Hóa Thần hậu kỳ) tới thử, Vương Lâm dùng Tịch Diệt Chỉ giết gọn một đòn và thu đám khí xám từ thất khiếu hắn vào tay phải."},{"chuong":540,"tieuDe":"Sát Lục Đạo!","tomTat":"Vương Lâm ngồi bên bờ sông lắng nghe tiếng đàn bi thương từ một chiếc thuyền tranh, đắm chìm cảm ngộ. Cách nghìn dặm trên tầng hai một tửu lầu, hai nam tử áo đen quan sát hắn, nhận định tu vi đạt Anh Biến Kỳ và nhận lệnh lão tổ truy bắt. Sát thủ số bốn hóa đạo cầu vồng tập kích nhưng bị Tịch Diệt Nhất Chỉ phá vỡ và đâm chết, để lại một đạo khí xám bay về phía Vương Lâm. Sát thủ số hai gần viên mãn Anh Biến Hậu Kỳ đích thân ra trận, dùng hơn trăm quang cầu yêu lực liên tiếp mới giải được Tịch Diệt Nhất Chỉ, hao tổn lớn chỉ còn tám quang cầu. Khi thuyền đi xa tiếng đàn tan, Vương Lâm đứng dậy lần đầu quay đầu, hai mắt lóe màu hồng phóng ra Sát Lục Đạo như kiếm sắc đâm vào tâm trí số hai khiến hắn cứng đờ, tâm thần suýt sụp đổ. Cả nhóm áo đen khiếp sợ, nam tử lớn tuổi đứng bật dậy làm vỡ bàn, kinh hãi nhận ra ánh mắt kia là sát khí tích từ việc giết vô số người và kêu lên đây chính là Sát Lục Đạo."},{"chuong":541,"tieuDe":"Kiếm Khí Của Lăng Thiên Hậu","tomTat":"Vương Lâm áp chế một yêu tu lớn tuổi đến mức hắn tự bùng nổ tiên yêu lực phá hủy cả vùng trăm trượng; Vương Lâm thoát thân an toàn và gài một tia khí xám âm thầm đuổi theo. Tại Đế Đô Thiên Yêu Thành, Yêu Đế chuẩn tấu cho Mặc Phi được đánh Mạc Lệ Hải trước, bất chấp lời can rằng việc đó sẽ khơi mào đấu đá giữa các Yêu Tướng; còn tám ngày là tới đại hội tranh đoạt. Mạt Dương của Kiếm Tiếu Thập Nhị Tử (Đại La Kiếm Tông) đột nhập Mạc phủ, giết quân sĩ và trao chiến thư “Chiến!” của Mặc Phi cho Mạc Lệ Hải, hẹn ba ngày sau ở Cổ Đạo. Quay đi gặp Vương Lâm, Mạt Dương khiêu chiến nhưng sáu mươi tư đạo kiếm khí bị dấu ấn hộ thể hóa giải sạch, cự kiếm tím bị b��t sống và Tà Dương Chi Hồn bị sát lục chi khí đánh tan, khiến hắn hộc máu. Vương Lâm tha hắn, ném trả cự kiếm và nhờ chuyển lời không muốn đối địch Đại La Kiếm Tông tại vùng đất Yêu Linh. Nhưng khi Mạt Dương rời đi thầm thề báo thù, khí xám ẩn trong cự kiếm chui vào đầu hắn, cắt nguyên thần khỏi thân thể và hút cạn huyết nhục lẫn tiên lực; Mạt Dương hóa thây khô, Vương Lâm hiện thân đoạt thi thể rồi biến mất."},{"chuong":542,"tieuDe":"Cuộc Chiến Yêu Tướng","tomTat":"Trong nơi ở tại Mạc phủ, Vương Lâm bước ra từ hư vô, buông thi thể Mạt Dương rồi tung Cấm Phiên hóa thành màn sương đen dựng vô số cấm chế. Hắn phun ra ngọn lửa u ám hô “Luyện!” thiêu đốt thi thể, sau đó luyện hóa nguyên thần Mạt Dương. Hắn nhớ lại đòn cuối điểm vào mi tâm khiến mình cảm thấy nguy cơ sinh tử, và phát hiện ở mi tâm nguyên thần Mạt Dương có một đường chỉ lam hình thanh kiếm thu nhỏ — đạo kiếm khí bảo mệnh mà Kiếm Tôn Lăng Thiên Hậu từng ban cho mười hai đệ tử Đại La Kiếm Tông ở cửa Yêu Linh Đông Hải. Vương Lâm cẩn thận luyện hóa nguyên thần Mạt Dương suốt mấy ngày, rồi cắn răng nuốt thẳng sợi chỉ lam, nguyên thần suýt đứt liên hệ với thân thể, phải tĩnh tọa ba ngày trước khi mở mắt lóe ra kiếm ảnh. Mạc Lệ Hải chờ ngoài phòng ba ngày trong lo lắng; khi Vương Lâm xuất quan với khí thế như nhất đại tông sư rồi thu liễm như phàm nhân, hắn khiếp sợ. Mạc Lệ Hải báo đã bại trận trước Mặc Phi vì Chuyển Luân thuật làm Yêu Hải Bách Lãng quay ngược trở về, và ngày mai là đại hội Yêu Tướng tranh đoạt."},{"chuong":543,"tieuDe":"Ngươi, Bước Ra Khỏi Hàng","tomTat":"Đêm trước trận chiến Yêu Tướng, Mạc Lệ Hải tiết lộ với Vương Lâm tuyệt chiêu Yêu Nhiên do Đế Quân đích thân truyền — phá được mười bảy trong mười tám tầng Chuyển Luân thuật; vì đã thua Mặc Phi nên hắn không được tham chiến, trông cậy hết vào Vương Lâm rồi vái sâu từ biệt. Sáng hôm sau tại Đế Đô, trống Thiên Yêu vang ba tiếng mở đại điển, sáu Phó Soái và tám Yêu Soái lần lượt nhập trường, riêng ngai Yêu Đế để trống vì Đế Quân không tới. Một nam tử mặc giáp vàng chủ trì, công bố quy tắc tàn khốc: một thắng một bại thì cả hai mất tư cách, Yêu Tướng không được chết, chỉ trợ giúp được phép tử vong. Trận đầu, Thạch Tiêu dùng quang đồ hình thoi hạ Mộ Vân rồi đâm vỡ thân trợ giúp Thiên Khôi Công Nhân của Cự Linh Môn thành máu thịt. Thạch Tiêu chuyển sang khiêu chiến Vương Lâm nhưng bị cự tuyệt và buộc lui, lúc đi ngang còn hạ giọng dọa sẽ giết Vương Lâm. Huyền Phó Soái có thù với Vương Lâm vẫn quả quyết hắn sẽ dẫn đầu, đánh cược Phó Thiên Triệu Kỳ với Huyền Huyền Đan của Hoàng Phó Soái. Cuối cùng Yêu Tướng Ngao Địch chớp cơ hội khiêu chiến Vương Lâm, bị hắn đáp gọn rằng đối phương không phải là đối thủ."},{"chuong":544,"tieuDe":"Nụ Cười Dâm Đãng Của Hứa Lập Quốc","tomTat":"Tại đại hội Yêu Tướng của Thiên Yêu Môn, Yêu Tướng Ngao Địch giậm chân độn thổ nhưng bị Vương Lâm bước một bước phá đất bức lộ thân. Vương Lâm túm tay phải Ngao Địch truyền tiên lực phá hủy toàn bộ kinh mạch, dùng Sinh Chi Lạc Ấn hóa giải hư ảnh long quy tới tầng thứ tám, rồi rung tay làm vỡ nát xương cốt đối phương thành phế nhân. Nam tử mặc giáp vàng (Kim tổng quản) ngưng ánh sáng mặt trời thành trường thương vàng phóng tới cứu, nhưng Vương Lâm vỗ hai cái làm thương đổi hướng và chất vấn khiến hắn thu thương, liếc nhìn thật sâu. Cả khán đài chấn động vì lần đầu một người ngoài đánh phế Yêu Tướng chớp mắt; Vu Sâm, nam tử tóc đen với Thất Yêu Chi Thuật, tám Yêu Soái, Trần Đào và Mạc Lệ Hải đều phản ứng mạnh. Tại Kiếm Các, Đế Kiếm căm giận Vương Lâm nhưng sợ lệnh Đế Quân nên chỉ hóa Kiếm Linh thiếu nữ lén ra ghi nhớ khí tức, ngồi ẩn trên mái cung điện. Hứa Lập Quốc — ma đầu Kiếm Linh trong tiên kiếm của Vương Lâm — kích động xin ra ngoài, cười dâm đãng đuổi theo tán tỉnh thiếu nữ Kiếm Linh và nhờ Tiểu Hắc Đao hỗ trợ cân bằng. Cuối cùng thiếu nữ quay về Kiếm Thể, Hứa Lập Quốc tức giận hẹn sẽ lại tới; kết thúc ngày đầu đại hội với sáu trận phân thắng bại."},{"chuong":545,"tieuDe":"Kế Hoạch Làm Phản Của Hứa Lập Quốc Thất Bại!","tomTat":"Giữa kỳ nghỉ mười ngày của vòng đầu tranh đoạt Yêu Tướng, Mạc Lệ Hải ngày ngày đến Đế Đô ghi lại đối thủ uy hiếp đưa cho Vương Lâm, còn Vương Lâm nghe đàn uống rượu suy ngẫm con đường Vấn Đỉnh nhưng vẫn thiếu một bước chưa rõ. Si mê thiếu nữ Kiếm Linh của Đế Kiếm, Hứa Lập Quốc phá phong tỏa đòi đi tìm tiểu mỹ nhân và mắng Vương Lâm ghen tị, khiến Vương Lâm nhận ra hắn che giấu nhiều thủ đoạn và chỉ trung thành khi chủ nhân đủ mạnh. Vương Lâm thu hồi sát khí cắt liên hệ tiên kiếm; Hứa Lập Quốc biến thành hình kiếm phá cấm chế bỏ chạy ra khỏi Thiên Yêu Thành nhưng bị Vương Lâm dùng cấm chế kéo về. Loan đao Tiểu Hắc tự xông ra tập kích hai lần đều bị Sinh Chi Lạc Ấn bật ra, rồi bị hơn ba nghìn đạo Sát lục chi khí ép thành quả cầu và bị in dấu ấn nguyên thần thu phục, song loan đao lại đi theo bên cạnh Hứa Lập Quốc. Tại Kiếm Các Đế Đô, Đế Kiếm hóa thiếu nữ thề chém kẻ Kiếm Linh vô sỉ kia. Về Hồng Thành, Vương Lâm gặp đoàn tu sĩ Ngọc Kiếm Môn thức tỉnh rời Thiên Yêu Thành, từ ánh đèn Mạc phủ và bình minh mà ngộ ra chữ “nghịch” — mấu chốt hướng Vấn Đỉnh. Cuối cùng hắn lên thuyền tranh nghe đàn của Minh Phí cô nương, cùng thanh niên bí ẩn nhận nhau là tục nhân và hẹn uống tới bình minh."},{"chuong":546,"tieuDe":"Đánh Cuộc","tomTat":"Vương Lâm cùng thanh niên ôm đàn ngắm trăng uống rượu tới rạng sáng trên thuyền rồi chia tay, theo gió bay đi trong màn sương sớm. Tại Đế Đô, vòng một cuộc tranh đoạt Yêu Tướng kết thúc còn lại 48 người; nam tử mặc kim giáp phụng mệnh Đế Quân tuyên luật vòng hai là gõ thánh vật Chiến Yêu Cổ — làm từ da Cổ Yêu, người huyết khí không đủ gõ không vang còn tự sụp đổ, lấy mười người và cho phép người trợ giúp cùng gõ. Yêu Tướng Vu Sâm tu Sát Lục đạo dùng Phệ Hồn Sát Lục đệ nhất thức gõ bốn tiếng rồi trọng thương tay phải. Mặc Phi đeo mặt nạ thong dong gõ tám tiếng, mặt nạ vỡ lộ khuôn mặt anh tuấn giống hệt nam tử tóc đen ở chỗ sâu Hồng Lao khiến Vương Lâm sững lại; cùng người trợ giúp thanh sam gõ thêm ba tiếng, tổng mười một tiếng áp đảo. Trên đài, Huyền Phó Soái đánh cược với Hoàng Phó Soái rằng Vương Lâm không thua, âm thầm cho rằng hắn đáng sợ hơn cả Mặc Phi. Trần Đào tự nhận chỉ gõ được bảy tiếng, tiếc chưa đạt Vấn Đỉnh trung kỳ. Cuối cùng nam tử kim giáp gọi tên Vương Lâm, tỏa sát khí và thách hắn dám đánh cược hay không."},{"chuong":547,"tieuDe":"Ngôn Xuất Pháp Tùy","tomTat":"Kim tổng quản mặc kim giáp cá cược với Vương Lâm rằng hắn không thể đánh quá năm tiếng trống trên Yêu Cổ, thắng thì đề cử làm yêu tướng còn thua thì bị xử lý; Vương Lâm từ chối đề cử, đòi thẳng một cánh tay của hắn. Vương Lâm vận hơn ba ngàn Lạc Ấn Sinh Mệnh làm lá chắn, đánh liền năm tiếng hợp nhất mà thân thể không hề di động, làm mặt đất nứt vòng tròn trăm trượng khiến khán giả chấn thương mất mạng. Kim tổng quản nhiều lần nuốt lời nâng giá; Vương Lâm đánh tới tiếng thứ tám mang theo câu “Ta muốn một bàn tay của ngươi” hóa thành thiên uy, khiến bảy yêu soái kinh sợ thốt “Ngôn xuất pháp tùy”. Kim tổng quản phản bác rằng Vương Lâm chỉ mượn uy chiếc trống chứ chưa thật đạt cảnh giới, rồi nâng giá lên mười lăm tiếng. Vương Lâm đánh tiếng thứ chín phá vỡ toàn bộ ba nghìn bảy trăm Lạc Ấn, vượt qua kỷ lục tám tiếng của đệ nhất yêu tướng Mặc Phi và vang danh Thiên Yêu quận. Cuối chương hắn ngộ ra đạo thuận - nghịch, nhận phản lực Yêu Cổ là khí tức bất khuất trong ý niệm, tiến chín bước vuốt mặt trống và dung hợp ý thức vào Yêu Cổ. Nữ yêu tướng duy nhất Tà Liên cùng Thiên soái và các yêu tướng đều chú ý theo dõi thành tích chấn động này."},{"chuong":548,"tieuDe":"Thiên Soái Động Dung","tomTat":"Người đàn ông mặc kim giáp cười lạnh chế giễu việc Vương Lâm đánh Yêu Cổ mười lăm tiếng là giả thần giả quỷ, nhưng Vũ soái — nữ Yêu soái duy nhất — đính chính rằng hắn đang cảm ngộ khí tức trong trống, năm xưa chính bà cũng từng cảm được, khiến toàn bộ Yêu soái ngưng trọng. Vương Lâm nhắm mắt dung hợp nguyên thần với cổ khí tức không chịu khuất phục trong Yêu Cổ, thu hồi Sinh Chi Lạc Ấn cho lực phản chấn tiến thẳng vào người, đánh tiếng trống thứ mười để tẩy tủy — mồ hôi đen tiết ra nhưng lực vận chuyển loạn khiến sắc mặt trắng xanh. Hắn ngộ ra mình bị thương không phải do tu vi yếu mà do dung hợp theo đạo của Yêu Cổ chứ không phải đạo của riêng mình, rằng một chữ nghịch chia thành nhiều con đường tùy cảm ngộ. Tới tiếng trống thứ mười một, Vương Lâm đem ý niệm bi thương cùng cảm ngộ tiếng đàn hoa thuyền hòa vào tiếng trống, đạt cảnh giới trống truyền niệm khiến bi niệm lan khắp Thiên Yêu thành. Cả khán đài Yêu soái, Yêu tướng cùng văn thần chìm vào nội tâm cộng hưởng tâm linh và rơi lệ, riêng Mặc Phi vẫn bình thản hờ hững không hề lay động. Huyền Hôn soái kính phục ngờ hắn là người Yêu Đế chờ đợi nhiều năm, Thiên soái lần đầu đứng thẳng kinh ngạc nhận ra danh tính Vương Lâm, còn người mặc kim giáp thì trắng mặt kinh hoàng."},{"chuong":549,"tieuDe":"Ta Phải Vấn Đỉnh","tomTat":"Sau khi gõ Yêu Cổ tới tiếng trống thứ mười một truyền niệm, đạt cảnh giới Ý Cảnh mà người mặc kim giáp tự nhận không làm được, Vương Lâm nhắc lại giao ước “đánh mười lăm cái thì chặt một cánh tay”. Ánh mắt hắn quét khắp khán đài: sáu phó soái né tránh trừ Huyền phó soái ôm quyền cảm khái; Thiên soái lần đầu mở miệng tuyên bố sẽ nhớ kỹ tên hắn; Thạch Tiêu lộ chiến ý bị phớt lờ; ánh mắt dừng ở Mặc Phi hờ hững. Vương Lâm lần đầu cảm nhận sự kêu gọi Vấn Đỉnh, gõ tiếp ba tiếng trống thứ mười hai, mười ba, mười bốn, đem bi ai dung nhập tiếng trống tạo lực trùng kích, đạt tẩy tủy thật với mồ hôi đen tiết ra. Chương tiết lộ lai lịch Yêu Cổ làm từ da Cổ Yêu, xếp sau sinh vật Long Đàm, chỉ Đế tộc hoặc người lập công lớn mới được tẩy tủy. Vương Lâm độc thoại nhận ra đạo tâm chưa viên mãn vì còn chấp niệm bi thương về Lý Mộ Uyển, muốn dung bi thương vào tiếng trống để đạt Vấn Đỉnh — nhưng làm vậy là phải quên nàng. Bàn tay hắn run lên do dự chưa hạ xuống, trong khi Thiên soái nhớ năm xưa mình cũng phải lựa chọn, Tà Liên châm biếm và Trần Đào lần đầu thấy chán ghét hắn."},{"chuong":550,"tieuDe":"Nghịch","tomTat":"Trên khán đài và trong giới quan sát, Trần Đào, Thạch Tiêu, Mặc Phi cùng Huyền Hôn soái bàn luận về nỗi đấu tranh nội tâm của Vương Lâm khi hắn ngừng tay trước Yêu Cổ. Đứng cách mặt trống một tấc, Vương Lâm nhận ra quét sạch bi thương để lên Vấn Đỉnh sẽ biến Lý Mộ Uyển thành Lô Đỉnh và là thuận thiên trốn chạy, nên ngộ ra đạo của mình là Nghịch — nghịch thiên mà đi, giữ trọn tình cảm. Khí tức nghịch thiên như vô số kiếm sắc đâm lên trời, khiến Thiên soái kinh hãi nhận ra hắn chọn con đường giống Yêu Đế năm xưa; từ tòa tháp đen trên chiến trường viễn cổ, một thực thể giáp đen phát thần niệm “Nghịch tu… Tốt lắm!”. Vương Lâm dồn bi niệm về Uyển Nhi lên tay phải, vỗ tiếng trống thứ mười lăm xuống Yêu Cổ, làm thiên địa biến sắc sấm chớp kinh động toàn Thiên Yêu thành. Kim Ô Húc dồn tu vi phóng tới sau lưng với quyền cầm mặt trời quyết giết hắn, nhưng Vương Lâm đã chuyển ba nghìn Sinh Chi Lạc Ấn lên toàn thân để chống đỡ. Thiên soái phóng xuống quát ngăn và bấm pháp quyết hóa ô quang đánh tay trái Kim Ô Húc; cùng lúc tiếng quát “To gan! Kim Ô Húc!” từ con thuyền ngoài Đế Đô và cổ âm hàn từ tháp đen đánh vỡ kim giáp Kim Ô Húc, khiến hắn hộc máu và mặt trời trên tay phải tàn lụi."},{"chuong":551,"tieuDe":"Kim Giáp Đã Chết!","tomTat":"Thần thông của Thiên soái đập vào người đàn ông mặc kim giáp nhưng thật ra chưa đánh trúng đã thu hồi; Thiên soái kinh ngạc nhận ra gã đã bị một kẻ ẩn danh mạnh hơn Đế Quân nhiều lần làm trọng thương kép, yêu lực tan, kinh mạch nứt, từ Mãnh Long thoái hóa thành loài bò sát. Vương Lâm hiểu rõ thời cơ, chụp lấy gã đang cực yếu đập thẳng vào Yêu Cổ, dồn toàn bộ bi niệm cả đời vào một kích cuối để vượt Anh Biến kỳ. Tiếng trống thứ mười lăm vang lên, Kim Ô Húc — chính là Kim tổng quản — nát vụn tiêu tán tận chân trời, đến Kỳ Khôi Phách cũng vỡ. Vương Lâm trở thành đệ nhất nhân trên danh nghĩa Thiên Yêu quận; Thiên soái tán thưởng, Huyền Phó soái sắp đột phá, Mạc Lệ Hải yên tâm, khán đài tôn kính. Tiếng trống thứ mười lăm hóa thiên bi địa bi, dung hợp sấm sét, lan khắp Thiên Yêu thành khiến mọi người rơi lệ và mở con đường tu hành nghịch thiên trên đạo tâm Vương Lâm. Vương Lâm ngẩng đầu “Ta đã giữ lại được!”, luận về thiên đạo và gọi thiên kiếp giáng xuống, bởi chỉ khi xuất hiện người nghịch tu thì thiên kiếp thật mới giáng."},{"chuong":552,"tieuDe":"Thiên Kiếp Đơn Giản Nhất","tomTat":"Ở lối vào cửa biển Đông Hải năm xưa ngoài lãnh thổ Yêu Linh, một luồng hồng quang mang khí tức chiến sát thời hồng hoang từ hư vô giáng lâm với tốc độ vượt mọi thần thông, xuyên qua cửa Đông Hải chưa mở tiến vào lãnh thổ Yêu Linh — đó là thiên kiếp hàng lâm. Nhiều lão quái cảm ứng: Thiên Vận Tử bấm pháp quyết thấy thiên kiếp liên hệ kỳ quái với Thiên Vận Tinh của mình, Lăng Thiên Hậu đang luyện Nguyên Nguyên Tạo Hóa Đan thì biến sắc nghi ‘tên Tham Lang’ gặp tai biến, còn người đàn ông tóc đỏ trong căn lầu máu giữa một tinh cầu máu thì lo cho đứa hài tử Tích Tuyết. Tại quảng trường vạn trượng Thiên Yêu thành, Vương Lâm đánh tiếng trống thứ mười lăm bên Yêu Cổ; tiên lực và đạo tâm cùng viên mãn, hắn sắp dung hợp tiến Vấn Đỉnh để tiến hóa từ người thành tiên, chính việc bảo lưu ý niệm nghịch thiên đã dẫn phát thiên kiếp. Hồng vân ngưng tụ thành kiếp lôi đỏ như máu trên bầu trời Đế Đô; người thanh niên trên thuyền hoa nhận ra đây là loại thiên kiếp đầu tiên đơn giản nhất, khen Vương Lâm vận khí không tồi. Vương Lâm hồi tưởng hơn bảy trăm năm đời mình từng nhiều lần dẫn động thiên kiếp, kể cả vì Lý Mộ Uyển nghịch thiên cải mệnh. Khi hồng lôi mang thiên sát giáng xuống cùng tuyết sát đầy trời, hắn ngưng hơn ba nghìn bảy trăm đạo Sinh Chi Lạc Ấn, dùng Cấm Phiên hóa lốc đen khổng lồ nghênh đánh, hai bên va nhau nổ vang chấn động khiến nhiều người chảy máu tai ngất xỉu."},{"chuong":553,"tieuDe":"Thiên Uy","tomTat":"Khi hồng lôi thiên kiếp đánh xuống Thiên Yêu Thành, Vương Lâm tung mọi cấm chế trong Cấm Phiên rồi trăm đạo Tịch Diệt Chỉ hợp thành hắc mang ba trượng nhưng đều thất bại trước thiên kiếp. Hắn ngưng tụ ba nghìn bảy trăm đạo Sinh ấn hóa thành Sát Lục Long thôn phệ hồng lôi, song rồng vẫn tan biến. Cuối cùng Vương Lâm hô “Hóa Ma”, nghịch chuyển cả núi tiên ngọc trắng thành ma lực vô tận, thi triển Hóa Ma Chỉ đỉnh phong vượt cả Tư Đồ Nam, mang theo chấp niệm hình bóng Lý Mộ Uyển. Hắc mang va chạm hồng lôi gây vụ nổ kinh thiên động địa làm quảng trường vạn trượng vỡ vụn, khán đài sụp đổ, và đạo lôi kiếp đầu cuối cùng tiêu tán. Thiên soái ném cho Vương Lâm một bình ngọc chứa đan dược rồi rời đi, nhưng hắn không tin thiên kiếp chỉ có một đạo lôi. Người thanh niên trên thuyền hoa định bắt Vương Lâm khỏi Đế Đô độ kiếp nơi khác nhưng phát hiện hắn bị thiên kiếp khóa chặt, đành phân thân thành tám di dời cư dân tám tòa ngoại thành. Vừa xong, hồng vân bao phủ Thiên Yêu Thành, thiên uy giáng lâm khiến người thanh niên cười khổ lo các lão tổ tông xuất hiện."},{"chuong":554,"tieuDe":"Yêu Cổ","tomTat":"Vương Lâm đứng trên mảnh vỡ quảng trường vạn trượng Đế Đô Thiên Yêu thành, đối mặt đòn trừng phạt thứ hai của thiên kiếp; thiên uy xuất hiện buộc vạn vật khuất phục, hồng vân hạ liên tục từng tấc đè nát mặt đất khiến hắn cảm giác như năm xưa bị phế tu vi trong linh mạch Luyện Hồn Tông, nhưng hắn ngẩng đầu tuyên bố sẽ không khuất phục. Hoàng cung Đế Đô sụp đổ, cả Thiên Yêu thành vạn năm hóa tro bụi, duy thánh vật Yêu Cổ sót lại; từ lòng đất năm lão già tóc trắng tự xưng con cháu Cổ Yêu phóng lên phẫn nộ mắng thiên kiếp, cãi cọ loạn rồi nhiều lần bị thiên uy quẳng xuống đất tạo năm hố sâu. Hồng vân hạ cả trượng, Vương Lâm phun máu lớn, cơ thể chìm sâu vào lòng đất, kinh mạch đứt khớp xương vỡ nhưng đạo tâm quyết không thỏa hiệp. Một giọng nói âm u vang trong tâm thần hắn, giảng giải vì sao thiên đạo trừng phạt người nghịch tu chọn ngênh chiến và kể lịch sử tộc Cổ thời vũ trụ sơ khai, chủng tộc đồng trang lứa với thiên đạo tự xưng Cổ. Tộc Cổ về sau phân chia thành Cổ Thần (lực lượng khổng lồ), Cổ Ma (sát lục) và Cổ Yêu (thần thông diệt đạo) — đều là sinh linh nghịch tu. Khi Vương Lâm hỏi giọng nói ấy có phải Cổ Yêu, nó đáp Ta là Cổ Yêu."},{"chuong":555,"tieuDe":"Vấn Đỉnh Chi Tinh","tomTat":"Cổ Yêu — tồn tại không hoàn chỉnh trong Yêu Cổ và là lão tổ tông của dân Thiên Yêu quận — tiết lộ với Vương Lâm về cửu quận Yêu Linh: chín tồn tại tương tự nó muốn thôn phệ lẫn nhau để hoàn chỉnh, sinh ra chiến tranh kéo dài. Cổ Yêu đề nghị sửa thân thể, giúp Vương Lâm vượt thiên kiếp và ban quyền lợi Thiên Yêu quận, đổi lấy việc tương lai Vương Lâm thu hồi thánh vật tám quận khác. Vương Lâm đồng ý; thân thể phục hồi mạnh hơn xưa nhiều lần, hư ảnh Cổ Yêu cao trăm trượng hiện sau lưng cùng hắn thi triển Diệt đạo - Vân toái đập vỡ hồng vân, rồi nuốt cả đạo Xích Tiêu Vân Mang, sau đó hóa khói xanh biến mất và hẹn ba tháng sau ở Long Đàm. Hệ quả là Thiên Yêu Thành sụp lún; năm lão tổ phạt Vân Độn ba tháng khôi phục thành và giao đưa Vương Lâm về Long Đàm. Vương Lâm dùng lệnh bài tiến vào thần bí động phủ, đổ hết tiên ngọc làm nhiên liệu, nuốt Vấn Đỉnh Chi Tinh của Chu Dật để tiến Vấn Đỉnh. Quá trình suýt thất bại vì nguyên khí không kết tinh được, viên Vấn Đỉnh Chi Tinh của Chu Dật mang Ý cảnh Chí Tử Si Ý bay vào kén nguyên thần, dập bớt tiên hỏa rồi tan vỡ dồn toàn bộ nguyên khí, khiến Vấn Đỉnh Chi Tinh của Vương Lâm tăng từ móng tay thành ngón tay và kén nguyên thần sinh khí tức mới. Trong khi đó, trên đỉnh hắc tháp chiến trường cổ ngoài Thiên Yêu Thành, một bộ giáp đen lóe u quang rình hút lực lượng Vấn Đỉnh của hắn nhưng do dự vì sự xuất hiện của Cổ Yêu."},{"chuong":556,"tieuDe":"Vấn Đỉnh Sơ Kỳ","tomTat":"Mười năm trôi qua, Vương Lâm tĩnh tọa như tượng trong động phủ ở Thiên Yêu quận; bên ngoài Thiên Yêu Thành đã được xây lại bằng kích thước cũ, Đế Đô cùng quảng trường Thiên Yêu Môn và Yêu Cổ vẫn còn, truyền thuyết về hắn vẫn lan truyền dù thuyền hoa và người đàn năm xưa đã biến mất. Người thanh niên từng uống rượu với Vương Lâm đứng trên lầu ở Đế Đô (bên cạnh có một cô gái trẻ xinh đẹp) than mười năm không tìm được tung tích hắn dù Ngũ tổ gia liên thủ tra thần thức; đại hán Phó soái ở một tòa thành khác cũng nhìn trời nhớ “Vương huynh”. Kén nguyên thần của Vương Lâm nứt vỡ, nguyên thần thực chất mang Vấn Đỉnh Chi Tinh bay ra; hắn mở mắt thốt “Vấn Đỉnh”, đạt cảnh giới Vấn Đỉnh sau bảy trăm năm tu đạo, song nguyên khí cần bốn mươi chín ngày củng cố. Một tồn tại bị thương nặng ngụ trong áo giáp ở tầng cao nhất hắc tháp trên chiến trường viễn cổ tỉnh dậy, mở vòng xoáy đen, dung hợp xương đen với hộ uyển lửa ma thành cánh tay xương rồi phái đi hút nguyên khí, đồng thời tự phá bỏ một cánh tay vì không thể rút ở cự ly xa. Vương Lâm thấy vòng xoáy lạ liền dùng lệnh bài động phủ thuấn di, né hụt cánh tay xương nhưng bị can nhiễu khiến truyền tống lệch sang đồng bằng Hỏa Yêu quận. Khi vòng xoáy lại đuổi tới, lần này hắn quyết ở lại đối đầu để xem cánh tay trong vòng xoáy có thần thông gì."},{"chuong":557,"tieuDe":"Thăng Tiên Quả","tomTat":"Vương Lâm vừa tiến Vấn Đỉnh, nguyên thần mới hình thành chưa kết hợp xong thì bị một cánh tay bộ xương bọc hộ uyển vung trảo tập kích cùng Thiên Ma Phong cuốn nửa nguyên thần muốn bay đi; hắn dùng sát tâm đập sát ý sinh sát khí kéo nguyên thần quay về rồi thi triển thần thông rút lui. Kẻ trong bảo tháp chiến trường viễn cổ lên tiếng tiết lộ tu sĩ Yêu Linh tu Cổ Yêu Thuật không sinh nguyên khí, chỉ khi tiến Vấn Đỉnh mới sinh, và hắn đã thôn phệ nguyên khí của hầu hết tu sĩ Yêu Linh đạt Vấn Đỉnh. Vương Lâm phát hiện một khu vườn được bảo vệ bằng hàng ngàn cấm chế, dùng thủ pháp phá tiên cấm xuyên qua, thấy đồng bằng trồng hơn một vạn cây Thăng Tiên Quả. Bộ xương cánh tay đuổi tới phá cấm chế; hắn dùng tiên kiếm chứa Hứa Lập Quốc cùng Ma Chỉ hấp thụ yêu lực làm bộ xương khô tan vỡ, nhưng ký hiệu hộ uyển kích hoạt dựng nhà lao ma lực nghìn trượng và sinh hắc ảnh một sừng Thiên Ma Loạn Vũ chui vào cơ thể. Để ép xuất hắc ảnh, Vương Lâm cô đọng hơn một vạn Thăng Tiên Quả thành một giọt đỏ như máu rồi nuốt, lấy hưng phấn và đau đớn cực điểm làm động lực. Hắn thi triển Hoàng Tuyền Chỉ bằng tu vi Vấn Đỉnh — dẫn động Ý Cảnh nguyên thần bao hàm Sinh Tử Luân Hồi, gần tiếp cận hạ phẩm tiên thuật Tiểu Thiên — làm phiến không gian sụp đổ và diệt hắc ảnh một sừng. Kẻ trong hắc tháp gầm rống phẫn nộ, ý chí lao ra dung nhập hư vô; Vương Lâm phong ấn hộ uyển bằng cấm chế mạng nhện cất vào túi trữ vật, chiến ý vẫn chưa tan khiến Hứa Lập Quốc run sợ."},{"chuong":558,"tieuDe":"Chương 558","tomTat":"Hai mắt Vương Lâm còn đỏ hồng sau khi hút một phần mười chất dịch Thăng Tiên Quả; dưới tu vi Vấn Đỉnh hắn vung trảo thu gần mười vạn Thăng Tiên Quả vào túi trữ vật, không áp chế nổi chiến ý và sát tâm. Một tiếng hừ lạnh từ đạo thần thức trong hắc tháp trên chiến trường viễn cổ đánh vào tâm thần khiến hắn phun máu, vết thương khơi dậy sát tính năm xưa từng làm Tu Ma Hải và Triệu Quốc run sợ — thứ đã bị xóa lúc hóa phàm nay thức tỉnh, khiến hắn nổi điên thay vì bỏ chạy. Vương Lâm phá nát mười vạn Thăng Tiên Quả dung hợp thành một giọt đỏ máu rồi nuốt, lại uống bốn trên mười giọt tiên dịch trong bầu rượu thu ở động phủ, tiên lực nổ như sấm sét trong kinh mạch nhờ Vấn Đỉnh cường hóa và Cổ Yêu thôi hóa năm xưa. Đạo thần thức trong hắc tháp công kích liên tục nhưng Vương Lâm không chết, sinh lòng lo sợ và hối tiếc đã đi hấp thu hắn. Vương Lâm gầm lên thi triển toàn lực Tịch Diệt, sóng Tịch Diệt làm mọi cỏ cây chim thú khô héo, sinh cơ hóa khí bạch sắc khôi phục nguyên thần và xác thịt đã tan vỡ. Tử Thử — Đô Thống Hỏa Yêu quận thuộc Thập Nhị Kiếm Tiếu Đại La Kiếm Tông — dẫn ba vạn Yêu binh thấy hắn điên cuồng vội lui tránh, sau khi thấy hắn phun máu thì hai mắt đột nhiên sáng ngời."},{"chuong":559,"tieuDe":"Chiến Ý","tomTat":"Thấy Vương Lâm trọng thương nặng, Tử Thử tham nguyên thần Vấn Đỉnh để dưỡng Kiếm Linh nên hạ quyết tâm liều mạng, hóa hư ảnh cùng ba vạn Yêu binh bày trận tập trung sát khí. Nhưng Vương Lâm chiến ý cuồng dại, đảo hướng lao tới chụp đại kiếm ném đi rồi điểm vai khiến Tử Thử héo rũ, nguyên thần hóa Sinh Chi Lạc Ấn dung nhập vào hắn; đạo kiếm khí kim quang sư tôn tặng Tử Thử còn chưa kịp dùng. Vương Lâm lao vào tàn sát sạch ba vạn Yêu binh, hấp thu các Sinh Chi Lạc Ấn để khôi phục thân thể sau nửa nén hương. Trong hắc tháp ở chiến trường viễn cổ, luồng thần thức người áo giáp phẫn nộ rồi hối hận khi nhận ra nhờ hấp thu nhiều Thăng Tiên Quả và thần thông hấp thu sinh cơ vạn vật, Vương Lâm không sợ chết mà ngày càng mạnh. Trên đường tiến về chiến trường viễn cổ, Vương Lâm giết hai đệ tử Anh Biến hậu kỳ của Mạc Tổ vì chúng tham đoạt Yêu Tinh, dù một kẻ van xin là đệ tử Mạc Tổ. Hắn thôn phệ sinh cơ vạn vật khiến đất đai cây cối khô héo, gây tử vong khổng lồ qua Hỏa Yêu quận và bị hơn mười Yêu tướng được phái ra vây bắt."},{"chuong":560,"tieuDe":"Có Sát Khí","tomTat":"Hỏa Yêu quận bày trận bao vây Vương Lâm tại Vạn Yêu sơn, dải núi ranh giới với Thiên Yêu quận; trong Thiên Dật Thành có mười vạn Yêu binh, hơn mười Yêu tướng và một Phó soái thần thái âm trầm tọa trấn theo lệnh Yêu Đế. Phó soái vốn có chuyện riêng muốn đến Thiên Văn Thành nên thấy phiền vì cho rằng diệt một tu sĩ Vấn Đỉnh trọng thương không cần lực lượng lớn. Yêu tướng Duẫn Đông xung phong xuất chiến, dồn Yêu lực hét lớn chấn nhiếp tinh thần cùng mười vạn Yêu binh trợ uy, nhưng luồng sát khí nồng đậm đó lại kích bùng chiến ý điên cuồng của Vương Lâm, khiến hắn lập tức điểm Tịch Diệt Chỉ giết chết Duẫn Đông. Vương Lâm ngửa cổ gầm Giết, hấp thụ khí sát lục triệu ba vạn Thương Long vờn quanh người như Ma Tôn hàng lâm. Mười vạn Yêu binh xếp trận hóa thành con bọ cạp hư ảo khổng lồ, nhưng nhờ Sát Lục Tiên Quyết và hiệu lực Thăng Tiên Quả, Vương Lâm vẫn áp đảo. Khi hơn mười Yêu tướng hợp công, hắn dùng tu vi Vấn Đỉnh thi triển Hoàng Tuyền Chỉ, hiện một dòng sông hoàng tuyền khổng lồ đục ngàu chứa lệ hồn dã quỷ giáng xuống như hồng thủy."},{"chuong":561,"tieuDe":"Mười Năm Giác Ngộ, Mười Năm Ngộ Đạo Hóa Hoàng Tuyền","tomTat":"Sau mười năm cảm ngộ cùng kích thích của Thăng Tiên Quả và tiên lực khổng lồ, Vương Lâm ngộ đạo, tự tay mở ra dòng sông Hoàng Tuyền và một luân hồi riêng không chịu quản lý của trời đất, trở thành đạo nhân tu đạo của chính mình và chạm tới bước thứ hai bên rìa thiên đạo. Hắn thu mười Yêu Tướng vào Hoàng Tuyền rồi phóng mười ba vạn khí sát lục đuổi giết Phó soái Hỏa Yêu quận, khiến vị này chết thành xác khô ngay trên truyền tống trận Đế Đô, chọc giận Yêu Đế ra lệnh truy sát bất kể thân phận. Trong bảo tháp chiến trường viễn cổ, chủ áo giáp ban ba kiện ma giáp biến lão già hắc y năm xưa cứu Hổ Bào thành Người hầu Tôn Ma, kẻ này liền triệu tập ba Yêu Vệ Phong Ngâm, Địa Ma và Hổ Bào để ngăn cản. Vượt Vạn Yêu sơn đến cánh đồng hài cốt, Vương Lâm bị Địa Ma vây trong quả cầu Thiên Trướng Địa Đông nhưng phá kén xuất thế với đôi mắt đỏ hồng, ba thanh vũ khí đồng xuất khiến lão già bị cắt ngón khi chộp tiên kiếm. Vương Lâm bóp nát kén ẩn thân, quất Côn Cực Tiên rồi dùng Chưởng ấn vô danh xuyên thân giết chết Phong Ngâm, khiến nhân vật trong hắc tháp lần hiếm hoi lộ sợ hãi vì nhận ra chưởng ấn ấy giống bảy phần thần thông của 'người kia'. Cuối cùng Hổ Bào dẫn hơn trăm ngàn hồn phách gào thét đến báo thù, hét tên Vương Lâm làm nguyên thần hắn hiện một tia thanh tỉnh, đồng thời trút hết oán hận và tuyên bố sẽ phong ấn hồn phách hắn, ném vào hắc lao cửu quận rồi hủy diệt cả Luyện Hồn bộ lạc."},{"chuong":562,"tieuDe":"Yêu Vệ","tomTat":"Hổ Bào bộc lộ hận thù và dã tâm, tuyên bố với Luyện Hồn thuật cùng trăm ngàn hồn phách sẽ đứng trên đỉnh vùng đất Yêu Linh và làm yêu đế đệ thập quận, khẳng định Vương Lâm phải chết. Vương Lâm vạch trần Hổ Bào tu một bộ công pháp thôi phát tiềm lực và sinh mệnh, đạt đỉnh điểm ngắn ngủi không quá một ngày. Khi Hổ Bào tung trăm vạn hồn phách rồi dùng thần thông Ức Hồn Thôn Phệ, Vương Lâm phát động chỗ thiếu sót năm xưa lưu trên Luyện Hồn thuật, đoạt quyền khống chế tuyệt đối mọi hồn phách khiến chúng nhận hắn là chủ nhân chân chính. Vương Lâm giải thích mình là đích hệ truyền thừa Luyện Hồn tông, thuật đã cải tiến vạn năm không thể bị trọng tổ. Hắn lấy Thập Ức Tôn Hồn Phiên dung hợp hồn phách thành một hồn, cách không đánh một quyền khiến hồn phách Hổ Bào tứ phân ngũ liệt rồi thu vào phiên. Hứa Lập Quốc trong kiếm tiên nghe cuộc đối thoại, thầm khinh Hổ Bào không biết trời cao đất rộng. Cuối chương Vương Lâm phát hiện tòa hắc tháp tỏa ma khí chân chính cùng lão giả áo giáp đen đứng dưới, nhận định là tuyệt đại cường giả, đồng thời biết nguyên thần chưa dung hợp hoàn toàn nên cần nửa tháng đạt Nguyên Nhục Quy Nhất mới củng cố chân chính Vấn Đỉnh kỳ."},{"chuong":563,"tieuDe":"Thanh Tỉnh","tomTat":"Vương Lâm đối mặt một hắc giáp lão giả bước ra từ dưới hắc tháp. Sự điên cuồng của Thăng Tiên quả phản công, ý đồ thay thế thần thức của hắn, nhưng Vương Lâm hai lần áp chế nó xuống, khôi phục tâm trí thanh tỉnh. Hắn xuất hai đại tuyệt kỹ — đạo Hóa Hoàng Tuyền và kiếm khí Lăng Thiên Hậu — nhằm chấn nhiếp chứ không đối chiến. Lão giả đánh giá Hoàng Tuyền chỉ là vỏ ngoài còn kiếm khí Lăng Thiên Hậu ắt do tuyệt đại cường giả mức toái niết tam cảnh phát ra. Một thần niệm khổng lồ từ trong hắc tháp lao ra hỏi nguồn gốc chưởng ấn, Vương Lâm đáp học từ tiên giới, thần niệm liền ra lệnh bắt sống rồi thu vào tháp. Hắc giáp lão giả nhờ Sáo Tiêu giáp đạt Vấn Đỉnh hậu kỳ, thi triển liên tiếp Phong, Lôi, Vũ, Điện; Vương Lâm dùng Hoàng Tuyền hà và Nhất Chỉ Hoàng Tuyền chống đỡ khiến Hoàng Tuyền sụp một phần ba. Vương Lâm bước vào Hoàng Tuyền hóa thân Hoàng Long, xuất Tôn Hồn Phiên dung nhập một trăm ngàn hồn phách cùng mười ba vạn đạo sát lục chi khí, ngưng hóa thành Hoàng Tuyền chi hồn mang đầy sát khí."},{"chuong":564,"tieuDe":"Ngưng Hóa Tuyền Hồn","tomTat":"Vương Lâm thi triển Hoàng Tuyền chân chính ẩn chứa mười ba vạn sát lục chi khí và trăm ngàn hồn phách, lao vào thần thông Phong Vũ Lôi Điện của hắc giáp lão giả khiến viễn cổ chiến trường rung chuyển. Hắn vung Tôn Hồn Phiên hóa hắc bố che trời hút vô số hồn phách bổ sung Hoàng Tuyền. Lão giả luyện ma đao bằng Ma đạo, ma ảnh đầu một sừng dung nhập biến thành ma đao bắn tới. Vương Lâm ngưng kiếm khí Kiếm Tôn Lăng Thiên Hậu trên đầu ngón tay, khiến thiên địa ngừng lại, phá tan ma đao rồi đánh nứt hắc tháp dù tháp không sụp. Sợ điên cuồng chiếm tâm thần sẽ chết, hắn thừa cơ rút lui; lão giả phun máu, hấp thụ ma khí từ hắc tháp phồng lớn thành người khổng lồ ba trượng mọc hắc giác, không còn là người, đuổi theo. Cuối cùng Vương Lâm phân một đạo thần thức nhảy vào túi trữ vật, tới tiểu cầu cấm chế giam Diêu Tích Tuyết, dọa dung nhập nàng vào hư vô để ép nàng khai phương pháp sử dụng Huyết Hồn đan."},{"chuong":565,"tieuDe":"Huyết Hồn Đan","tomTat":"Bị hắc giáp lão giả cùng hắc tháp truy sát, Vương Lâm tra khảo Diêu Tích Tuyết để đoạt phương pháp dùng Huyết Hồn đan, rồi bố trí giọt máu lam làm vật dẫn nguyên thần trước khi liều mình. Hắn tự bạo Vấn Đỉnh kỳ với bốn giọt tiên dịch trong người khiến uy lực vượt xa thường, xé tan thân lão giả và đánh sập hắc tháp bằng một quyền dung chứa đạo niệm cùng Cổ Thần chi niệm, lợi dụng vết nứt kiếm khí Lăng Thiên Hậu để lại. Nhờ Huyết Hồn đan, giọt máu lam ngoài ngàn dặm hồi sinh thân ảnh Vương Lâm, hắn lập tức thi triển liên tục Đại Na Di bỏ chạy về Thiên Yêu thành và bất ngờ phát hiện tiên lực tự hồi phục tức thì do tiên dịch đã dung nhập cơ thể. Bạch giáp lại tìm chủ mới là một đại hán tóc dài hoa văn tử kim ẩn trong trận pháp dưới tháp, còn một đại hán khải giáp mang ma hồn, tướng mạo giống Lăng Thiên Hậu, đuổi theo truy sát. Vương Lâm dùng tên Lăng Thiên Hậu kích cho đối thủ mê man nhưng ma hồn nhanh chóng áp chế, buộc hắn phải kêu cứu Cổ Yêu, kẻ trách hắn đến chậm mười năm rồi mượn máu ngưng thành nhân hình Bối La để giáng ý chí. Bối La dùng Cổ Thần ngữ vạch mặt kẻ địch là một trong cửu tán ma dưới trướng cổ ma, giăng yêu mạc che phủ toàn thành và đại chiến ba ngày. Vương Lâm vừa thổ nạp hồi phục vừa lĩnh ngộ Cổ Thần thuật từ ký ức Đồ Ti, dẫn động bản tôn tóc hồng nơi tiểu tinh xa xôi hút linh lực, rồi bày Hoàng Tuyền ném gần hết pháp bảo để cô đặc thành hoàng mang cùng mười ba vạn sinh chi lạc ấn. Phối hợp với Cổ Yêu chi mang có thể luyện hóa vạn vật, hai bên đánh trọng thương tán ma, nhưng ma hồn bỏ xác đại hán chui vào áo giáp, giữ lại chín phần ma khí mà đào thoát."},{"chuong":567,"tieuDe":"Đại Công Cáo Thành","tomTat":"Tại Vân Thiên Tông, một ông già kể cho cháu trai nghe truyền thuyết về người được tạc tượng: tu đạo hai trăm năm mà gây bão táp khắp Chu Tước tinh — loạn Tu Ma Hải, cứu mỹ nhân Vân Thiên Tông, tàn sát nước Triệu và diệt nhà họ Đằng, vào Tiên giới chém Hồng Điệp, bại Liễu Mi, đánh Kiền Phong, bái Độn Thiên làm sư, đuổi Tuyết Vực, diệt Cự Ma lão tổ, đoạt danh hiệu đệ nhất Chu Tước Tinh. Người đó tên Vương Lâm, đã cự tuyệt kế vị Chu Tước và nhường ngôi cho Chu Vũ Thái rồi rời đi không rõ tung tích. Chu Như cưỡi hổ Tiểu Bạch lên Vân Thiên Tông bái biệt pho tượng, khoe vừa Kết Đan và quyết tu tới Nguyên Anh để nhận túi trữ vật mà Thiết Nham đang giữ. Thiết Nham — người được Vương Lâm chỉ điểm đột phá Hóa Thần năm xưa — ân cần tiễn nàng đi núi Chu Tước. Trong khi đó, tại động phủ ngầm dưới Long Đàm thành Thiên Yêu, Vương Lâm ngồi mấy tháng dùng cấm chế và lạc ấn nguyên thần khống chế một Tán ma khổng lồ, trước mặt là đại hán giống Lăng Thiên Hậu đang hồi phục trong thủy tinh tím. Nhận ra tu vi chưa đủ để nuốt, hắn định dần khống chế Tán ma rồi dùng nó làm phôi thể luyện Nguyên thần thứ hai — thần thông sau cảnh giới Vấn Đỉnh."},{"chuong":570,"tieuDe":"Kiếm Khí Của Tử Thử","tomTat":"Vương Lâm xuất quan, cảm nhận sát khí đại quân Cổ Yêu khiến trời đất âm u; hắn xác định mục tiêu giết đệ tử Kiếm Tôn để thu mười đạo kiếm khí còn lại, luyện hóa khí sát lục để sống yên ổn ở vùng Yêu Linh. Bay tới tòa lầu các di chuyển theo đại quân, hắn gặp lại thanh niên từng uống rượu năm xưa, nhìn ra viên yêu tinh trong đan điền và xác nhận đối phương chính là Yêu Đế Cổ Vân Phong; hai bên thừa nhận địa vị tương đương. Hứa Lập Quốc ly khiếu ra ngoài đòi gặp kiếm linh Đế kiếm, khiến Song nhi — cháu gái Yêu Đế — oán hận thúc giục Đế kiếm phóng kiếm khí công kích. Với tu vi Vấn Đỉnh, Vương Lâm hừ lạnh chấn vỡ toàn bộ kiếm khí, vượt xa thuở Anh Biến hậu kỳ; Yêu Đế thu Đế kiếm về. Hỏi tung tích Mặc Phi, Vương Lâm biết hắn nay là Phó soái ở thành Tùng Đào quận Hỏa Yêu, và nhận ngọc giản trắng cho phép điều động Thiên soái cùng thân phận sứ giả Tổ Linh. Cổ Vân Phong tỏ thiện ý xem hắn là người cùng đường, còn đại quân cánh tả quận Thiên Yêu thẳng tiến thành Tùng Đào."},{"chuong":571,"tieuDe":"Ba Đạo Kiếm Khí","tomTat":"Đại quân yêu binh quận Thiên Yêu do ba chính soái Thiên, Trụ, Hoang và phó soái Mặc Phi (cánh quân phải) dẫn dắt tiến công thành Tùng Đào; phía sau Mặc Phi là người trung niên đeo kiếm lớn tên Hợi Trư. Vương Lâm cải trang áo giáp đen như Ma Tôn giáng lâm trong sét, mượn lệnh Yêu Đế tuyên bố bắt giết Mặc Phi và ném ngọc giản Yêu Đế ngăn hai chính soái Trụ, Hoang. Hắn dùng hư chiêu Tịch Diệt chỉ đánh lừa rồi Na Di chí mạng, Hoàng Tuyền dựng lên trấn áp khiến Hợi Trư không kịp thi triển kiếm khí Lăng Thiên Hậu, điểm một chỉ giết chết, cắt đầu luyện hóa và bắt thanh Khuyển kiếm. Sưu hồn nguyên thần Hợi Trư ném vào Hồn phiên làm chủ hồn, Vương Lâm biết Đại La Kiếm Tông còn có Tham Lang đạt Âm Hư chi cảnh âm thầm bảo vệ — tướng mạo quen mắt dù chưa từng gặp. Cái tên Tư Đồ Nam khiến hắn lấy ngọc giản cũ ra, nghi Tham Lang là kẻ thù năm xưa của Tư Đồ Nam và có thể biết bí mật Thiên Nghịch Châu. Hắn lo lắng độ khó viên mãn Kim thuộc tính cuối cùng và việc hạt châu đã dung hợp Nguyên thần không thể chia lìa."},{"chuong":573,"tieuDe":"Tiên Đế Thanh Lâm","tomTat":"Vương Lâm càng ở đất Yêu Linh càng thấy nơi này quỷ dị: bức tranh Hoàng Long, người giống Mặc Phi, người đàn ông vạm vỡ giống Lăng Thiên Hậu, khiến hắn ngờ Thiên Vận Tử cố ý dẫn hắn vào với mục đích khác, liên hệ tới việc đệ tử Thiên Vận Tử mất tích mà Bạch Vi từng nói. Hắn quyết giữ vững đạo tâm bằng thực lực, ở trong tháp trung tâm mười năm không ra, được bộ lạc Luyện Hồn tôn làm Lão tổ. Trong mười năm hắn củng cố lạc ấn trên Tán ma, thôi diễn 9999 tổ hợp cấm chế dung nhập Cấm phiên, và tản Tôn Hồn Phiên thành mây đen mười vạn hồn phách phủ bầu trời bộ lạc. Hắn dồn tâm tư vào năm đạo phong ấn trên Xạ Thần Xa, phán đoán đạo thứ hai phong hồn thú Lôi với lôi quang truy đuổi. Biết mở đạo này sẽ khiến Khu Thú Quyển sụp đổ, hắn quyết kế thừa phương pháp người chế tạo để bảo tồn bảo vật. Vương Lâm dịch chuyển ra ngàn dặm, triệu Xạ Thần Xa, đè hồn thú thân trăm trượng, cắn ngón tay vẽ huyết phù vào mi tâm nó rồi quát mở Đạo phong ấn thứ nhất, đánh vỡ miệng hồn thú khiến thân nó hóa ánh sáng đen chui vào da hắn tới Nguyên thần — hắn cười lạnh, mắt tỏa một luồng ánh sáng chói."},{"chuong":574,"tieuDe":"Đạo Phong Ấn Thứ Hai","tomTat":"Vương Lâm dùng Nguyên thần Xuất khiếu bắt cổ hồn thú trong Xạ Thần Xa thứ hai, in liên tiếp các đạo huyết phù dung hợp khí Nguyên thần để kích nó tiến hóa, có lúc bị khí tức con thú đánh văng thần thức. Ở vùng biên giới quận Hỏa Yêu và Kim Yêu, trong tòa thành trắng giữa chướng khí, một Lão tổ dáng người cực thấp bé nghe thuộc hạ bẩm báo đã tra ra vị trí Vương Lâm — kẻ mất tích ở quận đô thành Cổ Yêu hai mươi năm trước, nay làm sứ giả Cổ Yêu — rồi phái ba tiểu đội thêm một Tiên vệ đi bắt để luyện thành Tiên vệ mới. Vương Lâm bấm pháp quyết hô mở đạo phong ấn thứ hai; hồn thú khí tức dâng tới đỉnh, lôi điện đánh xuống bao quanh, hóa thành Lôi Thú mọc sừng bạc — loài hiếm hơn kỳ lân tiên giới. Hắn thoáng thất vọng vì ngọc giản nói mở hoàn mỹ phải ra sừng vàng, nhưng khi tạo huyết phù thứ tư in lên mi tâm để hạ lạc ấn lại thoáng thấy tia sáng vàng trên sừng rồi biến mất. Lôi Thú biến vào Xạ Thần Xa, được thu vào túi trữ vật. Vương Lâm tự lượng định Lôi Thú đủ chọi Vấn Đỉnh trung kỳ nhưng vẫn e ngại Vấn Đỉnh hậu kỳ như Chu Tước tử và lão già áo đen. Cuối cùng hắn thuấn di về bảo tháp bộ lạc Luyện Hồn, suy ngẫm về cảnh giới Vấn Đỉnh và các pháp bảo nghịch thiên như kiếm khí Lăng Thiên Hậu hay đệ tứ hồn năm xưa, rồi khoanh chân ngồi trầm tư."},{"chuong":576,"tieuDe":"Xuống Dưới Cho Ta!","tomTat":"Vương Lâm khảo sát cấm chế Tiên chủng (vân xanh) trên người Tôn Vân Sơn, xác nhận đó là vật Tiên giới của Lão Tổ liên minh, đồng thời suy đoán liệu Lão Tổ có phải Tiên đế Thanh Lâm. Hắn Sưu hồn Tiên vệ áo đen, phát hiện tu vi Vấn Đỉnh chỉ là giả do Toái ngọc ban, thật chỉ Anh Biến trung kỳ, rồi luyện hóa Nguyên thần thu được mảnh Toái ngọc chứa tiên lực kèm một đạo ý niệm; từ đó đoán ra bí mật dung hợp Toái ngọc tạo tu sĩ Vấn Đỉnh sơ kỳ. Tôn Vân Sơn khai căn cứ Liên minh nằm ở vùng chướng khí giao giới phía bắc Hoả Yêu Quận và Kim Yêu Quận, cảm tạ và được Vương Lâm đưa ngọc giản phòng thân. Vương Lâm cuốn Tôn Vân Sơn cùng hơn mười tu sĩ rời Luyện Hồn bộ lạc, tới vùng chướng khí rồi một mình bước vào để diệt Lão Tổ vì đã hai lần bị trêu chọc. Trong tòa thành giữa chướng khí, một lão già thấp bé đang hút tinh khí ba nữ tử tuyệt trần (gồm Tôn Nhược Nam), khiến họ mệt mỏi và già đi. Lão phát giác Vương Lâm, thi triển Hồn Phách thuật, nhưng Vương Lâm hô Hồn Tuyền hút sạch toàn bộ chướng khí thành đoàn khí mật độ cực cao, khiến căn cứ lần đầu lộ ra dưới ánh mặt trời."},{"chuong":577,"tieuDe":"Vật Của Tiên Giới","tomTat":"Vương Lâm ngưng hoá sương mù áp tới một toà thành màu trắng, đại bản doanh của Lão Tổ Liên minh. Hơn trăm tu sĩ phiêu phù bên ngoài khiếp sợ né tránh; một thanh niên Tu sĩ Liên minh quát hỏi tên liền bị ánh mắt sát nhân của Sát lục tiên quyết làm trào máu, mở thẳng một con đường tới thành. Đệ tử Lam hệ Thiên Vận Tông nhận ra Vương Lâm từ trận tranh đoạt phong hiệu Thiên Vận Thất tử, chấn động khi cảm nhận trên thân hắn mơ hồ có khí giống Thiên Vận Tử — chứng tỏ Vương Lâm đã nắm giữ đạo của chính mình, đủ tư cách khai tông lập phái, từ man nhân tàn phế Chu Tước Tinh vươn lên thành nhất đại tông sư. Lão Tổ ra lệnh giết, một Tiên vệ áo đen hoá mãnh thú nuốt Vương Lâm nhưng bị một chỉ Tịch Diệt phá toái, giết tức khắc. Tôn Nhược Nam nhận ra và gọi tên Vương Lâm, khiến Lão Tổ động lòng muốn giảng hoà thả đi. Vương Lâm cự tuyệt, gọi hai Tiên vệ đã giết chỉ là hai khối Toái ngọc; Lão Tổ nổi giận triệu tám Tiên vệ và Tiên đế ra giết, tám thân ảnh Vấn Đỉnh kỳ khoanh chân kết ấn quyết theo trận pháp."},{"chuong":578,"tieuDe":"Nhất Đại Tông Sư!","tomTat":"Tám Tiên vệ tán phát tiên lực dung hợp thành hư ảnh “Tiên Đế” mặc tiên bào tay cầm trường kiếm xanh, đám tu sĩ quỳ tham kiến. Từ Toà thành màu trắng, một lão già tự xưng vốn là người Tiên giới phá toái lưu lạc đến đây, khoe thần thông đều là Tiên thuật chân chính và dụ Vương Lâm rời đi kẻo chết. Vương Lâm nâng tay tung Hoàng tuyền nghênh chiến, đạo tâm kiên định ấp chế áp lực kiếm cùng tiếng vô thanh hoá tiếng sấm, hạ chân đạp vỡ ảo thuật khiến tám Tiên vệ m��t thần thái. Hắn xuyên qua Hoàng tuyền giết tám Tiên vệ đẩy vào Luân hồi, thu tám khối Toái ngọc rồi quét sập Toà thành màu trắng. Lão già thấp bé cùng ba nữ tử đồng tu lộ diện, phun tiên vụ triệt tiêu Tịch Diệt chỉ phong của Vương Lâm. Lão liều mạng thả Tiên thú chi lương — khối ngọc xanh hoá vô số sợi tơ — nhưng Vương Lâm gọi đúng tên, nhận ra thứ từng gặp ở động phủ năm xưa và trên người Tôn Vân Sơn, khiến lão kinh hãi. Vương Lâm triệu đầu Kỳ Lân thú trong Hồn Phiên, thiên địch của Tiên lương khiến nó run rẩy không dám chạy rồi bị hút sạch, lão già choáng váng há hốc mồm."},{"chuong":579,"tieuDe":"Tiên Thú Chi Lương","tomTat":"Kỳ Lân thú của lão già thấp bé ăn Tiên lương trên mi tâm các tu sĩ mà vẫn chưa no, lão liền rút ra cây Toả Thần bút — bút lông Tiên giới thân trong suốt, đầu lông trắng, tản uy nghiêm áp cả Kỳ Lân thú. Vương Lâm nói toạc bí mật lớn nhất của lão: dù là Vấn Đỉnh trung kỳ nhưng giống Tiên vệ, lão không hề có nguyên lực. Lão thẹn quá hoá giận, phun tiên huyết vẽ phù văn phản công, nhưng Vương Lâm nhận ra phù văn này giống đúc phù văn trên Tôn Long chi lộ nên sinh ham muốn mãnh liệt đoạt bút, triệu Lôi thú từ Xạ Thần xa dẫn Thiên lôi đánh sụp phù văn. Lão lộ bản tính nhát gan, bỏ chạy qua hơn mười loại thần thông độn thuật nhưng bị Vương Lâm dùng Na Di thuật chặn đầu ngoài ba vạn dặm. Cùng đường, lão ném Toả Thần bút vào hư vô; Vương Lâm sai Hứa Lập Quốc dẫn Tiểu hắc tử đuổi theo cây bút. Bị Đại Na Di thuật ép sát, lão đành rút Khốn Tiên võng — tấm lưới xanh Tiên giới mà lão khống chế còn kém hơn, van cầu nó đừng trói mình vì thấy quá mức quỷ dị."},{"chuong":583,"tieuDe":"Thân Phận Của Nữ Thi Áo Trắng","tomTat":"Trong bảy Quận của Yêu Linh, chỉ đầu lĩnh hai Quận Thuỷ Yêu và Lôi Yêu lấy Luyện Hồn bộ lạc làm mục tiêu, mỗi bên tách mười vạn yêu binh do một Phó soái dẫn đầu vây hai phương Nam–Bắc. Lôi Suất, tráng hán lôi hệ duy nhất không mặc giáp, tung quyền Lôi Long phá một lỗ hổng trên màn sương đen Tôn Hồn Phiên, chống lại đạo hắc khí do Âu Dương Hoa chỉ huy tộc nhân phóng ra, rồi tiến vào bộ lạc. Nữ Phó soái Thuỷ Yêu Quận và Lôi Suất ước định: Lôi Suất lấy dị bảo, Thuỷ Yêu Quận bắt tộc nhân về nghiên cứu. Khi Lôi Suất định huỷ toà tháp thờ phụng ở trung tâm, một tiếng ‘Định’ từ trong tháp khoá cứng hắn; Vương Lâm áo trắng tóc dài bước ra, vung tay áo đánh hắn phun máu văng khỏi bộ lạc. Trước trận pháp Thuỷ Yêu Quận, Vương Lâm lần đầu toàn lực thi triển Định Thân thuật ‘một chữ Định, thiên địa bất động’, định trụ toàn bộ yêu binh bên ngoài. Tộc nhân Luyện Hồn bộ lạc lao ra tàn sát, màn sương đen Tôn Hồn Phiên từ trời giáng xuống bao phủ bốn phía; nữ Phó soái Thuỷ Yêu Quận bị định nhưng sau ba tức loé lam quang thoát ra, kinh hãi xoay người bỏ chạy."},{"chuong":584,"tieuDe":"Xuất Quan","tomTat":"Ba đạo kiếm quang cùng ba hồn thú Tử Thử, Hợi Trư, Mạt Dương của Vương Lâm hạ sát một nữ tử, Tử Thử Tà hồn ngậm giữ hồn phách nàng; Vương Lâm dửng dưng cảm ngộ Tiên thuật giữa không trung nhưng vì ngày ước định với Cổ Yêu đã cận kề nên quyết định rời đi. Một tháng sau hắn rời Luyện Hồn bộ lạc, mang theo Tôn Hồn Phiên và để lại một đạo thần thức thủ hộ, ghé Động phủ ghi nhớ mười một phù văn ở Tôn Long chi lộ (vốn mười hai đạo, còn thiếu đạo cuối) rồi thi triển Đại Na Di tới Hoả Yêu Quận. Nơi đây chiến hoả ngập trời, tử chiến trăm năm với Thiên Yêu Quận theo kiểu một mạng đổi một mạng, đế đô trống không chỉ còn Thánh địa Yêu Cốc và bị Cổ Yêu phong ấn bằng yêu mạc mười dặm. Vương Lâm bước vào đế đô thử phá phong ấn nhưng bị phản lực đánh văng, đụng độ thần thức Cổ Yêu Hoả Yêu Quận quát “Cút!” rồi bị hắn dùng ấn quyết yêu khí hoá giải. Hắn tuyên bố với Bối La rằng bước đầu của ước định khỏi phải chờ nữa, thốt “Sát lục khí, tụ!” khiến tộc nhân Luyện Hồn bộ lạc ẩn khắp Hoả Yêu Quận thoát sát khí, mười vạn đạo Sát Lục khí ngưng gần thành thực chất tụ về hắn. Cuối cùng hắn thốt “Phân!”, mười vạn đạo tách đôi liên tiếp hơn mười lần, biến thành trăm vạn đạo phủ kín thiên địa."},{"chuong":589,"tieuDe":"Phát Sinh Rạn Nứt Với Thiên Vận Tử","tomTat":"Tại Vân Vụ sơn hải của Thủy Yêu quận, Đỗ Kiến — xích hệ đệ tử của Thiên Vận Tử — dẫn Mộ Dung Trác cùng hai nữ tử Phù Vân phái là Triệu Y Huyên và Từ Phi tới khám phá một vết nứt trong vân hải, nghi chính là Triều Tịch thâm uyên trong lời đồn. Mộ Dung Trác bất ngờ cảnh báo Rất mạnh, rồi Vương Lâm với tu vi Vấn Đỉnh sơ kỳ phá không xuất hiện. Vương Lâm nhận ra Đỗ Kiến là xích hệ đệ tử quen cũ và đặc biệt lưu tâm thần thông phát hiện ngoài ngàn dặm của Mộ Dung Trác. Trong màn giới thiệu danh tính, Mộ Dung Trác nói câu dài bất thường để bày tỏ tôn kính ngầm với Vương Lâm, còn cái tên Từ Phi gợi hồi ức cho Vương Lâm song hắn xác nhận không quen biết. Đỗ Kiến rủ kết bạn cùng vào thâm uyên, bề ngoài ôn hòa nhưng trong lòng đầy đố kị ác ý vì lo Vương Lâm sẽ tranh địa vị tử hệ. Vương Lâm sớm nhìn thấu thâm ý đó nhưng vẫn đồng ý phối hợp. Cả nhóm tiến vào sơn hải, và Triệu Y Huyên thừa nhận Vương Lâm là người thứ ba hơn trăm năm nàng không nhìn thấu nội tâm, cùng với Thần Long của Đại La Kiếm Tông và Mộ Dung Trác."},{"chuong":591,"tieuDe":"Tự Tìm Đau Khổ","tomTat":"Đỗ Kiến phun tiên huyết hóa vô số hạt huyết và ném bướu thịt ô uế chi nhục tự nổ, nhưng Vương Lâm dùng Hoàng Tuyền cuốn sạch rồi phong ấn nguyên thần Đỗ Kiến, dùng Cấm Phiên thu hắn vào túi trữ vật. Vương Lâm điểm Tịch Diệt Chỉ phá kim phù chứa phi trùng khiến Mộ Dung Trác gọi là “vô thị thần thông”; khi thử một tia kiếm khí Lăng Thiên Hậu, phi trùng chỉ run mà không chết khiến hắn kinh ngạc. Bốn người tiếp tục hạ xuống Triều Tịch thâm uyên, Vương Lâm dùng thủy tinh của Bối La dò đường và nhận ra Triệu Y Huyên cùng Từ Phi là người Thi Âm Tông nhưng chọn không vạch trần. Tới gần đáy thâm uyên, Bối La cảm ứng được bản thể Chu Dật mà chưa định vị; Vương Lâm cáo từ Mộ Dung Trác với lời kết giao hiếm có, truyền âm cảnh báo đề phòng nhị nữ, trong đó một người đã thi thể phụ nguyên thần. Khi rời đi, Từ Phi cài một sợi tóc lên vách khe để do thám, nhưng Vương Lâm triệu sợi tóc về, đốt lục hỏa thổi tan đạo thần thức bên trong khiến nàng chảy huyết và lộ vẻ kinh hãi."},{"chuong":594,"tieuDe":"Cứu Chu Dật","tomTat":"Vương Lâm dồn toàn lực phá ba đợt thần niệm Lăng Thiên Hậu canh giữ khe sâu Triều Tịch vực: hắn dùng Hoàng Tuyền, hóa Trăm vạn sinh ấn thành khí giết chóc và thúc Lôi thú công kích, cố tình không xuất kiếm khí của Lăng Thiên Hậu vì sợ bị đoạt. Chấn động lan khắp Triều Tịch v���c và Thủy Yêu quận khiến Mộ Dung Trác cùng Từ Phi dưới vực kinh hãi, còn Tham Lang ở Hỏa Yêu quận và phân thân Lăng Thiên Hậu ở Đại La kiếm tông đều cảm nhận biến động. Chui qua lỗ hổng thần niệm vào sâu trong khe, Vương Lâm rút tiên bút vẽ ký hiệu bảy nét — mỗi nét rút một tia nguyên thần — nhưng ký hiệu vỡ khi đụng kiếm khí Lăng Thiên Hậu, hắn phun sáu ngụm máu, mất sáu trong bảy đạo nguyên thần. Hắn gặp linh thể tím của Chu Dật bị phong ấn trong Luyện Tiên Hóa Ma đại trận bốn kiếm Nguyên Thần, bị yêu khí Cổ Yêu gặm nuốt. Chương hé lộ ân oán: Chu Dật vốn là kiếm linh Vũ chi tiên kiếm truy đuổi Lăng Thiên Hậu từ tiên giới, làm đối phương bị thương bằng Tiên ấn, nên bị dẫn về Yêu Linh giao dịch với Cổ Yêu để phong ấn. Chu Dật tỉnh dậy từ chối được cứu nhưng phóng một đạo bản mệnh kiếm khí phá quả cầu thứ tư, hồi phục nguyên thần cho Vương Lâm. Vương Lâm ném trả Bảo tháp thần thức và tiết lộ nữ nhân Chu Dật si mê tên thật là Thanh Sương chứ không phải Đình nhi, khiến linh thể Chu Dật chấn động, ánh mắt hóa hung dữ."},{"chuong":595,"tieuDe":"Tâm Tử","tomTat":"Vương Lâm trả ngọc giản của Thanh Lâm cho Chu Dật; xem xong, Chu Dật đau khổ nhận ra Đình nhi chính là Thanh Sương — nhi nữ tiên đế Thanh Lâm, cường giả đệ nhất Tiên giới đang tương truyền ẩn náu chữa thương ở mảnh đất Yêu Linh. Hy vọng cứu được nàng khiến tâm đã chết của Chu Dật sống lại, bức tử khí toàn thân tản ra, thân thể trở nên trong suốt. Hắn dung nhập thanh kiếm tiên, dùng bản mệnh kiếm khí đập vỡ ba quả cầu thần niệm, làm tan bốn thành kiếm Nguyên Thần và phá trận pháp phong ấn của Lăng Thiên Hậu, thoát khỏi cái khe cùng Vương Lâm. Chu Dật giao bảo tháp nhờ Vương Lâm giữ, nhắc lại Vấn Đỉnh chi tinh năm xưa là thù lao bảo vệ Đình nhi. Hắn truyền kiếm ý viễn cổ vào Hứa Lập Quốc, biến hắn thành kiếm linh phục vụ Vương Lâm và cài lạc ấn phòng phản bội, tự thân tổn thương linh thể. Cuối cùng Chu Dật chỉ cầu Vương Lâm tìm được phụ thân Đình nhi để nàng thức tỉnh, rồi vỗ mạnh lên thân kiếm tiên khiến luồng khí kỳ dị tỏa ra, sắc mặt tái nhợt, thân hư ảo nửa ngày — Vương Lâm kinh ngạc kêu thất thanh."},{"chuong":596,"tieuDe":"Bản Mệnh Kiếm Khí Của Chu Dật","tomTat":"Chu Dật lấy thân phận kiếm linh và người thừa kế kiếm ý viễn cổ, phá lạc ấn như Hoàng Đế ban thánh chỉ, tách một trong bốn thanh Vũ tiên kiếm trao vĩnh viễn cho Vương Lâm — từ nay kiếm linh khác, kể cả nữ thi áo trắng nếu thức tỉnh, cũng không điều khiển được thanh này. Hắn còn cho Hứa Lập Quốc lĩnh hội truyền thừa kiếm ý viễn cổ, đưa Hứa Lập Quốc thành kiếm linh đời thứ nhất của thanh kiếm này; hai đại lễ cho Vương Lâm cơ hội luân hồi không diệt. Chu Dật dẫn Vương Lâm xuống đáy Triều Tịch vực tìm hơi thở một đời kiếm linh để ban lễ vật thứ ba, Vương Lâm thu Hứa Lập Quốc đang mê man vào kiếm tiên rồi đuổi theo. Tại đáy vực, Vương Lâm quan sát hố sâu năm-ngàn-năm bộc phát, đoán đó là nguồn thủy triều Đông Hải và cảm thán bản thân bé nhỏ. Bức tranh thần bí lấy ở Chu Tước tinh bỗng t�� mở, hiện bóng nữ tím giục “Đi xuống”, khiến Vương Lâm ngờ trong hố có thứ liên quan đến bức tranh. Sương mù tím quái dị tràn ra cản thần thức, ảnh hưởng tâm thần; Vương Lâm suýt nguy, đứng lên kiếm tiên ngưng thần xua sương, được Chu Dật hóa cầu vồng phá sương tăng tốc tới hơi thở một đời kiếm linh."},{"chuong":600,"tieuDe":"Cơ Trí Của Vương Lâm","tomTat":"Vương Lâm xác nhận đối phương có việc cần tới mình; Tham Lang ba lần định ra tay bắt hắn đều bị một đạo thần thức ẩn trong sương cảnh cáo nên do dự bỏ qua. Thần Long hé lộ Tham Lang là tiền bối đồng lứa sư tôn, bị thương nên tu vi chỉ còn Vấn Đỉnh kỳ đại viên mãn khiến nhóm kẹt mấy trăm năm, rồi đề nghị hợp lực phá vây xông qua đàn yêu thú. Cả nhóm tiến vào sương tím mà ai cũng đề phòng nhau: Vương Lâm vận Sinh ấn, Thần Long phòng đánh lén, Ngọ Mã nhìn âm độc. Tới gần bờ sương, Vương Lâm chấn động nhận ra vô số Văn thú quen thuộc từ thế giới truyền thừa Cổ thần, còn Văn thú của hắn thì bay ra hòa vào đàn đồng loại. Tham Lang lộ bẫy, dùng tiểu đỉnh phun khói tím kích động đàn Văn thú khiến sương tím thu về, tuyên bố đợi trăm năm cuối cùng đã tới ngày này. Tử khí ăn mòn sinh ra ở rìa kẹt lại đệ tử Đại La kiếm tông, hấp thu cả kiếm khí Lăng Thiên Hậu; Vương Lâm từ chối ra tay cứu và tự thoát thân khỏi sương tím cùng kiếm tiên Chu Dật. Cuối chương Thần Long hối hận đã do dự không sớm phản bội Tham Lang, e toàn bộ sư đệ đều diệt vong."},{"chuong":601,"tieuDe":"Quyết Đoán","tomTat":"Trong làn sương tím co lại nhanh và Tử khí bên ngoài càng đậm, Vương Lâm nhìn thấy cơ hội từ bốn đạo kiếm khí Lăng Thiên Hậu và năm bảo kiếm của đệ tử Đại La. Thần Long sau trăm năm do dự quyết đoán bỏ rơi sư đệ, phóng đạo kiếm khí bản mệnh tạo lỗ hổng nhỏ rồi một mình đột phá ra. Bốn đệ tử còn lại tuyệt vọng; Vương Lâm nhờ Chu Dật định vị rồi trong mười lần hô hấp chém đầu kẻ Anh Biến trung kỳ, điểm chết Tị Xà, giả giọng Tuất Cẩu lừa rồi giết Ngọ Mã, đoạt ba kiếm hai đạo kiếm khí. Chu Dật cưỡng chế đưa Vương Lâm hóa kiếm quang bay ra khỏi sương tím. Ngoài sương, Thần Long chém giết bầy Văn thú và đe Tham Lang về sư tôn, còn Tham Lang khống chế Vương thú để điều khiển đàn Văn thú hơn vạn con. Tham Lang muốn bắt sống nguyên thần Vương Lâm tra hỏi tung tích Tư Đồ Nam nên xua đàn Văn thú lao tới; ngay lúc đó Văn thú của chính Vương Lâm bay thẳng về phía hắn."},{"chuong":602,"tieuDe":"Thần Thông Của Tham Lang","tomTat":"Văn thú của Vương Lâm gào thét lao tới, thôn phệ con Văn thú đầu đàn bị Thất Ma Châm khống chế, lớn lên tỏa khí tức đầu đàn rồi điều khiển toàn bộ đàn quay sang vây đánh Tham Lang. Vương Lâm dùng Tịch Diệt Chỉ, Thần Long điều đại kiếm hóa hắc long, hai người không hẹn cùng chớp thời cơ vây công. Tham Lang thi triển Phệ Tử Nhất Thức, đánh tay vào vách đá vực sâu rút thác lục khí thôn phệ Tịch Diệt Chỉ và phá long hồn Thần Long, đồng thời gọi đúng tên gốc hai thần thông là Toái Kiếm Hóa Thần của Lăng Thiên Hậu và Sát Lục Tiên Quyết của Thiên Vận Tử, chê hai người nắm không hoàn chỉnh. Khi bị dồn, Tham Lang lấy tòa núi tiên giới phong ấn, dùng Phệ Tử nhị thức rút sơn hồn khiến núi vỡ vụn. Sơn hồn đè hắc long của Thần Long khiến hắn phun máu trọng thương, còn sát lục khí của Vương Lâm bị tiên lực mênh mông từ sơn hồn làm tan nát, may còn lưu một tia trong thần thức để khôi phục. Tham Lang thoát khỏi vòng vây Văn thú, cười tiết lộ ngọn núi là của tiên giới hắn đoạt phong ấn mấy vạn năm trước. Cùng lúc, đám sương mù phía xa co lại còn bảy thước thành quả cầu dày đặc, lộ một lệnh bài và một đệ tử Đại La kiếm tông còn sống; Tham Lang tham lam tiến tới thì cả đàn Văn thú đồng loạt kêu gào kịch liệt."},{"chuong":603,"tieuDe":"Đỉnh","tomTat":"Đàn Văn thú của Vương Lâm phát hồng quang, tan nát rồi khôi phục liên tục, vây chặt Tham Lang. Tử vụ phía xa thu lại để lại một lệnh bài cổ kính tử quang ẩn kim quang lơ lửng giữa không trung, ba bên Vương Lâm, Thần Long và Tham Lang lao vào tranh đoạt trong vùng cấm thuấn di. Được Chu Dật truyền âm cảnh báo về kiếm khí bổn mạng Lăng Thiên Hậu, Vương Lâm dừng tay quan sát; Tham Lang thả đệ nhị nguyên thần phóng thần lôi đen, còn Thần Long liều mạng cướp lệnh bài bỏ chạy. Tham Lang đau lòng xuất chí bảo Thiên Mê Hương thoát vây rồi đạp sương đuổi theo. Vương Lâm hai lần thi triển tiên thuật ‘Định’ khống chế Th��n Long làm rơi lệnh bài rồi chặn Tham Lang đúng lúc để tự mình chụp lấy lệnh bài, mượn tốc độ Chu Dật lao về cửa ra Hỏa Yêu quận. Cùng đường, Tham Lang vỗ túi trữ vật lấy đại đỉnh, niệm ‘Càn Khôn nghịch chuyển, thiên địa phiên thân’ phóng hắc quang đảo ngược trời đất. Vị trí ba người bị đảo, Vương Lâm vốn ở phía trước lại rơi vào chỗ Thần Long đang bị sương mù vây khốn."},{"chuong":604,"tieuDe":"Thái Cổ Lôi Long","tomTat":"Thần Long bị cái đỉnh nghịch Càn Khôn của Tham Lang đổi chỗ với Vương Lâm, kinh hãi thần uy ph��p bảo nên bỏ chạy ra lối ra, còn Tham Lang nhếch mép bước tới vây Vương Lâm. Thần niệm Chu Dật trong tiên kiếm bộc phát kiếm khí phá vây, lao thẳng đâm Tham Lang; Tham Lang ném bình phong dáng dấp Sơn Hà đồ tạo lực hút, Chu Dật phóng bổn mạng kiếm khí đối kháng để Vương Lâm rút lui. Vương Lâm vận kiếm khí Lăng Thiên Hậu lao xuống vực sâu, bị đệ nhị nguyên thần lôi hệ của Tham Lang truy sát; hắn thả Lôi Thú từ Xạ Thần Xa nuốt lôi cầu, dùng phù văn tiên bút, huyết ngọc Diêu Tích Huyết và Tam Tài kiếm trận chống cửu tinh liên châu, điện long, hắc lôi và Diệt Tiên Lôi. Khi điện võng co rút, Vương Lâm thi tiên thuật Định định thân đệ nhị nguyên thần rồi mặc ma giáp đánh Hóa Ma Chỉ với Hoàng Tuyền Chỉ phá nát lạc ấn mi tâm, diệt nó. Đệ nhị nguyên thần nổ tan giải phóng Thái Cổ Lôi Long mà Tham Lang phong ấn bao đời bằng Thái Cổ ma khí, thanh long uy danh hiển hách ôm cừu hận lao tới khiến Tham Lang trên miệng vực phun máu kinh hãi. Vương Lâm cười khổ nhận ra cái đỉnh cổ thần Đồ Ti cũng vào tay Tham Lang, rồi vận tiên lực lao thẳng vào hố sâu vô hạn đáy vực mà hắn biết quy luật lực hút để né tránh; Lôi Long mới thức tỉnh theo bản năng lao theo, giãy giụa phóng điện đánh vỡ vách đá."},{"chuong":605,"tieuDe":"Thiên Soái Động Dung","tomTat":"Vương Lâm dựa vách đá kiểm soát tốc độ rơi xuống hố sâu, nhưng Thái Cổ Lôi Long vì hận mà truy kích không tha, buộc hắn tiến sâu vào nơi lực hút cực mạnh không thể lao ra. Lôi Long phun lôi cầu lớn như Thiên Kiếp song bị lực hút kéo lệch, hút mất vào vực vạn trượng; Vương Lâm thả Tam Tài Kiếm Trận rồi thêm Tiên Kiếm và Loan Đao đâm vách đá làm chỗ bám, để lại năm vết kéo dài. Hắn dùng định thân thuật khống chế Lôi Long khiến nó không trở lại được mà bị kéo xuống. Nhờ thanh quang của Lôi Long, hắn thoáng thấy một Truyền Tống Trận trên tảng đá nhô ra rồi tìm được miệng khe lớn trong vách đá để trốn lực hút. Lôi Long sợ hãi tự xẻ thân làm hai — một nửa bị hút mất, một nửa nhảy vào khe, đúng lúc nó suy yếu nhất. Vương Lâm vốn là một thôn hồn liền phóng nguyên thần một ngụm nuốt lấy nửa linh hồn Thái Cổ Lôi Long, rồi triển thần thông điên cuồng hấp thu sức mạnh lôi điện khiến thân thể lóe điện quang."},{"chuong":606,"tieuDe":"Nguyên Thần Biến Dị","tomTat":"Trong khe đá hung hiểm, nguyên thần Vương Lâm biến dị khi cắn nuốt Thái Cổ Lôi Long: bên trong nguyên thần hiện ra một Lôi Long dài như kinh mạch, hình thành lôi điện và cả một tia lôi quang — trạng thái mà ngay cả Thiên Vận Tử kiến thức cao thâm cũng chưa từng gặp. Lôi Long không khuất phục, giãy giụa phản kích đẩy nguyên thần đến ranh giới sắp tiêu tan, nhưng Vương Lâm nhờ ý chí kiên định kháng cự được. Hắn xuất nguyên thần khỏi Thiên Linh cái, tay phải túm Lôi Long lôi ra, tay trái in cấm chế phong ấn, vừa phong ấn vừa cắn nuốt lặp đi lặp lại; thân thể chìm vào chết giả để bảo trì sức sống. Nhiều năm trôi qua, cấm chế hình thành lớp vảy rồng trên thân Lôi Long, nguyên thần thu nhỏ thành hình Nguyên Anh cao ba thước tản lôi uy như hàng vạn ngân xà rồi dung nhập lại thân thể qua một lớp màng ngăn cách. Vương Lâm đánh giá nguyên thần giờ giống một đạo Thiên Lôi, bản lãnh vẫn Vấn Đỉnh Sơ Kỳ nhưng mang sức mạnh sấm sét, đủ thắng thế Vấn Đỉnh Trung Kỳ và phối pháp bảo quyết chiến Vấn Đỉnh Hậu Kỳ. Khi thử xuất nguyên thần lần nữa, hắn ngẩn ra vì nguyên thần không thể thoát ly khỏi cơ thể, nghi do lớp màng ngăn cách hoặc cái giá của biến dị. Cuối cùng hắn gác lại, vỗ túi trữ vật lấy ra một lệnh bài màu tím ngưng tụ từ sương mù."},{"chuong":608,"tieuDe":"Luyện Chế Tiên Vệ","tomTat":"Nguyên thần Vương Lâm hút lửa nguyên khí đang thiêu đốt nguyên thần Đỗ Kiến vào trong nguyên thần mình, cứu Đỗ Kiến khỏi nguy. Hơn mười ngày sau Đỗ Kiến dung hợp nguyên khí, đột phá Vấn Đỉnh Sơ Kỳ nhưng là yếu nhất do nguyên khí hao tổn nhiều, lòng vừa oán hận vừa cảm kích vừa hối hận sợ hãi. Vương Lâm đề nghị luyện chế Tiên Vệ — nhân thể pháp bảo do Tiên Đế Thanh Lâm bắt chước Cổ Thần chế tạo — giúp Đỗ Kiến đạt Vấn Đỉnh đại viên mãn; Đỗ Kiến không có lựa chọn, gật đầu đánh cuộc sống qua ngàn năm. Vương Lâm khởi luyện theo ba bước trong ngọc giản: luyện thân thể cực mạnh, hóa nguyên thần dung nhập cơ thể, luyện hóa lục phủ ngũ tạng héo rũ. Sau mấy tháng thất bại bước một, hắn nung chảy pháp bảo dư thừa thành chất lỏng làm vật liệu, qua hai tháng luyện được khôi lỗi chỉ đạt Đồng cấp. Trong lúc đó một đóa hoa hồng màu lam gợi nhớ một thân ảnh đỏ như lửa khiến hắn do dự rồi thu lại. Do lực hút bên ngoài cái khe ngày càng mạnh, cuối chương Vương Lâm cắn răng rung Tôn Hồn Phiên, triệu ra một đầu lâu xanh đen khổng lồ trừng nhìn hắn mà gào thét."},{"chuong":609,"tieuDe":"Khôi Lỗi Hùng Mạnh","tomTat":"Trong Tôn Hồn Phiên đa số linh hồn tránh xa cái đầu lâu Thiên Quỷ, chỉ kỳ lân (đã nuốt nhiều tiên lương biến hóa kỳ dị) dám đối đầu; Vương Lâm nhận ra đây chính là Thiên Quỷ năm xưa hắn bắt được lúc suy yếu nên lôi nó ra, ép lui khi nó định nuốt hắn. Hắn quyết dùng Thiên Quỷ làm hung khí đoạt hư thể cho khôi lỗi, nhấn vào lông mày khôi lỗi và dùng roi khắc chế quất khi nó chống cự, cân nhắc rồi bỏ phương án dùng Tán Ma Chi Hồn. Qua hơn nửa năm, Thiên Quỷ dung hợp với nguyên thần Đỗ Kiến rồi bị xóa mờ mà vẫn liên kết chặt — vượt bước luyện hóa thứ hai cực khó, luyện ra khôi lỗi Tiên Vệ thứ nhất có khí tức ngang cảnh giới âm dương hư thực, suýt soát Tư Đồ Nam. Vương Lâm nhỏ máu kích hoạt, đổ trăm vạn đạo sát lục chi khí, gắn ngọc giản truyền thần thông rồi ra lệnh Ẩn cho Tiên Vệ ẩn vào thân ảnh, bội phục tài trí Tiên Đế Thanh Lâm. Hắn xác định phải nắm chắc sáu phần thần thông Tiên Vệ mới rời tuyệt địa, rồi lấy đại kiếm Cự Phú dung nhập tâm thần tìm bí mật của nó. Cuối cùng hắn cô độc khoanh chân trong khe tăm tối, hồi tưởng 800 năm tu đạo, nhớ cha mẹ và Uyển Nhi — bóng hình trong tiểu cầu bạch quang bên cạnh bù đắp nỗi cô độc, gợi thứ hạnh phúc quá xa xỉ và gian nan."},{"chuong":610,"tieuDe":"Tai Họa Ngầm Của Sát Lục Tiên Quyết","tomTat":"Vương Lâm đã ngồi tu suốt ba năm trong khe nứt dưới hố sâu vùng đất Yêu Linh; lực hút hố sâu từng bùng nổ kéo cơ hội rời khỏi từ sáu phần xuống hai phần, nhưng hắn vẫn bình tĩnh chờ đợi. Tu vi Vấn Đỉnh chững lại, ba cửa ải Trung Kỳ, Hậu Kỳ, đại viên mãn như ba ngọn núi chắn đường. Sau hai năm cảm thụ ý chí trong Cự Phú, hắn lĩnh ngộ thức kiếm quyết duy nhất Trảm La Quyết, rồi Cự Phú hoàn toàn tiêu tan như đã hoàn thành truyền thừa. Cuộn tranh nữ tử thần bí lần thứ tư hiện ra gọi “Đi xuống”, bị hắn chém kiếm bắt im tiếng; Lôi Oa thức tỉnh ở bên hắn nuốt thiểm điện. Hắn nghiền ngẫm đạo niệm hai thức và khiếm khuyết Tuyền Hồn, dự định rút khí hung sát từ hồn phách phàm nhân để hoàn thiện. Nguy hiểm nhất là Sát Lục Chi Tâm bắt đầu dị biến — tai họa ngầm có thể khiến hắn phát điên hoặc hủy toàn bộ Sát Lục Chi Khí. Cuối cùng Vương Lâm quyết đoán bước qua ranh giới khe, chống cự lực hút xé thân, rồi nhảy ra lao về Truyền Tống Trận cổ cách hai mươi trượng phía dưới."},{"chuong":611,"tieuDe":"Đệ Tam Thức","tomTat":"Vương Lâm bị nhốt trong tuyệt địa hố sâu, lực hút cực mạnh kéo hắn xuống. Thất Tinh Kiếm Trận xoay tròn vẫn không chống nổi, hắn phải triệu con rối Tiên Vệ hóa cơn lốc đen mới đặt chân lên được tảng đá lớn. Trên đó hắn lợi dụng lực hút bức từng sợi tơ đỏ Sát Lục Tiên Quyết trong da thịt ra ngoài, đến năm thứ tư sợi cuối cùng tiêu tan, da dẻ trở lại bình thường. Sau đó hắn từ bỏ chống cự, ngồi bất động để lực hút xuyên thấu; qua sáu năm lực hút xuyên thẳng qua thân nhưng nguyên thần vẫn chưa hòa. Đến năm thứ mười bảy hắn ngộ ra phải tự biến thành một bộ phận của lực hút, thanh âm nữ tử trong nguyên thần thúc giục “Đi xuống…”. Vương Lâm bước một bước rơi vào hố sâu, buông toàn bộ tâm thần, lực hút dung nhập cả thân lẫn nguyên thần khiến hắn dừng lại giữa không trung. Hắn lĩnh ngộ thành công Đệ Tam Thức trong thần thông đạo niệm: Hoàng Tuyền Chi Lực, và tuyên bố đã đến lúc rời đi."},{"chuong":612,"tieuDe":"Gỡ Bỏ Bí Mật Của Bức Tranh","tomTat":"Âm thanh nữ tử trong nguyên thần Vương Lâm — biến mất mười ba năm — nay trở lại, lần đầu mang cảm xúc van xin hắn mang nàng xuống đáy hố. Khi Vương Lâm định bay lên vì còn nhiều việc lớn, nữ tử cắn răng dụ bằng lời hứa tiết lộ lai lịch thật của Thiên Nghịch châu và cách cứu sống tàn hồn nữ tử trong hạt châu, khiến hắn tạm mất tỉnh táo tám trăm năm tu đạo, mắt điên cuồng như dã thú, cầm tranh lao thẳng xuống. Sau thời gian dài bay xuống, hắn tới hành lang có dòng xoáy cực lớn; lực lượng từ tranh ngưng tụ ở mắt cho hắn nhìn xuyên dòng xoáy thấy La Thiên tinh vực — quê hương nữ tử, tức Lôi tiên giới. Hắn ngồi thích ứng lực hút bảy ngày rồi triển khai Thất Tinh Kiếm Trận chống cự, sát lục chi ý hóa tơ đỏ lộ dưới da đến trăm vạn bằng đúng số Sinh Mệnh Lạc Ấn. Nữ tử kể truyền thuyết Tứ đại tiên giới Phong Vũ Lôi Điện, cho biết Thiên Nghịch châu xuất hiện sớm nhất ở La Thiên tinh vực rồi biến mất, sau lại xuất hiện ở Vũ tiên giới của Liên Minh Tinh Vực, rồi đề nghị Vương Lâm đưa nàng về quê qua dòng xoáy đổi lấy lời hứa tổ tiên Hướng gia cứu tàn hồn. Nhận ra nàng giấu nhiều bí mật và đây là cái bẫy, Vương Lâm không qua dòng xoáy mà bay lên, phá tảng đá che truyền tống trận cần La Yêu thạch, ném tranh cắm sâu vào vách đá rồi đánh vô số cấm chế phong ấn suốt mấy tháng và vỗ sụp cái khe chôn sâu. Khi nữ tử cố thoát nứt ra ba động, hắn triệu con rối Tiên Vệ đánh thêm phong ấn mênh mông đè lên, hai lần phong ấn triệt để rồi mới rời đi."},{"chuong":613,"tieuDe":"Lão Quái Hàng Lâm","tomTat":"Vương Lâm vừa bay khỏi vực sâu vừa cân nhắc về nữ tử trong tranh — kẻ tu vi cực mạnh bị nghi là tai họa ngầm dụ hắn tới La Thiên tinh vực; hắn quyết rời vùng đất Yêu Linh sớm, định ghé Hướng gia ở Đông Lâm tinh dò thân phận nàng vì lão tổ tộc nàng đ��ợc cho là có thể khiến Uyển nhi sống lại. Nhờ Thất Tinh kiếm trận, con rối Tiên Vệ và Văn thú màu tím cũ tái ngộ, hắn thoát ra khỏi hố; qua thần thức Văn thú hé lộ năm xưa hai tu sĩ Hỏa Yêu quận bắt Tham Lang, Chu Dật cùng phần lớn đàn Văn thú. Vương Lâm dẫn Văn thú sang Thủy Yêu quận thu phục, chỉ ấu thú chịu vào túi trữ vật còn Văn thú trưởng thành tự vẫn vì bị bỏ rơi. Hắn truyền tống về động phủ, phong ấn và phá truyền tống trận, từ biệt động phủ chi linh, rồi tới bộ lạc Luyện Hồn để lại công pháp cho Thập Tam và từ biệt Âu Dương Hoa. Tại yêu tướng phủ Thiên Yêu quận, hắn dùng thần thông bóng Âm dương hư thật đập vỡ vụn Thạch Tiêu để báo lời hứa năm xưa, dặn sư huynh Trần Đào “Cẩn thận, sư tôn”. Cuối chương, Thiên Vận Tử, Lăng Thiên Hậu và Huyết Tổ cùng đám lão giả mở cánh cửa Yêu Linh ngoài Đông Hải tiến vào sớm mười năm, chấn động chín quận; Lăng Thiên Hậu gọi Tham Lang còn Huyết Tổ quét thần thức không thấy Diêu Tích Huyết nên sắc mặt càng âm trầm."},{"chuong":614,"tieuDe":"Rời Đi","tomTat":"Khi đám lão quái vừa bước vào vùng đất Yêu Linh, Vương Lâm lập tức lao vào vực sâu triều tịch, dùng Thất Tinh kiếm trận tạo lực đẩy dung nhập lực hút để tăng tốc tiến tới dòng xoáy thông La Thiên tinh vực. Vân Tiên đạo lữ Vương Tạ và Hồ Quyên xuất hiện trên mây lành hư ảo, thả Thần Long và Tham Lang cho các lão quái thẩm vấn. Lăng Thiên Hậu đòi lệnh bài vào động phủ; Tham Lang chối việc giết đệ tử Đại La kiếm tông và khai Vương Lâm là người giữ lệnh bài. Thiên Vận Tử bấm độn dò ra Vương Lâm xuyên vực sâu, thấy trên người hắn không còn lạc ấn Sát Lục Tiên Quyết nhưng không kịp ngăn. Huyết Tổ cảm nhận khí tức Diêu Tích Huyết trên người Vương Lâm, nhưng Vương Lâm trước khi biến mất để lại câu nói về bí mật hư phủ thứ tư, đẩy Huyết Tổ vào thế bị nghi kỵ. Cuối cùng các lão quái quyết định liên thủ đưa Tham Lang vào dòng xoáy, mỗi người đặt một cấm chế, cử hắn sang La Thiên tinh vực truy bắt Vương Lâm."},{"chuong":615,"tieuDe":"Sơ Nhập La Vân","tomTat":"Chương mở ra La Thiên Tinh Vực — tinh vực rộng lớn rực rỡ tinh quang, không có môn phái mà chỉ có các tu chân gia tộc huyết thống; đa số tu sĩ nơi đây biết tứ đại tiên giới phong-vũ-lôi-điện đều có tinh vực riêng, trong khi tu sĩ Liên Minh Tinh Vực quê Vương Lâm bị Tu Chân Liên Minh giấu diếm sự thật này. Bốn người Nhiễm Vân Tinh gồm Nhiễm Nguyệt (Anh Biến trung kì), Nhiễm Thần, Nhiễm Phong và Tôn Tuyết Sơn (Anh Biến sơ kì) vì chiếm được Xích diệu thạch khi thí luyện nên bị vô số Minh vụ trùng truy kích, bao vây trong sương độc hại nguyên thần. Nhiễm Nguyệt dùng vòng ngọc toả lôi điện che phủ cả nhóm cầm cự, ba nam thay nhau mở lỗ hổng nhưng tiên lực và đan dược cạn dần. Vương Lâm — sau khi dung nhập trận lốc xoáy như qua truyền tống trận — hiện ra tại La Vân Tinh Vực thuộc Lôi chi tiên giới, cưỡi ngân quang hình rồng và bỡ ngỡ dò xét. Hắn dùng ánh mắt thực chất khiến Minh vụ trùng run rẩy rút lui, thử thu hồi để dò xét rồi hỏi đường tới Hợp vân thánh, được Tôn Tuyết Sơn đáp cách bảy ngày hướng bắc. Cuối cùng Vương Lâm thi triển Thiên Lôi chân chính (do nguyên thần dung hợp Thái Cổ Lôi Long) tiêu tan toàn bộ sương mù, Minh vụ trùng lùi nhanh."},{"chuong":616,"tieuDe":"Mi Nhi","tomTat":"Sau khi thoát Minh vụ trùng và sấm sét, Nhiễm Nguyệt cùng Tôn Tuyết Sơn, Tôn Vân Sơn hóa cầu vồng bay tới bên Vương Lâm; Tôn Tuyết Sơn khiếp sợ vì trong sấm sét vừa rồi có một tia lôi uy chân chính nên nghi hắn là Lôi Tiên sứ giả, còn Vương Lâm không thừa nhận cũng không phủ nhận. Bốn người cung kính dẫn đường đi Nhiễm Vân Tinh, Vương Lâm ngồi trên tinh la bàn ngân long cho bay chậm để nhân cơ hội tìm hiểu La Thiên Tinh Vực, qua đó biết về Thiên Huyễn Tinh, Đông Lâm Sát Tinh và bốn vực đông tây nam bắc. Hắn xưng tên giả Hứa Mộc khiến Nhiễm Nguyệt nghi hắn là người Hứa gia danh giá. Tới Nhiễm Vân Tinh — tinh cầu thủy lam linh lực sung mãn — Vương Lâm tiến vào, bị ba cỗ thần thức Vấn Đỉnh quét tới nhưng hắn dễ dàng qua mặt, quyết định ẩn nấp tại đây tránh đám Thiên Vận Tinh truy đuổi. Cùng lúc ở Liên Minh Tinh Vực, lão già đại trưởng lão Huyễn gia đưa đệ tử Mi nhi rời La Thiên Tinh Vực, bỏ cả việc tìm Thiên Nghịch Châu vì yêu quý nàng. Vương Lâm che tu vi Vấn Đỉnh xuống Kết Đan hậu kì, dựa tiên vệ thần thông đổi tướng mạo, vào thành Tôn gia thuê phòng cấp dưới ở thành bắc, chịu cái nhìn khinh miệt của thanh niên canh giữ rồi đi tới gian phòng thứ năm phía tây."},{"chuong":617,"tieuDe":"Mưu Ngọc","tomTat":"Vương Lâm vào phòng xá mới ở Nhiễm Vân Tinh bằng lệnh bài, gia cố cấm chế gian ngoài rồi ngồi thổ nạp linh khí nhưng nhận ra thổ nạp thông thường không còn nâng được tu vi. Kiểm điểm tài nguyên, hắn thấy tiên ngọc đã hao gần hết sau lần Vấn Đỉnh, tiên dịch chỉ còn năm giọt nên để dành cho lúc nguy cấp, xác định thu hoạch tiên ngọc hằng ngày là ưu tiên hàng đầu. Hắn quan sát hạt châu xanh trên nóc phòng ẩn ba trận pháp biến khói nến thành ánh sáng và hương thơm, nhận xét pháp thuật nhỏ ở La Thiên Tinh Vực mạnh hơn Tu Chân Liên Minh. Gạt bỏ ý định cướp đoạt tiên ngọc vì cho rằng hành vi tầm thường và sẽ buộc rời Nhiễm Vân Tinh, hắn chuyển sang luyện chế ba Ngụy tiên bảo: phi kiếm chứa na di ấn quyết, gương đồng chứa Tuế Nguyệt Ý Cảnh, trâm cài tóc chứa Thiên Huyễn Vô Tình Đạo mô phỏng từ Liễu Mi. Hắn còn sáng tạo thủ pháp ngụy kế thừa — thêm phong ấn đặc thù và ấn bí quyết phá giải vào ngọc giản — áp dụng thành công lên gương đồng, hai pháp bảo còn lại chưa hoàn thành. Sáng hôm sau ra ngoài, hắn đi ngang chỗ núi đá nơi gã thanh niên vẫn ngồi tu luyện; đợi Vương Lâm đi xa, gã mới mở mắt lộ vẻ khinh miệt."},{"chuong":618,"tieuDe":"Tôn Lão","tomTat":"Vương Lâm ẩn thân giả dạng tu sĩ bình thường ở một thành tu sĩ, hấp thụ linh khí ngoài thành bắc rồi đi tìm chốn buôn bán pháp bảo để bán thanh phi kiếm tự luyện chế. Một gã thanh niên tu vi thấp khinh thường hắn nhưng vẫn chỉ tới Bảo Hợp Lâu ở thành đ��ng, nơi cửa hàng lớn đặt khối linh thạch khổng lồ trước cửa để phô trương. Tại Bảo Hợp Lâu, hắn bị Lô Phong chặn vì không đủ mười vạn linh thạch theo quy củ “hai không tiến, một không ra”; phi kiếm bị Lô Phong chê thấp kém và từ chối thu. Trước khi đi, Vương Lâm liếc thẳng vào mắt Lô Phong khiến gã rúng động, Nguyên Anh gần sụp đổ, mặt tái nhợt lùi mấy bước. Tôn lão lưng còng chống gậy đi ra, nghe Lô Phong bẩm báo, nhìn theo bóng Vương Lâm thấy thoáng quen quen, lộ tia nghi hoặc rồi mệt mỏi trở vào lâu thở dài. Vương Lâm tới Thanh Trúc Các, văn sĩ trẻ niềm nở nhận phi kiếm, dùng thần thức xem xét thì đột nhiên mở tròn mắt, kinh khiếp nhìn chằm chằm vào thanh kiếm."},{"chuong":619,"tieuDe":"Bỏ Qua","tomTat":"Tại Thanh Trúc Các trên Nhiễm Vân Tinh, thanh niên Tôn Mặc dùng thần thức thử phi kiếm Vương Lâm đem bán, phát hiện kiếm có tính chất dung hợp đạt linh bảo bậc trung, sắc bén bậc cao, và đặc biệt chứa lạc ấn thuấn di — điều gần như bất khả với phi kiếm thường. Tôn Mặc trả giá mười lăm vạn linh thạch thượng phẩm nhưng không đủ tư cách mua, bèn dùng ngọc giản mời trưởng lão Anh Biến hậu kì tới kiểm định. Lão già áo xanh thử phi kiếm, xác nhận đây là ngụy tiên bảo có thuật Đại Na Di cùng lôi điện kì dị quý báu, mua với giá ba nghìn tiên ngọc. Vương Lâm tiếp đó lấy ra mặt gương đồng khiến lão khiếp sợ hơn cả phi kiếm, gọi là kế thừa ngụy tiên bảo và lộ rõ lòng tham. Vương Lâm ra giá năm vạn tiên ngọc — toàn bộ tích lũy trăm năm lão dành cho Vấn Đỉnh 7 ngày sau. Thực chất Vương Lâm ngầm bố trí thế phòng vệ: nếu đối phương cướp bảo thì hắn giết người đoạt bảo cũng hợp tình hợp lí, để đứng vững chân ở Nhiễm Vân Tinh."},{"chuong":620,"tieuDe":"Cảnh Báo","tomTat":"Tại Thanh Trúc Các, một lão già tu sĩ Anh Biến cực kỳ động tâm trước gương đồng ngụy tiên bảo kế thừa của Vương Lâm; vì thấy Vương Lâm (lốt thanh niên dòng trưởng gia tộc tu chân) bình tĩnh, xuất được hai pháp bảo, lão không dám đoạt mà xuất hơn một vạn tiên ngọc cùng số dư túi trữ vật mua ngọc giản kế thừa, rồi rời đi sau khi không hứng thú với cây trâm. Rời cửa hàng, Vương Lâm phát hiện một đạo thần thức bám theo nên cố tình ra ngoài thành, giữ tốc độ trình độ Kết Đan để dụ; kẻ tập kích — một người trung niên Nguyên Anh trung kỳ — giáng sương mù quỷ dị hóa bàn tay chộp tới. Vương Lâm phất tay quét tan đòn, làm kẻ địch phun tiên huyết, hoảng sợ nhận ra hắn không phải Kết Đan rồi bỏ chạy về trung tâm thành Tôn gia kêu cứu và ngã gục. Vương Lâm thong thả đuổi tới, vung lốc xoáy cuốn văng tu sĩ Tôn gia và giáng uy áp khổng lồ lên tòa nhà lớn buộc cả gia tộc chống đỡ; lão già mặt đỏ và Tôn trưởng lão dọa nạt đòi chờ trưởng bối gia tộc. Một lão hắc y Anh Biến hậu kỳ đại viên mãn mang đạo khí Vấn Đỉnh ra dàn xếp, đồng ý bồi thường hai mươi vạn tiên ngọc (xin ba ngày), bởi Lão tổ Tôn gia tầng Vấn Đỉnh đã giáng lâm trên thân lão dặn đáp ứng toàn bộ và giữ kín việc. Vương Lâm liếc mắt thâm ý vào thần thức Vấn Đỉnh trên người lão rồi rời đi; ở đáy biển đông bộ Nhiễm Vân Tinh, một nam tử tóc dài ẩn tu cảm nhận tu sĩ Vấn Đỉnh, run rẩy hiểu ra cái liếc là cảnh cáo nên rời đi không dám quấy rầy."},{"chuong":621,"tieuDe":"Nữ Giả Nam","tomTat":"Vương Lâm xác lập cách hành sự khiêm tốn tại Nhiễm Vân Tinh dưới danh Hứa Mộc: hờ hững nhìn ngoài, không tham dự tình thế, tạo một luồng lực vô hình khiến các tồn tại đỉnh cao không dám xúc phạm, nhằm yên tâm tu luyện rồi quay về Liên Minh Tinh Vực. Trên đường về chỗ trú nơi thành Bắc, hắn bị một thanh niên gầy gò mặc quần áo rộng thùng thình giáo huấn về tu chân — phải chăm chỉ, bế quan vài chục năm mới kết anh — khiến hắn cười khổ vâng dạ, cảm khái chưa từng có ai dám nói với mình như vậy. Khi vào c���a, Vương Lâm xác nhận người này thực ra là một phụ nữ giả nam dùng pháp thuật che mặt, song tướng mạo thật vẫn chưa lộ. Về phòng, hắn dùng nghìn khối tiên ngọc bắt pháp quyết ép tiên khí co rút thổ nạp ba ngày khiến tiên ngọc hóa bụi, rồi nhận ra Vấn Đỉnh ngốn tiên ngọc khổng lồ, suy đoán tu sĩ bước thứ hai có thể không cần hoặc có cách thay thế. Tôn Khải Minh — lão già hắc y phụ trách tòa thành, hạ tu vi xuống Kết Đan kỳ khi vào — cung kính giao túi trữ vật chứa hai mươi vạn tiên ngọc và hỏi tên, được đáp là Hứa Mộc. Theo lệnh tộc dò tu vi, lão buộc phải bẩm chuyện đấu giá bát phẩm thứ thần đan bảy ngày sau tại Bảo Hợp Lâu của Nhiễm Gia; bị Vương Lâm phóng áp lực vô hình ép, cuối cùng lão đưa lệnh bài đấu giá hồng sắc rồi lui ra."},{"chuong":622,"tieuDe":"Pháp Bảo Đặc Biệt Nhằm Vào Vương Lâm","tomTat":"Lão già hắc y dùng bát phẩm thần đan thăm dò Vương Lâm theo lệnh người trong tộc, bị hắn cảnh cáo ‘không còn lần thứ hai’ liền hóa gió tan biến, kinh hãi vì tâm tư đã bị nhìn thấu. Vương Lâm luận rõ phẩm cấp đan dược nhờ ký ức Lý Mộ Uyển từng là Luyện Đan Đại Sư, nhận ra cái bẫy của Tôn Gia rồi bỏ qua. Ở Vực Bắc La Thiên Tinh Vực, sư phụ Huyễn Gia đưa Liễu Mi về Thiên Huyễn Tinh nhờ La Thiên Thạch, định thi Hoán Huyết đưa huyết mạch gia tộc vào nàng, nhận làm nghĩa nữ và đổi tên thành Huyễn Mi. Liễu Mi nghĩ Vương Lâm không còn xứng làm đối thủ, tiếc pháp bảo đặc biệt từng chuẩn bị cho hắn nay không còn chỗ dùng. Trên Nhiễm Vân Tinh, Vương Lâm hấp thụ tiên ngọc bảy ngày rồi gặp người áo tím Tôn Tích chờ trước cổng thành Bắc. Tôn Lăng liều mình giữ thành bảo vệ hắn dù bị uy hiếp, khiến Vương Lâm cảm động bước ra dùng tám bước uy thế áp đảo Tôn Tích. Tôn Tích lộ thân phận lão tổ Vấn Đỉnh sơ kỳ Tôn Gia, cầu giúp, đề nghị tặng suất đi Lôi tiên giới trăm năm sau và hé lộ nghi ngờ về lai lịch Vương Lâm."},{"chuong":623,"tieuDe":"Người Bốn Năm Trước","tomTat":"Dưới thân phận cải trang ‘Hứa huynh’, Vương Lâm hỏi Tôn Tích về vãn bối Tôn Gia tên Tôn Tuyết Sơn và xác nhận từng cứu mạng người này, khiến Tôn Tích chỉ còn hoài nghi mà không dám truy đến cùng, càng kiêng dè và muốn kết giao. Cả đoàn tới Bảo Hợp Lâu thành Đông đúng kỳ đấu giá; Tôn Khải Minh, tộc nhân đời thứ ba Tôn Gia phụ trách thành, cung kính nghênh đón và tự dẫn đường lên lầu bốn, còn người thanh niên họ Tôn thì kinh ngạc mơ hồ cảm thấy mình đã bỏ lỡ điều gì. Vào phòng nhìn xuống đại sảnh, Vương Lâm dùng thần thức phát hiện một hình bóng già nua ở lầu ba với dấu vết đã tiêu tán hơn phân nửa, thầm thốt ‘Là hắn!’ và cảm nhận có vấn đề. Tôn Tích kể chuyện bốn năm trước: hắn cùng lão tổ Nhiễm Gia và Tiêu Diêu Cư Sĩ đồng thời cướp năm viên bát phẩm đan dược từ một tu sĩ ngoại lai bị trọng thương, kẻ này chết trong tay Nhiễm Gia lão tổ. Trong túi trữ vật kẻ bị giết có lệnh bài Chủ Tinh Thiên Huyễn của Huyễn Gia — thế lực cực bá đạo sẽ diệt tộc bất kỳ ai dính vào di vật, nên đến nay không ai dám nuốt đan dược. Vương Lâm nhận ra đây là cạm bẫy của tu sĩ Vấn Đỉnh Nhiễm Gia nhằm dụ hắn mua đan dược để kéo hắn vào ân oán với Huyễn Gia, liền thầm cảnh giác khi cuộc đấu giá bắt đầu với giá khởi điểm một vạn tiên ngọc."},{"chuong":624,"tieuDe":"Tôn Thái","tomTat":"Tại phiên đấu giá tầng hai Bảo Hợp Lâu, một sứ giả mặc hồng bào của Nhiễm Gia mở hộp ngọc rao bán “bát phẩm đan dược” to bằng nắm tay trẻ con — thực chất đám đông nhận ra là một cái đầu người, ai mua thì đầu mình cũng khó giữ, nên dù xôn xao không ai dám hét giá. Ngồi tầng bốn dưới danh nghĩa họ Hứa, Vương Lâm lạnh nhạt hô giá vỏn vẹn một khối tiên ngọc cho món vật khởi điểm một vạn, khiến cả đại sảnh chấn động và cho là cố ý làm khó Nhiễm Gia. Sứ giả hồng bào rơi vào thế tiến thoái lưỡng nan: nhận giá thì lộ việc bán có đầu mối lớn và để lộ Nhiễm Gia đang sợ hãi, không bán thì trái lệnh lão tổ; cuối cùng cắn răng chấp nhận. Vương Lâm vung trảo cách không đoạt viên thuốc, ném ra một khối tiên ngọc, ôm quyền chào Tôn Tích rồi thuấn di rời đi, thầm nghĩ một đan dược chưa đủ để dụ mình gia nhập cục diện đó. Lão già tang thương ở tầng ba nghe giọng liền chấn động tâm thần, đuổi theo nhưng tưởng nhận lầm người mà xin lỗi quay đi. Vương Lâm trầm mặc gọi đích danh “Tôn Thái”, khiến lão kinh ngạc nhận ra cố nhân. Hắn phóng thần thức dò xét, hỏi vì sao thần thông Cự Ma Tộc lão tổ năm xưa đưa được lão tới La Thiên Tinh Vực và vì sao lạc ấn còn sót; khi Tôn Thái vừa nhắc Đông Lâm Tinh thì Vương Lâm liền cuốn lão thuấn di vào thành Bắc, đưa về phòng riêng để tra hỏi cặn kẽ."},{"chuong":625,"tieuDe":"Trên Sinh Tử Chính Là Nhân Quả","tomTat":"Tôn Thái — Đại trưởng lão Thi Âm Tông chi Chu Tước tinh năm xưa, nay tu vi tụt xuống Hóa Thần kỳ — kinh hãi nhận ra Vương Lâm đã biến đổi long trời lở đất từ quân cờ bậc thấp thành cao thủ khí tức sâu không lường, từng giết tu sĩ Vấn Đỉnh. Khi hỏi tu vi, Vương Lâm bình thản đáp “Vấn Đỉnh”, khiến Tôn Thái cười khổ không tin và hiểu ra vì sao Lão tổ Nhiễm gia chịu đưa bát phẩm đan dược. Tôn Thái kể chuyện luân lạc: bị truyền tống vào La Thiên tinh vực gần Đông Lâm tinh, làm tạp dịch cho Lữ gia gần trăm năm, lạc ấn được người Lữ gia gỡ nhưng vẫn còn. Hắn tiết lộ Đông Lâm tinh có ba gia tộc Hứa-Lữ-Lưu cực mạnh, là địa ngục hỗn loạn; xác nhận không biết nơi đó có Hướng gia. Hắn cũng tiết lộ Thi Âm Tông và Tứ Thánh tông là hai tông phái lớn nhất Liên minh tinh vực, Chu Tước tinh là chi nhánh tách từ Tứ Thánh tông, nên Vương Lâm có thể tính là đệ tử bên ngoài Tứ Thánh tông. Tôn Thái cảnh báo bát phẩm đan dược là âm mưu của Lão tổ Nhiễm gia. Vương Lâm dùng ý cảnh sinh tử luân hồi nhìn ra tử khí, tuổi thọ Tôn Thái chỉ còn hai mươi năm; hắn hứa tiễn và mang tro cốt về Ám Nguyệt tinh, còn Tôn Thái tặng túi trữ vật chứa tiên ngọc và tâm đắc luyện đan luyện khí để tạ ơn."},{"chuong":626,"tieuDe":"Tiên Phong Khinh Phất, Thụ Dục Bất Tĩnh","tomTat":"Tôn Thái tặng Vương Lâm túi trữ vật chứa hơn năm vạn tiên ngọc rồi tập tễnh rời đi dưới ánh chiều tà, buông bỏ việc khôi phục tu vi cùng oán hận mấy trăm năm, chỉ xin được đưa về quê nhà dưới chân Thiên Sơn. Vương Lâm nhắm mắt cảm ngộ nhân quả sinh tử luân hồi, hiểu nhân quả là căn nguyên của sinh và tử nhưng vẫn còn mơ hồ. Tại Thiên Huyễn tinh, Liễu Mi ngồi trong lầu các Huyễn gia, dùng giọt máu trấn một vật dao động trong túi trữ vật rồi than pháp bảo “chuẩn bị cho hắn” nay đã vô dụng; tin truyền một tổ tiên Huyễn gia trở về với đệ tử tư chất kinh người, ba tháng sau sẽ thi triển Hoán Huyết đại pháp. Vương Lâm dịch chuyển tới cánh đồng hoang cách thành Tôn gia hơn mười vạn dặm, rải gần ba mươi vạn tiên ngọc lập trận pháp từ thức thứ ba Đạo Hóa Hoàng Tuyền, thả Thất Tinh kiếm trận và Tiên Vệ phòng vệ. Hắn hô “Vỡ!” rồi “Hút!”, nuốt trọn cơn lốc tiên lực khổng lồ, nguyên thần cắn nuốt mà đột phá lên Vấn Đỉnh trung kỳ. Toàn Nhiễm Vân tinh chỉ ba người cảm nhận được cơn lốc — Tôn Tích kinh sợ, người đàn ông trung niên trong sông băng bỏ qua, còn lão già đầu tóc xanh đen của Nhiễm gia âm trầm rồi Na Di ra ngoài vạn dặm phóng một tia sét đánh về phía hư không trong khi Vương Lâm đã thu trận và rời đi."},{"chuong":627,"tieuDe":"Nhân Quả Tuần Hoàn, Tầm Sinh Tầm Tử","tomTat":"Lão tổ Nhiễm gia phóng Chưởng Tâm Lôi đánh vào hư không, nhưng Vương Lâm bước ra cho con rối Tiên vệ trong bóng lao ra đánh tan đòn sét rồi hu��ch trọng thương lão tổ khiến lão phun máu, kinh hãi đoán tu vi hắn đạt Vấn Đỉnh hậu kỳ đại viên mãn. Dưới danh Hứa mỗ, Vương Lâm trách lão tổ kéo Hứa mỗ vào chuyện bốn năm trước, ra điều kiện che chở: ép Nhiễm gia chín phần tiên ngọc, Tôn Tích bảy phần, Tiêu Dao tán nhân chín phần cùng đan dược, túi trữ vật và toàn bộ di vật người Huyễn gia chết bốn năm trước. Lo nguy cơ diệt tộc nếu Huyễn gia tra ra, cả ba chấp nhận nộp đủ; Vương Lâm thu vật rồi biến mất, dặn nếu người Huyễn gia tới hắn sẽ tự ra tay, sau đó Tôn Tích cáo lui với ý nghĩ khác còn lão tổ Nhiễm gia tự nhủ mất tiền mua bình yên và đề phòng người này. Cùng lúc ở Thiên Huyễn tinh, gia chủ Huyễn Phong Thần báo cáo lão tổ Huyễn gia về việc tộc nhân mất tích bốn năm trước, bị lão tổ cho thêm ba tháng và lệnh phái tộc vệ cho Huyễn Mi nhổ tận gốc người liên quan. Huyễn Phong Thần thầm nghi lão tổ vì người ngoài Liễu Mi mà không tiếc thi triển Hoán huyết đại pháp, có ý định giao Huyễn gia cho nàng; ba ngày sau Liễu Mi nhận việc, phái thuộc hạ si mê nàng là Huyễn Đông đi Nhiễm Vân tinh xử lý nhanh gọn. Cuối chương, Vương Lâm dùng Na Di về Tôn gia thành, đi bộ cảm ngộ đạo Sinh Tử Luân Hồi đã dung hợp với nguyên thần, ngẫm rằng đã nắm mặt tử qua Đạo Hóa Hoàng Tuyền nhưng đạo của sinh còn chưa rõ ở nơi nào."},{"chuong":628,"tieuDe":"Vân Hà Hữu Kim, Ngũ Hành Khuyết Nhất","tomTat":"Trở về phía bắc thành Nhiễm Vân tinh, Vương Lâm gặp lại người tu sĩ trẻ lòng dạ thiện lương từng biết hắn bị bắt đi; hắn khích lệ y giữ nguyên tâm cảnh hiện giờ thì có thể đạt Hóa Thần, khiến y vừa cảm động vừa hoài nghi. Về phòng, Vương Lâm nhận ra tiên lực dù sung túc mà ý cảnh không tăng thì nuốt bao nhiêu cũng vô dụng, bèn lấy di vật người Huyễn gia mà ba lão tổ Nhiễm gia đưa cho ra kiểm tra. Trong túi trữ vật có bát phẩm đan dược, cây lược đen ngụy tiên bảo loại công kích, đôi đá đánh lửa tử kim, lệnh bài thân phận và một ngọc giản. Nhờ trí nhớ Cổ Thần Đồ Ti, hắn nhận ra đôi đá lửa là pháp bảo thiên nhiên hình thành, tài liệu luyện khí sinh kim hỏa, tiếc rằng đôi này tạp chất nhiều khó luyện hóa. Hắn triệu Tiên Vệ soi lệnh bài, phát hiện bên trong cài thần thông mệnh hồn báo cho Huyễn gia biết chủ nhân đã chết. Cho thần thức dung nhập ngọc giản và đánh nát đạo sóng đưa tin, Vương Lâm đọc được công pháp Thiên Huyễn Vô Tình đạo (phá cấm chế bằng huyết mạch) cùng tin tức mỏ quáng Kim Viêm ở Vân Hà tinh. Hắn định đoạt mỏ Kim Viêm để lấp đầy tính kim loại còn thiếu của hạt châu Thiên Nghịch, nổi sát khí với kẻ tranh đoạt, rồi buông thần thức truyền âm lệnh Tôn Tích khắc tinh đồ La Thiên tinh vực vào ngọc giản đưa tới."},{"chuong":629,"tieuDe":"Thính Vũ, Hồi Ức Tri Mi","tomTat":"Sau mười ngày nghiên cứu kỹ ngọc giản tinh đồ của Tôn Tích, Vương Lâm (mang danh Hứa Mộc) xác định đích đến là Vân Hà tinh — tinh cầu bỏ đi tràn ngập khói độc, cách Nhiễm Vân tinh mấy tháng đường — rồi sửa sang pháp bảo, rời phòng lên tầng cương phong hướng chân trời. Lão tổ Nhiễm gia, Tiêu Dao tán nhân và Tôn Tích cùng Na Di đến chặn, ngờ vực vì đã dâng toàn bộ của cải; Vương Lâm lạnh lùng khẳng định giữ lời, chuyến đi lâu thì một năm nhanh thì mấy tháng. Giữa lúc đó Huyễn Đông — nhị phẩm tộc vệ Huyễn gia trên Thiên Huyễn chủ tinh — đạp tinh la bàn giáng lâm Nhiễm Vân tinh, tự xưng và gọi tu sĩ Vấn Đỉnh ra gặp, tiếng quát như sấm khiến tu sĩ yếu phun máu, danh Huyễn gia làm ba người tái nhợt tuyệt vọng. Vương Lâm cầm tiền trừ tai họa, hóa thần thức thành chữ Cút rồi xuất Tịch Diệt chỉ nhuốm điện quang đậm đặc tựa sấm sét Thiên kiếp. Huyễn Đông bấm kim bí quyết của Tâm Ý Ngũ Hành quyết và lấy kim kiếm đỡ, nhưng kim kiếm vỡ vụn, hắn bị đánh phun máu, điện quang vờn quanh nguyên thần đau đớn. Kinh hãi nhận ra tu vi đối phương đáng sợ không phải người bản tinh, Huyễn Đông tăng tốc Na Di bỏ chạy về bẩm báo tiểu thư. Lúc này tu vi Vương Lâm vẫn Vấn Đỉnh sơ kỳ nhưng tiên lực đã cực kỳ gần trung kỳ, chỉ cần cảm ngộ ý cảnh là đột phá."},{"chuong":630,"tieuDe":"Tư Đồ Nam Lại Bế Quan","tomTat":"Vương Lâm dưới thân phận Hứa Mộc phóng Thất Tinh kiếm trận hóa bảy đạo cầu vồng truy sát Huyễn Đông; tà hồn Thất Sanh Tiếu trên thất kiếm dung hợp hóa móng vuốt thú lớn kéo Huyễn Đông ra khỏi hư vô, khống chế nguyên thần chỉ trong vài hơi thở. Ba lão tổ Nhiễm gia — Nhiễm Học Phong, Tôn Tích, Triệu Truyền Văn — kiêng dè uy thế Hứa Mộc; Huyễn Đông tái mặt đe dọa rồi phơi bày việc ba nhà giết người Huyễn gia bốn năm trước, tiết lộ Lão tổ Huyễn gia đã trở về với tu vi Âm Dương Hư Thực và có Tiên Vệ. Tôn Tích giải thích Lão tổ Huyễn gia mang một cô gái từ Liên Minh Tinh Vực về làm con gái nuôi (Huyễn Mi), sắp thi triển Hoán huyết đại pháp. Vương Lâm tuyên bố giao Huyễn Đông cho Nhiễm gia rồi đột ngột dùng Sưu hồn thuật (mượn lực Tiên Vệ) moi trí nhớ, phát hiện Huyễn Mi chính là Liễu Mi — kẻ thù cũ từ Chu Tước tinh — liền bóp chết Huyễn Đông, thu nguyên thần vào Tôn hồn phiên. Lượng sức không liều chết với Lão tổ Huyễn gia, Vương Lâm dùng Tinh la bàn hóa rồng bạc bay tới Vân Hà tinh lấy mỏ quặng Kim Viêm để hoàn chỉnh hạt châu Thiên Nghịch; một tháng sau Vân Hà tinh hiện trong thần thức hắn. Huyễn gia nhận tin Huyễn Đông chết, Lão tổ ưu tiên Hoán huyết đại pháp, giao việc trả thù cho Huyễn Mi lập uy và bố trí Tỏa tinh đại trận vây Nhiễm Vân tinh; Liễu Mi lạnh nhạt coi cái chết của Huyễn Đông như con kiến chết."},{"chuong":631,"tieuDe":"Huyễn Mi Tới Gần","tomTat":"Liễu Mi (Huyễn Mi) đứng bên cửa sổ lầu các nghĩ về Nhiễm Vân tinh — nơi sẽ là trận chiến lập uy của nàng ở Huyễn gia, coi “người đó” trên Chu Tước tinh và Huyễn Đông như con kiến. Túi trữ vật của nàng truyền ra dao động và oán khí đậm đặc; lão tổ Huyễn gia cảnh báo vật quá độc ác, giục giết bỏ kẻo hỏng đạo tâm, nhưng nàng từ chối vì đã có tính toán. Lão tổ chủ trì Hoán huyết đại pháp: dung hợp máu mấy vạn tộc nhân thành ngàn huyết phù, thi triển Vạn Huyễn Vô Tướng đạo và trào hết tiên lực, tự tổn hại hai trăm năm tu vi nâng nàng lên Vấn Đỉnh hậu kỳ đại viên mãn trong nửa nén hương, trao huyết mạch Huyễn gia (tổ tiên vốn là tiên nhân Lôi tiên giới đã hủy). Sau đó lão dặn nàng bế quan rồi tới Nhiễm Vân tinh lập uy và biến mất; nàng một mình bay đi không mang tùy tùng. Song song, Vương Lâm xâm nhập Vân Hà tinh — tinh cầu tu chân hoang phế đầy tử khí và xúc tu — dùng Thất Tinh kiếm trận xuyên sương mù để tìm mỏ Kim Viêm, rồi chạm trán mãnh thú Vọng Nguyệt ký sinh Cổ Thần nên lập tức tránh né và nghi nơi đây có xác Cổ Thần. Ở Liên minh tinh vực, Tư Đồ Nam bị tông chủ Loan Phượng tinh ra lệnh truy nã, bị hai cô gái dùng quả cầu đỏ ép trời đất truy sát; hắn thoát thân nhưng phun máu, dọa rải mười vạn ngọc giản bôi nhọ một nữ tử rồi quyết bế quan tới Khuy Niết kỳ. Cuối chương, Vương Lâm dùng thổ độn chui vào vách đá tiếp tục tìm mỏ Kim Viêm dưới lòng đất."},{"chuong":632,"tieuDe":"Lang Yên Khởi","tomTat":"Vương Lâm di chuyển trong lòng đất Vân Hà tinh, thả thần thức lan tỏa toàn tầng ngầm và phát hiện một mỏ quáng Kim Viêm phát ánh vàng kéo dài vô số dặm — chính là nơi Huyễn gia năm xưa từng khai thác. Hắn thấy kỳ quái khi mỏ lộ rõ mà không ai dám lấy, men theo quan sát thì nhận ra nó chỉnh tề như một bộ xương dài. Toàn tinh cầu bỗng run lên, xúc tu trồi lên mặt đất, hắn kinh hãi nhận ra sự thật chấn động: cả Vân Hà tinh là một con Vọng Nguyệt khổng lồ đang ngủ say, mỏ Kim Viêm là xương cốt của nó. Nhờ thói quen thận trọng không vội thu mỏ, hắn thoát chết, đồng thời hiểu vì sao không tu sĩ nào dám lấy xương. Dựa trí nhớ Cổ Thần Đồ Ti, Vương Lâm lập kế tinh luyện dược vật từ Thăng Tiên Quả khiến Vọng Nguyệt hôn mê để lấy xương, then chốt là chỉ mình hắn có ấn quyết Cổ Thần dẫn dắt. Hắn cưỡi tinh la bàn rời đi, hoãn việc viên mãn Thiên Nghịch, hướng tới Nhiễm Vân tinh — nơi ba người Lão tổ Nhiễm gia, Tiêu Dao tán nhân và Tôn Tích đang đối mặt Tỏa tinh đại trận của Huyễn gia, nhận ra Huyễn gia muốn diệt tộc cả ba nhà và lập uy cho Huyễn Mi."},{"chuong":633,"tieuDe":"Tới Rồi","tomTat":"Ba lão tổ Nhiễm gia, Triệu gia và Tôn gia bàn nhau về kết cục diệt tộc sắp tới: họ đã âm thầm đưa dòng chính ba tộc đi giữ hương khói nhưng căn cơ ở Nhiễm Vân tinh không thể di chuyển, đồng thời oán Hứa Mộc đã hứa che chở rồi rời đi lúc nguy cơ. Liễu Mi áo trắng xuyên Tỏa tinh đại trận giáng lâm, ba lão tổ quyết thiêu nguyên thần tử chiến; lão tổ Nhiễm gia xưng tên thật Nhiễm Học Phong, Tiêu Dao tán nhân là Triệu Truyền Văn. Liễu Mi thi triển Thiên Huyễn Vô tình đạo mê hoặc khiến Tiêu Dao tán nhân và Tôn Tích si mê quay sang đánh chính Nhiễm Học Phong, để mặc ba người tương tàn; lão tổ này được Hoán huyết nâng tu vi để thử uy lực bước hai của đạo pháp. Hai lão tổ thiêu cả thân thể lẫn nguyên thần rồi tự bạo, Nhiễm Học Phong gắng lên Ngụy hậu kỳ đánh ra kiếm khí vạn trượng, vụ tự bạo khiến biển dâng trăm trượng và linh mạch Nhiễm Vân tinh nứt vỡ. Trước khi chết, Nhiễm Học Phong nguyền rủa Liễu Mi cùng Huyễn Mi, tiết lộ người giết Huyễn Đông là Hứa Mộc chứ không phải ba người, rồi tự thiêu nguyên thần hóa bụi để bảo vệ tinh cầu. Liễu Mi dò ra phân thân Kết Đan của Tôn Tích ẩn ở cực nam, biết ba lão tổ đều ngầm tế luyện phân thân giữ mạng. Đúng lúc đó Vương Lâm cưỡi tinh la bàn hóa cầu vồng bạc trở về vì đã thu tiên ngọc ba lão tổ, đổi dung mạo đối mặt Liễu Mi, kinh hãi nhận thấy tu vi nàng đạt Vấn Đỉnh hậu kỳ đại viên mãn. Liễu Mi nhận ra hắn qua ánh mắt lạnh lùng, gọi đúng tên, nhắc chuyện Chu Tước tinh năm xưa và quyết không cho đi; Vương Lâm phóng Tịch Diệt chỉ phong, Liễu Mi bấm pháp quyết tạo quầng sáng đỡ, quầng sáng nứt vô số vết, mở màn cuộc chiến."},{"chuong":634,"tieuDe":"Vạn Huyễn Thiên Ma Đạo","tomTat":"Liễu Mi xác nhận tu vi Vương Lâm chỉ là Vấn Đỉnh sơ kỳ, nghi sư tôn hắn cưỡng ép đề cao tu vi có mục đích khác, rồi tuyên bố hôm nay sẽ chấm dứt ân oán Chu Tước tinh. Nàng thi triển Vạn Huyễn Thiên Ma đạo, điểm mi tâm biến hóa thành Hồng Điệp đấu pháp bằng hoa hồng và phù văn trăm trượng; Vương Lâm phản kích bằng Thất Tinh kiếm trận và Đạo hóa Hoàng Tuyền có đạo niệm. Liễu Mi lần lượt biến thành Chu Như, mẹ hắn, cha hắn, Vương Trác, Độn Thiên và Lý Mộ Uyển để công tâm, khiến Hoàng Tuyền của hắn dừng lại rồi sụp đổ. Vương Lâm nhận thấu bản chất pháp môn, nhắm mắt buông bỏ để đám huyễn hóa khói nhập thể; nhờ nguyên thần ẩn chứa thượng cổ Lôi Long có lôi uy thiên địa, hắn bóp nát đoàn sương phá huyễn khiến Liễu Mi bị thương hiện thân. Hai người đấu khẩu ân oán cũ: Liễu Mi tố hắn dùng tàn hồn ý cảnh ô uế phá thân xử nữ nàng, hắn đáp do nàng ra tay trước. Cuối cùng Liễu Mi mở túi trữ vật thả ra sương đen oán khí kinh thiên phủ mười dặm; hắc mang lướt qua Tiên vệ xông tới, Vương Lâm thổi tan sương lộ một đôi mắt đen đục ngầu chứa oán diễm khiến hắn sững lại."}];
